INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1, 'Bulbasaur', 'Grass', 'Poison', 45, 49, 49, 65, 65, 45, 7.00, 69.00, 'For some time after its birth, it grows by taking nourishment from the seed on its back.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (2, 'Ivysaur', 'Grass', 'Poison', 60, 62, 63, 80, 80, 60, 10.00, 130.00, 'When the bud on its back starts swelling, a sweet aroma wafts to indicate the flower’s coming bloom.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (3, 'Venusaur', 'Grass', 'Poison', 80, 82, 83, 100, 100, 80, 20.00, 1000.00, 'After a rainy day, the flower on its back smells stronger. The scent attracts other Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (4, 'Charmander', 'Fire', null, 39, 52, 43, 60, 50, 65, 6.00, 85.00, 'The fire on the tip of its tail is a measure of its life. If the Pokémon is healthy, its tail burns intensely.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (5, 'Charmeleon', 'Fire', null, 58, 64, 58, 80, 65, 80, 11.00, 190.00, 'In the rocky mountains where Charmeleon live, their fiery tails shine at night like stars.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (6, 'Charizard', 'Fire', 'Flying', 78, 84, 78, 109, 85, 100, 17.00, 905.00, 'It is said that Charizard’s fire burns hotter if it has experienced harsh battles.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (7, 'Squirtle', 'Water', null, 44, 48, 65, 50, 64, 43, 5.00, 90.00, 'It hides in its shell to protect itself, then strikes back with spouts of water at every opportunity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (8, 'Wartortle', 'Water', null, 59, 63, 80, 65, 80, 58, 10.00, 225.00, 'It is said to live 10,000 years. Its furry tail is popular as a symbol of longevity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (9, 'Blastoise', 'Water', null, 79, 83, 100, 85, 105, 78, 16.00, 855.00, 'The jets of water it spouts from the rocket cannons on its shell can punch through thick steel.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10, 'Caterpie', 'Bug', null, 45, 30, 35, 20, 20, 45, 3.00, 29.00, 'It releases a stench from its red antennae to repel enemies. It grows by molting repeatedly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (11, 'Metapod', 'Bug', null, 50, 20, 55, 25, 25, 30, 7.00, 99.00, 'A steel-hard shell protects its tender body. The Pokémon quietly endures hardships while awaiting evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (12, 'Butterfree', 'Bug', 'Flying', 60, 45, 50, 90, 80, 70, 11.00, 320.00, 'It loves the nectar of flowers and can locate flower patches that have even tiny amounts of pollen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (13, 'Weedle', 'Bug', 'Poison', 40, 35, 30, 20, 20, 50, 3.00, 32.00, 'It eats its weight in leaves every day. It fends off attackers with the needle on its head.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (14, 'Kakuna', 'Bug', 'Poison', 45, 25, 50, 25, 25, 35, 6.00, 100.00, 'While awaiting evolution, it hides from predators under leaves and in nooks of branches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (15, 'Beedrill', 'Bug', 'Poison', 65, 90, 40, 45, 80, 75, 10.00, 295.00, 'Its best attack involves flying around at high speed, striking with poison needles, then flying off.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (16, 'Pidgey', 'Normal', 'Flying', 40, 45, 40, 35, 35, 56, 3.00, 18.00, 'It is docile and prefers to avoid conflict. If disturbed, however, it can ferociously strike back.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (17, 'Pidgeotto', 'Normal', 'Flying', 63, 60, 55, 50, 50, 71, 11.00, 300.00, 'It flies over its wide territory in search of prey, downing it with its highly developed claws.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (18, 'Pidgeot', 'Normal', 'Flying', 83, 80, 75, 70, 70, 101, 15.00, 395.00, 'By flapping its wings with all its might, Pidgeot can make a gust of wind capable of bending tall trees.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (19, 'Rattata', 'Normal', null, 30, 56, 35, 25, 35, 72, 3.00, 35.00, 'It’s cautious in the extreme, and its hardy vitality lets it live in any kind of environment.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20, 'Raticate', 'Normal', null, 55, 81, 60, 50, 70, 97, 7.00, 185.00, 'It whittles down its constantly growing fangs by gnawing on hard things. It can chew apart cinder block walls.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (21, 'Spearow', 'Normal', 'Flying', 40, 60, 30, 31, 31, 70, 3.00, 20.00, 'It flaps its small wings busily to fly. Using its beak, it searches in grass for prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (22, 'Fearow', 'Normal', 'Flying', 65, 90, 65, 61, 61, 100, 12.00, 380.00, 'It has the stamina to fly all day on its broad wings. It fights by using its sharp beak.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (23, 'Ekans', 'Poison', null, 35, 60, 44, 40, 54, 55, 20.00, 69.00, 'It sneaks through grass without making a sound and strikes unsuspecting prey from behind.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (24, 'Arbok', 'Poison', null, 60, 95, 69, 65, 79, 80, 35.00, 650.00, 'The pattern on its belly is for intimidation. It constricts foes while they are frozen in fear.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (25, 'Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'When several of these Pokémon gather, their electricity can build and cause lightning storms.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (26, 'Raichu', 'Electric', null, 60, 90, 55, 90, 80, 110, 8.00, 300.00, 'If the electric pouches in its cheeks become fully charged, both ears will stand straight up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (27, 'Sandshrew', 'Ground', null, 50, 75, 85, 20, 30, 40, 6.00, 120.00, 'To protect itself from attackers, it curls up into a ball. It lives in arid regions with minimal rainfall.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (28, 'Sandslash', 'Ground', null, 75, 100, 110, 45, 55, 65, 10.00, 295.00, 'It curls up, then rolls into foes with its back. Its sharp spines inflict severe damage.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (29, 'Nidoran♀️', 'Poison', null, 55, 47, 52, 40, 40, 41, 4.00, 70.00, 'While this Pokémon does not prefer to fight, even one drop of the venom it secretes from its barbs can be fatal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (30, 'Nidorina', 'Poison', null, 70, 62, 67, 55, 55, 56, 8.00, 200.00, 'When it senses danger, it raises all the barbs on its body. These barbs grow more slowly than Nidorino’s.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (31, 'Nidoqueen', 'Poison', 'Ground', 90, 92, 87, 75, 85, 76, 13.00, 600.00, 'Its entire body is armored with hard scales. It will protect the young in its burrow with its life.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (32, 'Nidoran♂️', 'Poison', null, 46, 57, 40, 40, 40, 50, 5.00, 90.00, 'It scans its surroundings by raising its ears out of the grass. Its toxic horn is for protection.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (33, 'Nidorino', 'Poison', null, 61, 72, 57, 55, 55, 65, 9.00, 195.00, 'It has a violent disposition and stabs foes with its horn, which oozes venom upon impact.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (34, 'Nidoking', 'Poison', 'Ground', 81, 102, 77, 85, 75, 85, 14.00, 620.00, 'One swing of its mighty tail can snap a telephone pole as if it were a matchstick.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (35, 'Clefairy', 'Fairy', null, 70, 45, 48, 60, 65, 35, 6.00, 75.00, 'It can be found in quiet mountain areas on a full moon’s night. Its dancing and its tiny, faintly glowing wings confer upon it a lovely fairylike quality.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (36, 'Clefable', 'Fairy', null, 95, 70, 73, 95, 90, 60, 13.00, 400.00, 'Legend says that on clear, quiet nights, it listens for the voices of its kin living on the moon. I, too, often think of my homeland, so far away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (37, 'Vulpix', 'Fire', null, 38, 41, 40, 50, 65, 65, 6.00, 99.00, 'In its belly burns a fire, which Vulpix spits out in the form of fireballs. When young, this Pokémon has but one white tail. As the Pokémon matures, this single tail splits into six.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (38, 'Ninetales', 'Fire', null, 73, 76, 75, 81, 100, 100, 11.00, 199.00, 'The coat of gleaming golden fur is quite magnificent. This species is said to store sacred power in its nine long tails and to live for a millennium.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (39, 'Jigglypuff', 'Normal', 'Fairy', 115, 45, 20, 45, 25, 20, 5.00, 55.00, 'If it inflates to sing a lullaby, it can perform longer and cause sure drowsiness in its audience.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (40, 'Wigglytuff', 'Normal', 'Fairy', 140, 70, 45, 85, 50, 45, 10.00, 120.00, 'The rich, fluffy fur that covers its body feels so good that anyone who feels it can’t stop touching it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (41, 'Zubat', 'Poison', 'Flying', 40, 45, 35, 30, 40, 55, 8.00, 75.00, 'Makes its home in gloomy caves. Atrophied eyes have left this Pokémon blind, so it scans its surroundings via sound waves that it emits from its mouth as it flies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (42, 'Golbat', 'Poison', 'Flying', 75, 80, 70, 65, 75, 90, 16.00, 550.00, 'It sinks its sharp fangs into other creatures and slurps up their blood. A closer look at the fangs reveals that they are hollow and akin to straws.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (43, 'Oddish', 'Grass', 'Poison', 45, 50, 55, 75, 65, 30, 5.00, 54.00, 'It often plants its root feet in the ground during the day and sows seeds as it walks about at night.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (44, 'Gloom', 'Grass', 'Poison', 60, 65, 70, 85, 75, 40, 8.00, 86.00, 'The nectar it drools from its mouth smells so atrocious that it can make noses curl from more than a mile away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (45, 'Vileplume', 'Grass', 'Poison', 75, 80, 85, 110, 90, 50, 12.00, 186.00, 'Its petals are the largest in the world. As it walks, it scatters extremely allergenic pollen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (46, 'Paras', 'Bug', 'Grass', 35, 70, 55, 45, 55, 25, 3.00, 54.00, 'Sometimes seen at the foot of trees in humid forests. The mushrooms on its back—called tochukaso—are not present on infant specimens and instead emerge as Paras matures.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (47, 'Parasect', 'Bug', 'Grass', 60, 95, 80, 60, 80, 30, 10.00, 295.00, 'Mushroom-lacking specimens of this Pokémon lie unmoving in the forest, lending credence to the hypothesis that the large mushroom is in control of Parasect’s actions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (48, 'Venonat', 'Bug', 'Poison', 60, 55, 50, 40, 55, 45, 10.00, 300.00, 'Its eyes act as radar, enabling it to be active in darkness. The eyes can also shoot powerful beams.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (49, 'Venomoth', 'Bug', 'Poison', 70, 65, 60, 90, 75, 90, 15.00, 125.00, 'When it attacks, it flaps its large wings violently to scatter its poisonous powder all around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50, 'Diglett', 'Ground', null, 10, 55, 25, 35, 45, 95, 2.00, 8.00, 'Its skin is very thin. If it is exposed to light, its blood heats up, causing it to grow weak.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (51, 'Dugtrio', 'Ground', null, 35, 100, 50, 50, 70, 120, 7.00, 333.00, 'In battle, it digs through the ground and strikes the unsuspecting foe from an unexpected direction.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (52, 'Meowth', 'Normal', null, 40, 45, 35, 40, 40, 90, 4.00, 42.00, 'It loves things that sparkle. When it sees a shiny object, the gold coin on its head shines, too.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (53, 'Persian', 'Normal', null, 65, 70, 60, 65, 65, 115, 10.00, 320.00, 'It has a vicious temperament. Beware if it raises its tail straight up. This is a signal that it is about to pounce and bite.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (54, 'Psyduck', 'Water', null, 50, 52, 48, 65, 50, 55, 8.00, 196.00, 'If its chronic headache peaks, it may exhibit odd powers. It seems unable to recall such an episode.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (55, 'Golduck', 'Water', null, 80, 82, 78, 95, 80, 85, 17.00, 766.00, 'It swims gracefully along on the quiet, slow-moving rivers and lakes of which it is so fond.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (56, 'Mankey', 'Fighting', null, 40, 80, 35, 35, 45, 70, 5.00, 280.00, 'It is extremely quick to anger. It could be docile one moment, then thrashing away the next instant.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (57, 'Primeape', 'Fighting', null, 65, 105, 60, 60, 70, 95, 10.00, 320.00, 'Some researchers theorize that Primeape remains angry even when inside a Poké Ball.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (58, 'Growlithe', 'Fire', null, 55, 70, 45, 70, 50, 60, 7.00, 190.00, 'It’s very friendly and faithful to people. It will try to repel enemies by barking and biting.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (59, 'Arcanine', 'Fire', null, 90, 110, 80, 100, 80, 95, 19.00, 1550.00, 'Its magnificent bark conveys a sense of majesty. Anyone hearing it can’t help but grovel before it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (60, 'Poliwag', 'Water', null, 40, 50, 40, 40, 40, 90, 6.00, 124.00, 'Its skin is so thin, its internal organs are visible. It has trouble walking on its newly grown feet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (61, 'Poliwhirl', 'Water', null, 65, 65, 65, 50, 50, 90, 10.00, 200.00, 'The spiral pattern on its belly subtly undulates. Staring at it gradually causes drowsiness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (62, 'Poliwrath', 'Water', 'Fighting', 90, 95, 95, 70, 90, 70, 13.00, 540.00, 'With its extremely tough muscles, it could keep swimming in the Pacific Ocean without resting.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (63, 'Abra', 'Psychic', null, 25, 20, 15, 105, 55, 90, 9.00, 195.00, 'Spends 18 hours of the day sleeping. Even while asleep, Abra can control its psychic powers—should danger approach, the Pokémon will simply teleport away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (64, 'Kadabra', 'Psychic', null, 40, 35, 30, 120, 70, 105, 13.00, 565.00, 'There are rumors that a child with mystical powers became a Kadabra; however, this remains unverified. I suspect that the spoon Kadabra holds enhances its brain waves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (65, 'Alakazam', 'Psychic', null, 55, 50, 45, 135, 95, 120, 15.00, 480.00, 'The longer Alakazam lives, the larger and heavier its head becomes. Our tests have shown that the strength of its psychic powers correlates positively to the weight of its head.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (66, 'Machop', 'Fighting', null, 70, 80, 50, 35, 35, 35, 8.00, 195.00, 'Though as small as a child, it has strength enough to easily throw a well-built adult. Striving to become ever stronger, Machop trains by carrying a Graveler on its shoulders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (67, 'Machoke', 'Fighting', null, 80, 100, 70, 50, 60, 45, 15.00, 705.00, 'A sturdy creature boasting a robust physique and boundless stamina. Loves training above all else and voluntarily assists with tasks such as construction and clearing land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (68, 'Machamp', 'Fighting', null, 90, 130, 80, 65, 85, 55, 16.00, 1300.00, 'In close combat, its four arms afford it offensive and defensive supremacy. In but a blink, this valiant Pokémon can overwhelm its foes with more than 1,000 blows from its fists.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (69, 'Bellsprout', 'Grass', 'Poison', 50, 75, 35, 70, 30, 40, 7.00, 40.00, 'It prefers hot and humid environments. It is quick at capturing prey with its vines.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (70, 'Weepinbell', 'Grass', 'Poison', 65, 90, 50, 85, 45, 55, 10.00, 64.00, 'This Pokémon has the appearance of a plant. It captures unwary prey by dousing them with a toxic powder.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (71, 'Victreebel', 'Grass', 'Poison', 80, 105, 65, 100, 70, 70, 17.00, 155.00, 'In its mouth, it pools a fragrant nectar-like fluid. The fluid is really an acid that dissolves anything.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (72, 'Tentacool', 'Water', 'Poison', 40, 40, 35, 50, 100, 70, 9.00, 455.00, 'They fire beams from the glassy, magenta orbs that resemble eyes atop their heads, and they drift in shallow seas. During low tide, they can sometimes be found on beaches, desiccated.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (73, 'Tentacruel', 'Water', 'Poison', 80, 70, 65, 80, 120, 100, 16.00, 550.00, 'It has 80 tentacles, each with a venomous tip. These tentacles are also extendible, lengthening when Tentacruel attempts to catch prey. Use caution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (74, 'Geodude', 'Rock', 'Ground', 40, 80, 100, 30, 30, 20, 4.00, 200.00, 'Makes its home in mountainous regions, using its arms to climb along harsh mountain roads. Can be troublesome—carelessly kicking one will cause it to fly into a rage and chase after you.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (75, 'Graveler', 'Rock', 'Ground', 55, 95, 115, 45, 45, 35, 10.00, 1050.00, 'Dwells in holes dug into sheer walls of stone. It enjoys rolling down slopes as though it were a boulder during a rockfall, so keep an eye upward while traversing mountain roads.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (76, 'Golem', 'Rock', 'Ground', 80, 120, 130, 55, 65, 45, 14.00, 3000.00, 'The rocklike shell is shed each year. The cast-off shell then crumbles, reverting to a mass of soil, which can be spread across fields to promote crop growth.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (77, 'Ponyta', 'Fire', null, 50, 85, 55, 65, 65, 90, 10.00, 300.00, 'These Pokémon live in herds out in the grassland. Newborn foals lack their fiery manes, which will develop about an hour after birth.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (78, 'Rapidash', 'Fire', null, 65, 100, 70, 80, 80, 105, 17.00, 950.00, 'Fiery mane aglow, Rapidash darts like an arrow across the land. This prodigiously swift creature can traverse the vast region of Hisui in a day and a half.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (79, 'Slowpoke', 'Water', 'Psychic', 90, 65, 65, 40, 40, 15, 12.00, 360.00, 'It is always vacantly lost in thought, but no one knows what it is thinking about. It is good at fishing with its tail.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (80, 'Slowbro', 'Water', 'Psychic', 95, 75, 110, 100, 80, 30, 16.00, 785.00, 'If the tail-biting Shellder is thrown off in a harsh battle, this Pokémon reverts to being an ordinary Slowpoke.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (81, 'Magnemite', 'Electric', 'Steel', 25, 35, 70, 95, 55, 45, 3.00, 60.00, 'It moves while constantly hovering. It discharges electromagnetic waves and so on from the units at its sides.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (82, 'Magneton', 'Electric', 'Steel', 50, 60, 95, 120, 70, 70, 10.00, 600.00, 'They’re formed by several Magnemite linked together. They frequently appear when sunspots flare up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (83, 'Farfetch\'d', 'Normal', 'Flying', 52, 90, 55, 58, 62, 60, 8.00, 150.00, 'It can’t live without the stalk it holds. That’s why it defends the stalk from attackers with its life.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (84, 'Doduo', 'Normal', 'Flying', 35, 85, 45, 35, 35, 75, 14.00, 392.00, 'The brains in its two heads appear to communicate emotions to each other with a telepathic power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (85, 'Dodrio', 'Normal', 'Flying', 60, 110, 70, 60, 60, 110, 18.00, 852.00, 'When Doduo evolves into this odd breed, one of its heads splits into two. This Pokémon runs at nearly 40 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (86, 'Seel', 'Water', null, 65, 45, 55, 45, 70, 45, 11.00, 900.00, 'This Pokémon lives on icebergs. It uses the sharp point on its head to break up ice as it swims in the sea.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (87, 'Dewgong', 'Water', 'Ice', 90, 70, 80, 70, 95, 70, 17.00, 1200.00, 'In snow, the pure white coat covering its body obscures it from predators.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (88, 'Grimer', 'Poison', null, 80, 80, 50, 40, 50, 25, 9.00, 300.00, 'When two of these Pokémon’s bodies are combined together, new poisons are created.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (89, 'Muk', 'Poison', null, 105, 105, 75, 65, 100, 50, 12.00, 300.00, 'It’s so stinky! Muk’s body contains toxic elements, and any plant will wilt when it passes by.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (90, 'Shellder', 'Water', null, 30, 65, 100, 45, 25, 40, 3.00, 40.00, 'Clamping on to an opponent reveals its vulnerable parts, so it uses this move only as a last resort.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (91, 'Cloyster', 'Water', 'Ice', 50, 95, 180, 85, 45, 70, 15.00, 1325.00, 'When attacked, it launches its spikes in quick volleys. Its innards have never been seen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (92, 'Gastly', 'Ghost', 'Poison', 30, 35, 30, 100, 35, 80, 13.00, 1.00, 'Its body is made of gas. Despite lacking substance, it can envelop an opponent of any size and cause suffocation.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (93, 'Haunter', 'Ghost', 'Poison', 45, 50, 45, 115, 55, 95, 16.00, 1.00, 'In total darkness, where nothing is visible, Haunter lurks, silently stalking its next victim.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (94, 'Gengar', 'Ghost', 'Poison', 60, 65, 60, 130, 75, 110, 15.00, 405.00, 'Hiding in people’s shadows at night, it absorbs their heat. The chill it causes makes the victims shake.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (95, 'Onix', 'Rock', 'Ground', 35, 45, 160, 30, 45, 70, 88.00, 2100.00, 'This chain of immense stones resembles a giant serpent. Tremors shake the earth above as it burrows deep beneath the ground, feeding on boulders as it goes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (96, 'Drowzee', 'Psychic', null, 60, 48, 45, 43, 90, 42, 10.00, 324.00, 'When it twitches its nose, it can tell where someone is sleeping and what that person is dreaming about.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (97, 'Hypno', 'Psychic', null, 85, 73, 70, 73, 115, 67, 16.00, 756.00, 'Always holding a pendulum that it swings at a steady rhythm, it causes drowsiness in anyone nearby.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (98, 'Krabby', 'Water', null, 30, 105, 90, 25, 25, 50, 4.00, 65.00, 'It lives in burrows dug on sandy beaches. Its pincers fully grow back if they are lost in battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (99, 'Kingler', 'Water', null, 55, 130, 115, 50, 50, 75, 13.00, 600.00, 'The larger pincer has 10,000-horsepower strength. However, it is so heavy, it is difficult to aim.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (100, 'Voltorb', 'Electric', null, 40, 30, 50, 55, 55, 100, 5.00, 104.00, 'It’s usually found in power plants. Easily mistaken for a Poké Ball, it has zapped many people.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (101, 'Electrode', 'Electric', null, 60, 50, 70, 80, 80, 150, 12.00, 666.00, 'It explodes in response to even minor stimuli. It is feared, with the nickname of the Bomb Ball.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (102, 'Exeggcute', 'Grass', 'Psychic', 60, 40, 80, 60, 45, 40, 4.00, 25.00, 'Its six eggs converse using telepathy. They can quickly gather if they become separated.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (103, 'Exeggutor', 'Grass', 'Psychic', 95, 95, 85, 125, 75, 55, 20.00, 1200.00, 'It is called the Walking Jungle. If a head grows too big, it falls off and becomes an Exeggcute.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (104, 'Cubone', 'Ground', null, 50, 50, 95, 40, 50, 35, 4.00, 65.00, 'When it thinks of its dead mother, it cries. Its crying makes the skull it wears rattle hollowly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (105, 'Marowak', 'Ground', null, 60, 80, 110, 50, 80, 45, 10.00, 450.00, 'The bones it uses have been in its possession since it was born. It has a ferocious nature.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (106, 'Hitmonlee', 'Fighting', null, 50, 120, 53, 35, 110, 87, 15.00, 498.00, 'Its legs can stretch to double their length. First-time foes are startled by Hitmonlee’s extensible reach.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (107, 'Hitmonchan', 'Fighting', null, 50, 105, 79, 35, 110, 76, 14.00, 502.00, 'When Hitmonchan twists its arm while throwing a punch, the blow will pulverize even concrete. The Pokémon rests after three minutes of fighting.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (108, 'Lickitung', 'Normal', null, 90, 55, 75, 60, 75, 30, 12.00, 655.00, 'Wields its long tongue deftly, as though it were an arm. The Pokémon’s viscous saliva, once it has been collected and boiled down, yields a strong and highly useful adhesive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (109, 'Koffing', 'Poison', null, 40, 65, 95, 60, 45, 35, 6.00, 10.00, 'Lighter-than-air gases in its body keep it aloft. The gases not only smell; they are also explosive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (110, 'Weezing', 'Poison', null, 65, 90, 120, 85, 70, 60, 12.00, 95.00, 'It grows by feeding on gases released by garbage. Though very rare, triplets have been found.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (111, 'Rhyhorn', 'Ground', 'Rock', 80, 85, 95, 30, 30, 25, 10.00, 1150.00, 'Ludicrously strong—when it butts heads with a mountain, it is the mountain that shatters. But its short legs struggle with turns, and it is incapable of stopping unless it collides with something.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (112, 'Rhydon', 'Ground', 'Rock', 105, 130, 120, 45, 45, 40, 19.00, 1200.00, 'Rapidly rotates its horn to bore through bedrock. It swaggers around volcanic regions, protected from the lava’s heat by its tough, armorlike hide.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (113, 'Chansey', 'Normal', null, 250, 5, 5, 35, 105, 50, 11.00, 346.00, 'It walks carefully to prevent its egg from breaking. However, it is extremely fast at running away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (114, 'Tangela', 'Grass', null, 65, 55, 115, 100, 40, 60, 10.00, 350.00, 'It is cloaked entirely in blue vines, preventing any glimpse of its true identity. The vines impart a refreshing sensation when chewed—they’re useful as a spice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (115, 'Kangaskhan', 'Normal', null, 105, 95, 80, 40, 80, 90, 22.00, 800.00, 'It raises its offspring in its belly pouch. It lets its baby out to play only when it feels safe to do so.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (116, 'Horsea', 'Water', null, 30, 40, 70, 70, 25, 60, 4.00, 80.00, 'It makes its nest in the shade of corals. If it senses danger, it spits black ink and flees.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (117, 'Seadra', 'Water', null, 55, 65, 95, 95, 45, 85, 12.00, 250.00, 'Its spines provide protection. Its fins and bones are prized as traditional medicine ingredients.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (118, 'Goldeen', 'Water', null, 45, 67, 60, 35, 50, 63, 6.00, 150.00, 'It swims at a steady five knots. If it senses danger, it will strike back with its sharp horn.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (119, 'Seaking', 'Water', null, 80, 92, 65, 65, 80, 68, 13.00, 390.00, 'To protect its family, it will fight with its drill-sharp horn. It lives in hollowed rocks in streams.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (120, 'Staryu', 'Water', null, 30, 45, 55, 70, 55, 85, 8.00, 345.00, 'If Staryu’s body is damaged, it will regenerate as long as the red core remains. The core flashes at midnight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (121, 'Starmie', 'Water', 'Psychic', 60, 75, 85, 100, 85, 115, 11.00, 800.00, 'At the center of its body is a red core that sends mysterious radio signals into the night sky.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (122, 'Mr. Mime', 'Psychic', 'Fairy', 40, 45, 65, 100, 120, 90, 13.00, 545.00, 'The behavior of this clown-like Pokémon reminds one of pantomime. It creates invisible walls using a force emitted from its fingertips.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (123, 'Scyther', 'Bug', 'Flying', 70, 110, 80, 55, 80, 105, 15.00, 560.00, 'The sharp scythes on its forearms become increasingly sharp by cutting through hard objects.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (124, 'Jynx', 'Ice', 'Psychic', 65, 50, 35, 115, 95, 95, 14.00, 406.00, 'Its cries sound like human speech. However, it is impossible to tell what it is trying to say.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (125, 'Electabuzz', 'Electric', null, 65, 83, 57, 95, 85, 105, 11.00, 300.00, 'Feeds on electrical energy. During sudden showers beneath looming thunderclouds, one can observe Electabuzz scaling tall trees, where the Pokémon will then wait for lightning to strike.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (126, 'Magmar', 'Fire', null, 65, 95, 57, 100, 85, 93, 13.00, 445.00, 'Legend has it that this Pokémon was born from the crater of a volcano. When wounded, it bathes in lava to heal its body, much as one would soak in a hot spring.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (127, 'Pinsir', 'Bug', null, 65, 125, 100, 55, 70, 85, 15.00, 550.00, 'It grips prey with its pincers until the prey is torn apart. What it can’t tear, it tosses far away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (128, 'Tauros', 'Normal', null, 75, 100, 95, 40, 70, 110, 14.00, 884.00, 'They fight each other by locking horns. The herd’s protector takes pride in its battle-scarred horns.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (129, 'Magikarp', 'Water', null, 20, 10, 55, 15, 20, 80, 9.00, 100.00, 'In the distant past, it was somewhat stronger than the horribly weak descendants that exist today.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (130, 'Gyarados', 'Water', 'Flying', 95, 125, 79, 60, 100, 81, 65.00, 2350.00, 'It appears whenever there is world conflict, burning down any place it travels through.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (131, 'Lapras', 'Water', 'Ice', 130, 85, 80, 85, 95, 60, 25.00, 2200.00, 'It loves crossing the sea with people and Pokémon on its back. It understands human speech.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (132, 'Ditto', 'Normal', null, 48, 48, 48, 48, 48, 48, 3.00, 40.00, 'It can freely recombine its own cellular structure to transform into other life-forms.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (133, 'Eevee', 'Normal', null, 55, 55, 50, 45, 65, 55, 3.00, 65.00, 'Its genetic code is irregular. It may mutate if it is exposed to radiation from element stones.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (134, 'Vaporeon', 'Water', null, 130, 65, 60, 110, 95, 65, 10.00, 290.00, 'Its cell composition is similar to water molecules. As a result, it can’t be seen when it melts away into water.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (135, 'Jolteon', 'Electric', null, 65, 65, 60, 110, 95, 130, 8.00, 245.00, 'If agitated, it uses electricity to straighten out its fur and launch it in small bunches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (136, 'Flareon', 'Fire', null, 65, 130, 60, 95, 110, 65, 9.00, 250.00, 'It fluffs out its fur collar to cool down its body temperature, which can reach 1,650 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (137, 'Porygon', 'Normal', null, 65, 60, 70, 85, 75, 40, 8.00, 365.00, 'It has no discernible heartbeat and does not seem to draw breath, and yet it appears to function without issue. I cannot even begin to explain this utterly bizarre anomaly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (138, 'Omanyte', 'Rock', 'Water', 35, 40, 100, 90, 55, 35, 4.00, 75.00, 'It’s a Pokémon that was resurrected from a fossil using modern science. It swam in ancient seas.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (139, 'Omastar', 'Rock', 'Water', 70, 60, 125, 115, 70, 55, 10.00, 350.00, 'It is thought that this Pokémon became extinct because its spiral shell grew too large.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (140, 'Kabuto', 'Rock', 'Water', 30, 80, 90, 55, 45, 55, 5.00, 115.00, 'It is thought to have inhabited beaches 300 million years ago. It is protected by a sturdy shell.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (141, 'Kabutops', 'Rock', 'Water', 60, 115, 105, 65, 70, 80, 13.00, 405.00, 'It is thought that this Pokémon came onto land because its prey adapted to life on land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (142, 'Aerodactyl', 'Rock', 'Flying', 80, 105, 65, 60, 75, 130, 18.00, 590.00, 'It’s a Pokémon that roamed the skies in the dinosaur era. Its teeth are like saw blades.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (143, 'Snorlax', 'Normal', null, 160, 110, 65, 65, 110, 30, 21.00, 4600.00, 'This glutton appears in villages without warning and devours the entirety of their rice granaries—such occurrences have long been counted among the gravest of disasters.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (144, 'Articuno', 'Ice', 'Flying', 90, 85, 100, 95, 125, 85, 17.00, 554.00, 'This legendary bird Pokémon can create blizzards by freezing moisture in the air.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (145, 'Zapdos', 'Electric', 'Flying', 90, 90, 85, 125, 90, 100, 16.00, 526.00, 'This legendary Pokémon is said to live in thunderclouds. It freely controls lightning bolts.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (146, 'Moltres', 'Fire', 'Flying', 90, 100, 90, 125, 85, 90, 20.00, 600.00, 'It is one of the legendary bird Pokémon. Its appearance is said to indicate the coming of spring.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (147, 'Dratini', 'Dragon', null, 41, 64, 45, 50, 50, 50, 18.00, 33.00, 'It is born large to start with. It repeatedly sheds its skin as it steadily grows longer.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (148, 'Dragonair', 'Dragon', null, 61, 84, 65, 70, 70, 70, 40.00, 165.00, 'It is called the divine Pokémon. When its entire body brightens slightly, the weather changes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (149, 'Dragonite', 'Dragon', 'Flying', 91, 134, 95, 100, 100, 80, 22.00, 2100.00, 'It can fly in spite of its big and bulky physique. It circles the globe in just 16 hours.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (150, 'Mewtwo', 'Psychic', null, 106, 110, 90, 154, 90, 130, 20.00, 1220.00, 'Mewtwo was created by recombining Mew’s genes. It’s said to have the most savage heart among Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (151, 'Mew', 'Psychic', null, 100, 100, 100, 100, 100, 100, 4.00, 40.00, 'Because it can use all kinds of moves, many scientists believe Mew to be the ancestor of Pokémon.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (152, 'Chikorita', 'Grass', null, 45, 49, 65, 49, 65, 45, 9.00, 64.00, 'It uses the leaf on its head to determine the air’s temperature and humidity. It loves to sunbathe.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (153, 'Bayleef', 'Grass', null, 60, 62, 80, 63, 80, 60, 12.00, 158.00, 'The buds that ring its neck give off a spicy aroma that perks people up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (154, 'Meganium', 'Grass', null, 80, 82, 100, 83, 100, 80, 18.00, 1005.00, 'Its breath has the fantastic ability to revive dead plants and flowers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (155, 'Cyndaquil', 'Fire', null, 39, 52, 43, 60, 50, 65, 5.00, 79.00, 'Hails from the Johto region. Though usually curled into a ball due to its timid disposition, it harbors tremendous firepower.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (156, 'Quilava', 'Fire', null, 58, 64, 58, 80, 65, 80, 9.00, 190.00, 'This creature’s fur is most mysterious—it is wholly impervious to the burning touch of flame. Should Quilava turn its back to you, take heed! Such a posture indicates a forthcoming attack.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (157, 'Typhlosion', 'Fire', null, 78, 84, 78, 109, 85, 100, 17.00, 795.00, 'It attacks using blasts of fire. It creates heat shimmers with intense fire to hide itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (158, 'Totodile', 'Water', null, 50, 65, 64, 44, 48, 43, 6.00, 95.00, 'It has a habit of biting everything with its well-developed jaws. Even its Trainer needs to be careful.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (159, 'Croconaw', 'Water', null, 65, 80, 80, 59, 63, 58, 11.00, 250.00, 'Once it bites down, it won’t let go until it loses its fangs. New fangs quickly grow into place.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (160, 'Feraligatr', 'Water', null, 85, 105, 100, 79, 83, 78, 23.00, 888.00, 'It usually moves slowly, but it goes at blinding speed when it attacks and bites prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (161, 'Sentret', 'Normal', null, 35, 46, 34, 35, 45, 20, 8.00, 60.00, 'It has a very nervous nature. It stands up high on its tail so it can scan wide areas.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (162, 'Furret', 'Normal', null, 85, 76, 64, 45, 55, 90, 18.00, 325.00, 'The mother puts its offspring to sleep by curling up around them. It corners foes with speed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (163, 'Hoothoot', 'Normal', 'Flying', 60, 30, 30, 36, 56, 50, 7.00, 212.00, 'It switches its standing foot so quickly that the switch can’t be seen. It cries at the same time every day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (164, 'Noctowl', 'Normal', 'Flying', 100, 50, 50, 86, 96, 70, 16.00, 408.00, 'If it flips its head upside down, it’s a sign that it is engaged in very complex thinking.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (165, 'Ledyba', 'Bug', 'Flying', 40, 20, 30, 40, 80, 55, 10.00, 108.00, 'It’s so timid that it can’t move unless it’s with a swarm. It conveys its feelings through scent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (166, 'Ledian', 'Bug', 'Flying', 55, 35, 50, 55, 110, 85, 14.00, 356.00, 'It uses starlight as energy. When more stars appear at night, the patterns on its back grow larger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (167, 'Spinarak', 'Bug', 'Poison', 40, 60, 40, 40, 40, 30, 5.00, 85.00, 'It sets a trap by spinning a web with thin but strong thread. It waits motionlessly for prey to arrive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (168, 'Ariados', 'Bug', 'Poison', 70, 90, 70, 60, 70, 40, 11.00, 335.00, 'It attaches silk to its prey and sets it free. Later, it tracks the silk to the prey and its friends.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (169, 'Crobat', 'Poison', 'Flying', 85, 90, 80, 70, 80, 130, 18.00, 750.00, 'Its hind limbs have become another set of wings. Crobat expertly maneuvers its four wings to dart in exquisite fashion through even the most confined caves without losing any speed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (170, 'Chinchou', 'Water', 'Electric', 75, 38, 38, 56, 56, 67, 5.00, 120.00, 'It discharges positive and negative electricity from the tips of its antennae to shock its foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (171, 'Lanturn', 'Water', 'Electric', 125, 58, 58, 76, 76, 67, 12.00, 225.00, 'Lanturn’s light can shine up from great depths. It is nicknamed the Deep-Sea Star.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (172, 'Pichu', 'Electric', null, 20, 40, 15, 35, 35, 60, 3.00, 20.00, 'Despite this Pokémon’s cute appearance, those who want to live with one should prepare to be on the receiving end of its electric jolts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (173, 'Cleffa', 'Fairy', null, 50, 25, 28, 45, 55, 15, 3.00, 30.00, 'In silhouette, they resemble twinkling starlight. When shooting stars rain from the night sky, Cleffa gather in numbers and dance as though they are indeed incarnations of the stars.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (174, 'Igglybuff', 'Normal', 'Fairy', 90, 30, 15, 40, 20, 15, 3.00, 10.00, 'It likes to sing but is not yet good at it. With praise and encouragement, it will get better little by little.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (175, 'Togepi', 'Fairy', null, 35, 20, 65, 40, 65, 20, 3.00, 15.00, 'This ovate creature is frequently mistaken for a moving egg when encountered out in the fields or in the mountains. Its guileless smile soothes the soul.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (176, 'Togetic', 'Fairy', 'Flying', 55, 40, 85, 80, 105, 40, 6.00, 32.00, 'No records exist of Togetic being seen in the wilds. Rumors abound that it evolves under the loving care of a trusted human companion, upon whom the Pokémon then bestows great joy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (177, 'Natu', 'Psychic', 'Flying', 40, 50, 45, 70, 45, 70, 2.00, 20.00, 'It picks food from cactus plants, deftly avoiding buds and spines. It seems to skip about to move.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (178, 'Xatu', 'Psychic', 'Flying', 65, 75, 70, 95, 70, 95, 15.00, 150.00, 'This odd Pokémon can see both the past and the future. It eyes the sun’s movement all day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (179, 'Mareep', 'Electric', null, 55, 40, 40, 65, 45, 35, 6.00, 78.00, 'Its fleece grows continually. In the summer, the fleece is fully shed, but it grows back in a week.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (180, 'Flaaffy', 'Electric', null, 70, 55, 55, 80, 60, 45, 8.00, 133.00, 'Because of its rubbery, electricity-resistant skin, it can store lots of electricity in its fur.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (181, 'Ampharos', 'Electric', null, 90, 75, 85, 115, 90, 55, 14.00, 615.00, 'When it gets dark, the light from its bright, shiny tail can be seen from far away on the ocean’s surface.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (182, 'Bellossom', 'Grass', null, 75, 80, 95, 90, 100, 50, 4.00, 58.00, 'When the heavy rainfall season ends, it is drawn out by warm sunlight to dance in the open.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (183, 'Marill', 'Water', 'Fairy', 70, 20, 50, 20, 50, 40, 4.00, 85.00, 'The oil-filled tail functions as a buoy, so it’s fine even in rivers with strong currents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (184, 'Azumarill', 'Water', 'Fairy', 100, 50, 80, 60, 80, 50, 8.00, 285.00, 'By keeping still and listening intently, it can tell what is in even wild, fast-moving rivers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (185, 'Sudowoodo', 'Rock', null, 70, 100, 115, 30, 65, 30, 12.00, 380.00, 'To avoid being attacked, it does nothing but mimic a tree. It hates water and flees from rain.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (186, 'Politoed', 'Water', null, 90, 75, 75, 90, 100, 70, 11.00, 339.00, 'A group of Poliwag and Poliwhirl will form with a Politoed as the leader. Politoed’s cries make the Pokémon of the group obey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (187, 'Hoppip', 'Grass', 'Flying', 35, 35, 40, 35, 55, 50, 4.00, 5.00, 'Outside of cold regions, Hoppip can be found practically everywhere. This is because the wind carries this species all over the world.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (188, 'Skiploom', 'Grass', 'Flying', 55, 45, 50, 45, 65, 80, 6.00, 10.00, 'When the weather grows cold, Skiploom’s flower closes and the Pokémon cannot photosynthesize, so it flies away to warmer regions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (189, 'Jumpluff', 'Grass', 'Flying', 75, 55, 70, 55, 95, 110, 8.00, 30.00, 'Beware its cotton spores. If you accidentally breathe them in, you’ll be racked with coughs and itchiness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (190, 'Aipom', 'Normal', null, 55, 70, 55, 40, 55, 85, 8.00, 115.00, 'This treetop dweller possesses a tail as dexterous as a hand. Ancient writings describe this Pokémon as a one-armed oddity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (191, 'Sunkern', 'Grass', null, 30, 30, 30, 30, 30, 30, 3.00, 18.00, 'It is very weak. Its only means of defense is to shake its leaves desperately at its attacker.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (192, 'Sunflora', 'Grass', null, 75, 75, 55, 105, 85, 30, 8.00, 85.00, 'Since it converts sunlight into energy, it is always looking in the direction of the sun.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (193, 'Yanma', 'Bug', 'Flying', 65, 65, 45, 75, 45, 95, 12.00, 380.00, 'Its frail wings are so thin that one can see clear through them. However, during flight these wings exhibit the power to churn air with force enough to launch a house skyward.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (194, 'Wooper', 'Water', 'Ground', 55, 45, 45, 25, 25, 15, 4.00, 85.00, 'When the temperature cools in the evening, they emerge from water to seek food along the shore.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (195, 'Quagsire', 'Water', 'Ground', 95, 85, 85, 65, 65, 35, 14.00, 750.00, 'A dim-witted Pokémon. It doesn’t care if it bumps its head into boats or rocks while swimming.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (196, 'Espeon', 'Psychic', null, 65, 65, 60, 130, 95, 110, 9.00, 265.00, 'It uses the fine hair that covers its body to sense air currents and predict its enemy’s actions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (197, 'Umbreon', 'Dark', null, 95, 65, 110, 60, 130, 65, 10.00, 270.00, 'When darkness falls, the rings on the body begin to glow, striking fear in the hearts of anyone nearby.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (198, 'Murkrow', 'Dark', 'Flying', 60, 85, 42, 85, 42, 91, 5.00, 21.00, 'If spotted, it will lure an unwary person into chasing it, then lose the pursuer on mountain trails.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (199, 'Slowking', 'Water', 'Psychic', 95, 75, 80, 100, 110, 30, 20.00, 795.00, 'It has incredible intellect and intuition. Whatever the situation, it remains calm and collected.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (200, 'Misdreavus', 'Ghost', null, 60, 60, 60, 85, 85, 85, 7.00, 10.00, 'It loves to bite and yank people’s hair from behind without warning, just to see their shocked reactions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (201, 'Unown', 'Psychic', null, 48, 72, 48, 72, 48, 48, 5.00, 50.00, 'It is hard to believe these strangely shaped Pokémon are truly living creatures. I’ve pointed out that the species’ many forms resemble writing from other lands; no one will take me seriously.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (202, 'Wobbuffet', 'Psychic', null, 190, 33, 58, 33, 58, 33, 13.00, 285.00, 'It desperately tries to keep its black tail hidden. This behavior is said to be proof that its tail hides a secret.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (203, 'Girafarig', 'Normal', 'Psychic', 70, 80, 65, 90, 65, 85, 15.00, 415.00, 'Girafarig’s tail has a small head. It instinctively bites at any foe that approaches the Pokémon from behind.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (204, 'Pineco', 'Bug', null, 50, 65, 90, 35, 35, 15, 6.00, 72.00, 'It spits out a fluid that it uses to glue tree bark to its body. The fluid hardens when it touches air.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (205, 'Forretress', 'Bug', 'Steel', 75, 90, 140, 60, 60, 40, 12.00, 1258.00, 'Its entire body is shielded by a steel-hard shell. What lurks inside this shell is a total mystery.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (206, 'Dunsparce', 'Normal', null, 100, 70, 70, 65, 65, 45, 15.00, 140.00, 'If spotted, it escapes by burrowing with its tail. It can float just slightly using its wings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (207, 'Gligar', 'Ground', 'Flying', 65, 75, 105, 35, 65, 85, 11.00, 648.00, 'Its tail is tipped by a thick, horrible stinger. To bring down prey, it will first obscure their vision by covering their faces with its body, and then it will use the stinger to inject them with venom.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (208, 'Steelix', 'Steel', 'Ground', 75, 85, 200, 55, 65, 30, 92.00, 4000.00, 'This Pokémon evolved through use of a strange item. Its body is coated with steel powder and notably hard—not even diamond can leave so much as a scratch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (209, 'Snubbull', 'Fairy', null, 60, 80, 50, 40, 40, 30, 6.00, 78.00, 'Small Pokémon flee from its scary face. It is, however, considered by many people to be cute.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (210, 'Granbull', 'Fairy', null, 90, 120, 75, 60, 60, 45, 14.00, 487.00, 'It is timid in spite of its looks. If it becomes enraged, however, it will strike with its huge fangs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (211, 'Qwilfish', 'Water', 'Poison', 65, 95, 85, 55, 55, 85, 5.00, 39.00, 'Experienced fishers say they try to catch Qwilfish in the brief moment that these Pokémon become defenseless just after launching poisonous spikes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (212, 'Scizor', 'Bug', 'Steel', 70, 130, 100, 55, 80, 65, 18.00, 1180.00, 'It swings its eye-patterned pincers up to scare its foes. This makes it look like it has three heads.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (213, 'Shuckle', 'Bug', 'Rock', 20, 10, 230, 10, 230, 5, 6.00, 205.00, 'It stores berries in its shell. The berries mix with its body fluids to become delicious juices.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (214, 'Heracross', 'Bug', 'Fighting', 80, 125, 75, 40, 95, 85, 15.00, 540.00, 'With its herculean powers, it can easily throw around an object that is 100 times its own weight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (215, 'Sneasel', 'Dark', 'Ice', 55, 95, 55, 35, 75, 115, 9.00, 280.00, 'This is a smart and sneaky Pokémon. A pair may work together to steal eggs by having one lure the parents away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (216, 'Teddiursa', 'Normal', null, 60, 80, 50, 50, 50, 40, 6.00, 88.00, 'Its paws are soaked in oodles of honey. When nervous, Teddiursa will lick its paws and soon have a smile back on its face.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (217, 'Ursaring', 'Normal', null, 90, 130, 75, 75, 75, 55, 18.00, 1258.00, 'It is quite skilled at climbing trees. If it comes across a Primeape while searching for berries in the treetops, trouble will surely ensue.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (218, 'Slugma', 'Fire', null, 40, 40, 40, 70, 40, 20, 7.00, 350.00, 'Its body is made of magma. If it doesn’t keep moving, its body will cool and harden.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (219, 'Magcargo', 'Fire', 'Rock', 60, 50, 120, 90, 80, 30, 8.00, 550.00, 'Its body temperature is roughly 18,000 degrees Fahrenheit. Flames burst from gaps in its shell made of hardened magma.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (220, 'Swinub', 'Ice', 'Ground', 50, 50, 40, 30, 30, 50, 4.00, 65.00, 'Swinub excels at sniffing out mushrooms buried beneath grass or snow. Since ancient times, the people of Hisui have often relied upon this skill.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (221, 'Piloswine', 'Ice', 'Ground', 100, 100, 80, 60, 60, 50, 11.00, 558.00, 'The long fur of this Pokémon covers its eyes, ears, and even limbs, allowing Piloswine to resist harshly frigid conditions. The Pokémon’s white tusks can be used to defeat its enemies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (222, 'Corsola', 'Water', 'Rock', 65, 55, 95, 65, 95, 35, 6.00, 50.00, 'Many live in the clean seas of the south. They apparently can’t live in polluted waters.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (223, 'Remoraid', 'Water', null, 35, 65, 35, 65, 35, 65, 6.00, 120.00, 'Spits water from its mouth with incredible accuracy. It captures Burmy by shooting them down off the branches from which they dangle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (224, 'Octillery', 'Water', null, 75, 105, 75, 105, 75, 45, 9.00, 285.00, 'While Octillery still shoots water from its mouth, the drastic anatomical difference between it and Remoraid meant that for a long time, no one believed the former evolved from the latter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (225, 'Delibird', 'Ice', 'Flying', 45, 55, 45, 65, 45, 75, 9.00, 160.00, 'It always carries its food with it, wherever it goes. If attacked, it throws its food at the opponent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (226, 'Mantine', 'Water', 'Flying', 85, 40, 70, 80, 140, 70, 21.00, 2200.00, 'This calm and gentle Pokémon swims gracefully through the sea. After building speed, it can leap out of the water. It is often misidentified as a bird Pokémon due to this behavior.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (227, 'Skarmory', 'Steel', 'Flying', 65, 80, 140, 40, 70, 70, 17.00, 505.00, 'Skarmory is clad entirely in ironhard armor. It flies at speeds over 180 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (228, 'Houndour', 'Dark', 'Fire', 45, 60, 30, 80, 50, 65, 6.00, 108.00, 'It uses different kinds of cries for communicating with others of its kind and for pursuing its prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (229, 'Houndoom', 'Dark', 'Fire', 75, 90, 50, 110, 80, 95, 14.00, 350.00, 'Upon hearing its eerie howls, other Pokémon get the shivers and head straight back to their nests.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (230, 'Kingdra', 'Water', 'Dragon', 75, 95, 95, 95, 95, 85, 18.00, 1520.00, 'It lives in caves on the seafloor and creates giant whirlpools every time it moves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (231, 'Phanpy', 'Ground', null, 90, 60, 60, 40, 40, 40, 5.00, 335.00, 'It is far stronger than it appears. If a Phanpy is swinging its trunk around and your arm gets hit by it, your arm bone will shatter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (232, 'Donphan', 'Ground', null, 90, 120, 120, 60, 60, 50, 11.00, 1200.00, 'Donphan is normally a calm Pokémon, but once it is enraged, it will curl its body into a ball and charge at you while rolling.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (233, 'Porygon2', 'Normal', null, 85, 80, 90, 105, 95, 60, 6.00, 325.00, 'A bizarre item caused this Pokémon to evolve. While it now exhibits many new gestures and expressions, its biology remains inscrutable.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (234, 'Stantler', 'Normal', null, 73, 95, 62, 85, 65, 85, 14.00, 712.00, 'It’s said that this Pokémon used to be stronger long ago when it had many enemies, and that it was even able to evolve under its own power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (235, 'Smeargle', 'Normal', null, 55, 20, 35, 20, 45, 75, 12.00, 580.00, 'It marks its territory by using its tail like a paintbrush. There are more than 5,000 different marks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (236, 'Tyrogue', 'Fighting', null, 35, 35, 35, 35, 35, 35, 7.00, 210.00, 'It is famous for its eagerness to fight and always nurses injuries from challenging larger foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (237, 'Hitmontop', 'Fighting', null, 50, 95, 95, 35, 110, 70, 14.00, 480.00, 'It fights while spinning like a top. The centrifugal force boosts its destructive power by a factor of 10.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (238, 'Smoochum', 'Ice', 'Psychic', 45, 30, 15, 85, 65, 65, 4.00, 60.00, 'It tests everything by touching with its lips, which remember what it likes and dislikes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (239, 'Elekid', 'Electric', null, 45, 63, 37, 65, 55, 95, 6.00, 235.00, 'They generate electricity by spinning their arms. During a thunderstorm, if one hears the lively voices of children out in the wilderness, what one is actually hearing are the voices of Elekid.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (240, 'Magby', 'Fire', null, 45, 75, 37, 70, 55, 83, 7.00, 214.00, 'This Pokémon lives in volcanic areas. With each breath, sparks spurt from its mouth and nose. When Magby is in good health, its flames gain a yellow tint.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (241, 'Miltank', 'Normal', null, 95, 80, 105, 40, 70, 100, 12.00, 755.00, 'It is said that kids who drink Miltank’s milk grow up to become hearty, healthy adults.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (242, 'Blissey', 'Normal', null, 255, 10, 10, 75, 135, 55, 15.00, 468.00, 'The eggs it lays are filled with happiness. Eating even one bite will bring a smile to anyone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (243, 'Raikou', 'Electric', null, 90, 85, 75, 115, 100, 115, 19.00, 1780.00, 'It is said to have fallen with lightning. It can fire thunderbolts from the rain clouds on its back.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (244, 'Entei', 'Fire', null, 115, 115, 85, 90, 75, 100, 21.00, 1980.00, 'It is said that when it roars, a volcano erupts somewhere around the globe.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (245, 'Suicune', 'Water', null, 100, 75, 115, 90, 115, 85, 20.00, 1870.00, 'It races around the world to purify fouled water. It dashes away with the north wind.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (246, 'Larvitar', 'Rock', 'Ground', 50, 64, 50, 45, 50, 41, 6.00, 720.00, 'It is born deep underground. It can’t emerge until it has entirely consumed the soil around it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (247, 'Pupitar', 'Rock', 'Ground', 70, 84, 70, 65, 70, 51, 12.00, 1520.00, 'Its shell is as hard as bedrock, and it is also very strong. Its thrashing can topple a mountain.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (248, 'Tyranitar', 'Rock', 'Dark', 100, 134, 110, 95, 100, 61, 20.00, 2020.00, 'In just one of its mighty hands, it has the power to make the ground shake and mountains crumble.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (249, 'Lugia', 'Psychic', 'Flying', 106, 90, 130, 90, 154, 110, 52.00, 2160.00, 'It sleeps in a deep-sea trench. If it flaps its wings, it is said to cause a 40-day storm.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (250, 'Ho-Oh', 'Fire', 'Flying', 106, 130, 90, 110, 154, 90, 38.00, 1990.00, 'Its feathers are in seven colors. It is said that anyone seeing it is promised eternal happiness.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (251, 'Celebi', 'Psychic', 'Grass', 100, 100, 100, 100, 100, 100, 6.00, 50.00, 'It has the power to travel across time, but it is said to appear only in peaceful times.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (252, 'Treecko', 'Grass', null, 40, 45, 35, 65, 55, 70, 5.00, 50.00, 'The soles of its feet are covered by countless tiny hooks, enabling it to walk on walls and ceilings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (253, 'Grovyle', 'Grass', null, 50, 65, 45, 85, 65, 95, 9.00, 216.00, 'It lives in dense jungles. While closing in on its prey, it leaps from branch to branch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (254, 'Sceptile', 'Grass', null, 70, 85, 65, 105, 85, 120, 17.00, 522.00, 'The leaves that grow on its arms can slice down thick trees. It is without peer in jungle combat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (255, 'Torchic', 'Fire', null, 45, 60, 40, 70, 50, 45, 4.00, 25.00, 'A fire burns inside it, so it feels very warm to hug. It launches fireballs of 1,800 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (256, 'Combusken', 'Fire', 'Fighting', 60, 85, 60, 85, 60, 55, 9.00, 195.00, 'Its kicking mastery lets it loose 10 kicks per second. It emits sharp cries to intimidate foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (257, 'Blaziken', 'Fire', 'Fighting', 80, 120, 70, 110, 70, 80, 19.00, 520.00, 'Flames spout from its wrists, enveloping its knuckles. Its punches scorch its foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (258, 'Mudkip', 'Water', null, 50, 70, 50, 50, 50, 40, 4.00, 76.00, 'Using the fin on its head, Mudkip senses the flow of water to keep track of what’s going on around it. Mudkip has the strength to heft boulders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (259, 'Marshtomp', 'Water', 'Ground', 70, 85, 70, 60, 70, 50, 7.00, 280.00, 'Its sturdy legs give it sure footing, even in mud. It burrows into dirt to sleep.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (260, 'Swampert', 'Water', 'Ground', 100, 110, 90, 85, 90, 60, 15.00, 819.00, 'It can swim while towing a large ship. It bashes down foes with a swing of its thick arms.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (261, 'Poochyena', 'Dark', null, 35, 55, 35, 30, 30, 35, 5.00, 136.00, 'A Pokémon with a persistent nature, it chases its chosen prey until the prey becomes exhausted.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (262, 'Mightyena', 'Dark', null, 70, 90, 70, 60, 60, 70, 10.00, 370.00, 'It chases down prey in a pack. It will never disobey the commands of a skilled Trainer.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (263, 'Zigzagoon', 'Normal', null, 38, 30, 41, 30, 41, 60, 4.00, 175.00, 'It walks in zigzag fashion. It’s good at finding items in the grass and even in the ground.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (264, 'Linoone', 'Normal', null, 78, 70, 61, 50, 61, 100, 5.00, 325.00, 'It charges prey at speeds over 60 mph. However, because it can only run straight, it often fails.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (265, 'Wurmple', 'Bug', null, 45, 45, 35, 20, 30, 20, 3.00, 36.00, 'Likes sap and is abundant in the wild. Why it evolves into various different forms is unknown. One cannot tell from a Wurmple’s appearance which form it will take when it evolves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (266, 'Silcoon', 'Bug', null, 50, 35, 55, 25, 25, 15, 6.00, 100.00, 'Wraps itself in thin strings of silk while it stores energy for evolution. It can’t extend its limbs and its movement is slow, but its eyes keep a sharp lookout—Silcoon is always on guard.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (267, 'Beautifly', 'Bug', 'Flying', 60, 70, 50, 100, 50, 65, 10.00, 284.00, 'A colorful and incredibly beautiful but also greedy Pokémon. In an effort to keep its favorite food all to itself, it will chase away Combee as they try to gather nectar.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (268, 'Cascoon', 'Bug', null, 50, 35, 55, 25, 25, 15, 7.00, 115.00, 'The silk coating its body is thin but sufficiently strong. Cascoon’s silk has a luster and texture superior to that of Silcoon’s, and clothes made using Cascoon silk are regarded as top-notch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (269, 'Dustox', 'Bug', 'Poison', 60, 50, 70, 50, 90, 65, 12.00, 316.00, 'Tends to be drawn to bonfires on dark nights. Difficult to chase away from settlements because of the way it scatters highly toxic scales.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (270, 'Lotad', 'Water', 'Grass', 40, 30, 30, 40, 50, 30, 5.00, 26.00, 'It looks like an aquatic plant and serves as a ferry for Pokémon that can’t swim.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (271, 'Lombre', 'Water', 'Grass', 60, 50, 50, 60, 70, 50, 12.00, 325.00, 'It has a mischievous spirit. If it spots an angler, it will tug on the fishing line to interfere.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (272, 'Ludicolo', 'Water', 'Grass', 80, 70, 70, 90, 100, 70, 15.00, 550.00, 'If it hears festive music, all its muscles fill with energy. It can’t help breaking out into a dance.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (273, 'Seedot', 'Grass', null, 40, 40, 50, 30, 30, 30, 5.00, 40.00, 'When it dangles from a tree branch, it looks just like an acorn. It enjoys scaring other Pokémon that try to peck at it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (274, 'Nuzleaf', 'Grass', 'Dark', 70, 70, 40, 60, 40, 60, 10.00, 280.00, 'The sound of its grass flute makes its listeners uneasy. It lives deep in the forest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (275, 'Shiftry', 'Grass', 'Dark', 90, 100, 60, 90, 60, 80, 13.00, 596.00, 'By flapping its leafy fans, it can whip up gusts of 100 feet per second that can level houses.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (276, 'Taillow', 'Normal', 'Flying', 40, 55, 30, 30, 30, 85, 3.00, 23.00, 'It has a gutsy spirit that makes it bravely take on tough foes. It flies in search of warm climates.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (277, 'Swellow', 'Normal', 'Flying', 60, 85, 60, 75, 50, 125, 7.00, 198.00, 'It circles the sky in search of prey and dives sharply to catch its target.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (278, 'Wingull', 'Water', 'Flying', 40, 30, 30, 55, 30, 85, 6.00, 95.00, 'It rides upon ocean winds as if it were a glider. In the winter, it hides food around its nest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (279, 'Pelipper', 'Water', 'Flying', 60, 50, 100, 95, 70, 65, 12.00, 280.00, 'It protects its young in its beak. It bobs on waves, resting on them on days when the waters are calm.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (280, 'Ralts', 'Psychic', 'Fairy', 28, 25, 25, 45, 35, 40, 4.00, 66.00, 'It is highly attuned to the emotions of people and Pokémon. It hides if it senses hostility.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (281, 'Kirlia', 'Psychic', 'Fairy', 38, 35, 35, 65, 55, 50, 8.00, 202.00, 'The cheerful spirit of its Trainer gives it energy for its psychokinetic power. It spins and dances when happy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (282, 'Gardevoir', 'Psychic', 'Fairy', 68, 65, 65, 125, 115, 80, 16.00, 484.00, 'It unleashes psychokinetic energy at full power when protecting a Trainer it has bonded closely with.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (283, 'Surskit', 'Bug', 'Water', 40, 30, 32, 50, 52, 65, 5.00, 17.00, 'It secretes a thick, sweet-scented syrup from the tip of its head. It lives on weed-choked ponds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (284, 'Masquerain', 'Bug', 'Flying', 70, 60, 62, 100, 82, 80, 8.00, 36.00, 'The antennae have distinctive patterns that look like eyes. When it rains, they grow heavy, making flight impossible.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (285, 'Shroomish', 'Grass', null, 60, 40, 60, 40, 60, 35, 4.00, 45.00, 'If it senses danger, it scatters spores from the top of its head to protect itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (286, 'Breloom', 'Grass', 'Fighting', 60, 130, 80, 60, 60, 70, 12.00, 392.00, 'The seeds on its tail are made of toxic spores. It knocks out foes with quick, virtually invisible punches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (287, 'Slakoth', 'Normal', null, 60, 60, 60, 35, 35, 30, 8.00, 240.00, 'The way Slakoth lolls around makes anyone who watches it feel like doing the same.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (288, 'Vigoroth', 'Normal', null, 80, 80, 80, 55, 55, 90, 14.00, 465.00, 'It is always hungry because it won’t stop rampaging. Even while it is eating, it can’t keep still.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (289, 'Slaking', 'Normal', null, 150, 160, 100, 95, 65, 100, 20.00, 1305.00, 'This Pokémon lives lying on its side. It only rolls over and moves when there is no more grass to eat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (290, 'Nincada', 'Bug', 'Ground', 31, 45, 90, 30, 30, 40, 5.00, 55.00, 'It grows underground, sensing its surroundings using antennae instead of its virtually blind eyes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (291, 'Ninjask', 'Bug', 'Flying', 61, 90, 45, 50, 50, 160, 8.00, 120.00, 'Because they move so quickly, they sometimes become unseeable. They congregate around tree sap.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (292, 'Shedinja', 'Bug', 'Ghost', 1, 90, 45, 30, 30, 40, 8.00, 12.00, 'It is a discarded bug shell that came to life. Peering into the crack on its back is said to steal one’s spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (293, 'Whismur', 'Normal', null, 64, 51, 23, 51, 23, 28, 6.00, 163.00, 'Usually, its cries are like quiet murmurs. If frightened, it shrieks at the same volume as a jet plane.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (294, 'Loudred', 'Normal', null, 84, 71, 43, 71, 43, 48, 10.00, 405.00, 'The shock waves from its cries can tip over trucks. It stamps its feet to power up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (295, 'Exploud', 'Normal', null, 104, 91, 63, 91, 73, 68, 15.00, 840.00, 'Its howls can be heard over six miles away. It emits all sorts of noises from the ports on its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (296, 'Makuhita', 'Fighting', null, 72, 60, 30, 20, 30, 25, 10.00, 864.00, 'It toughens up by slamming into thick trees over and over. It gains a sturdy body and dauntless spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (297, 'Hariyama', 'Fighting', null, 144, 120, 60, 40, 60, 50, 23.00, 2538.00, 'It stomps on the ground to build power. It can send a 10-ton truck flying with a straight-arm punch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (298, 'Azurill', 'Normal', 'Fairy', 50, 20, 40, 20, 40, 20, 2.00, 20.00, 'Its tail is packed full of the nutrients it needs to grow.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (299, 'Nosepass', 'Rock', null, 30, 45, 135, 45, 90, 30, 10.00, 970.00, 'Once the people of Hisui discovered that its red nose always points north, they grew to rely on it greatly when traveling afar. The nose seems to work in a similar way to ancient compasses.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (300, 'Skitty', 'Normal', null, 50, 45, 45, 35, 35, 50, 6.00, 110.00, 'It can’t stop itself from chasing moving things, and it runs in circles, chasing its own tail.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (301, 'Delcatty', 'Normal', null, 70, 65, 65, 55, 55, 90, 11.00, 326.00, 'It is highly popular among Trainers for its sublime fur. It does not keep a nest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (302, 'Sableye', 'Dark', 'Ghost', 50, 75, 75, 65, 65, 50, 5.00, 110.00, 'Materials from gems it has eaten float to the surface of its body and can form an infinite number of patterns among individuals.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (303, 'Mawile', 'Steel', 'Fairy', 50, 85, 85, 55, 55, 50, 6.00, 115.00, 'Attached to its head is a huge set of jaws formed by horns. It can chew through iron beams.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (304, 'Aron', 'Steel', 'Rock', 50, 70, 100, 40, 40, 30, 4.00, 600.00, 'It usually lives deep in mountains. But when it’s hungry, it shows up at the foot of the mountains and eats railroad tracks and cars.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (305, 'Lairon', 'Steel', 'Rock', 60, 90, 140, 50, 50, 40, 9.00, 1200.00, 'For food, it digs up iron ore. It smashes its steely body against others to fight over territory.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (306, 'Aggron', 'Steel', 'Rock', 70, 110, 180, 60, 60, 50, 21.00, 3600.00, 'While seeking iron for food, it digs tunnels by breaking through bedrock with its steel horns.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (307, 'Meditite', 'Fighting', 'Psychic', 30, 40, 55, 40, 55, 60, 6.00, 112.00, 'It meditates to heighten its inner energy and to float in the air. It eats one berry a day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (308, 'Medicham', 'Fighting', 'Psychic', 60, 60, 75, 60, 75, 80, 13.00, 315.00, 'It elegantly avoids attacks with dance-like steps, then launches a devastating blow in the same motion.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (309, 'Electrike', 'Electric', null, 40, 45, 40, 65, 40, 65, 6.00, 152.00, 'Using electricity stored in its fur, it stimulates its muscles to heighten its reaction speed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (310, 'Manectric', 'Electric', null, 70, 75, 60, 105, 60, 105, 15.00, 402.00, 'It discharges electricity from its mane. The Pokémon creates a thundercloud overhead from which to drop lightning bolts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (311, 'Plusle', 'Electric', null, 60, 50, 40, 85, 75, 95, 4.00, 42.00, 'It cheers on friends with pom-poms made of sparks. It drains power from telephone poles.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (312, 'Minun', 'Electric', null, 60, 40, 50, 75, 85, 95, 4.00, 42.00, 'It cheers on friends. If its friends are losing, its body lets off more and more sparks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (313, 'Volbeat', 'Bug', null, 65, 73, 75, 47, 85, 85, 7.00, 177.00, 'It communicates with others by lighting up its rear at night. It loves Illumise’s sweet aroma.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (314, 'Illumise', 'Bug', null, 65, 47, 75, 73, 85, 85, 6.00, 177.00, 'With its sweet aroma, it guides Volbeat to draw signs with light in the night sky.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (315, 'Roselia', 'Grass', 'Poison', 50, 60, 45, 100, 80, 65, 3.00, 20.00, 'Though beautiful, it has highly poisonous thorns. There is an old tradition in my homeland wherein one would send these thorns to an opponent to challenge them to a duel.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (316, 'Gulpin', 'Poison', null, 70, 43, 53, 43, 53, 40, 4.00, 103.00, 'It has a small heart and brain. Its stomach comprises most of its body, with enzymes to dissolve anything.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (317, 'Swalot', 'Poison', null, 100, 73, 83, 73, 83, 55, 17.00, 800.00, 'It can swallow a tire whole in one gulp. It secretes a horribly toxic fluid from the pores on its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (318, 'Carvanha', 'Water', 'Dark', 45, 90, 20, 65, 20, 65, 8.00, 208.00, 'They swarm any foe that invades their territory. Their sharp fangs can tear out boat hulls.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (319, 'Sharpedo', 'Water', 'Dark', 70, 120, 40, 95, 40, 95, 18.00, 888.00, 'Its fangs rip through sheet iron. It swims at 75 mph and is known as the Bully of the Sea.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (320, 'Wailmer', 'Water', null, 130, 70, 35, 70, 35, 60, 20.00, 1300.00, 'On sunny days, it lands on beaches to bounce like a ball and play. It spouts water from its nostrils.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (321, 'Wailord', 'Water', null, 170, 90, 45, 90, 45, 60, 145.00, 3980.00, 'It’s the biggest of all Pokémon. It can dive to a depth of almost 10,000 feet on only one breath.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (322, 'Numel', 'Fire', 'Ground', 60, 60, 40, 65, 45, 35, 7.00, 240.00, 'The flaming magma it stores in the hump on its back is the source of its tremendous power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (323, 'Camerupt', 'Fire', 'Ground', 70, 100, 70, 105, 75, 40, 19.00, 2200.00, 'If angered, the humps on its back erupt in a shower of molten lava. It lives in the craters of volcanoes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (324, 'Torkoal', 'Fire', null, 70, 85, 140, 85, 70, 20, 5.00, 804.00, 'Coal is the source of Torkoal’s energy. Large amounts of coal can be found in the mountains where they live.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (325, 'Spoink', 'Psychic', null, 60, 25, 35, 70, 80, 60, 7.00, 306.00, 'Using its tail like a spring, it keeps its heart beating by bouncing constantly. If it stops, it dies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (326, 'Grumpig', 'Psychic', null, 80, 45, 65, 90, 110, 80, 9.00, 715.00, 'It uses black pearls to amplify its psychic power. It does a strange dance to control foes’ minds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (327, 'Spinda', 'Normal', null, 60, 60, 60, 60, 60, 60, 11.00, 50.00, 'No two Spinda have the same pattern of spots. Their tottering steps hinder the aim of foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (328, 'Trapinch', 'Ground', null, 45, 100, 45, 45, 45, 10, 7.00, 150.00, 'It makes a conical pit in desert sand and lies in wait at the bottom for prey to come tumbling down.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (329, 'Vibrava', 'Ground', 'Dragon', 50, 70, 50, 50, 50, 70, 11.00, 153.00, 'It violently shudders its wings, generating ultrasonic waves to induce headaches in people.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (330, 'Flygon', 'Ground', 'Dragon', 80, 100, 80, 80, 80, 100, 20.00, 820.00, 'It whips up sandstorms with powerful flaps of its wings. It is known as the Desert Spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (331, 'Cacnea', 'Grass', null, 50, 85, 40, 85, 40, 35, 4.00, 513.00, 'It lives in arid locations. Its yellow flowers bloom once a year.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (332, 'Cacturne', 'Grass', 'Dark', 70, 115, 60, 115, 60, 55, 13.00, 774.00, 'It lives in deserts. It becomes active at night when it hunts for prey exhausted from the desert’s heat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (333, 'Swablu', 'Normal', 'Flying', 45, 40, 60, 40, 75, 50, 4.00, 12.00, 'It can’t relax if it or its surroundings are not clean. It wipes off dirt with its wings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (334, 'Altaria', 'Dragon', 'Flying', 75, 70, 90, 70, 105, 80, 11.00, 206.00, 'On sunny days, it flies freely through the sky and blends into the clouds. It sings in a beautiful soprano.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (335, 'Zangoose', 'Normal', null, 73, 115, 60, 60, 60, 90, 13.00, 403.00, 'If it comes across a Seviper, its fur bristles and it assumes its battle pose. Its sharp claws are its best weapon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (336, 'Seviper', 'Poison', null, 73, 100, 60, 100, 60, 65, 27.00, 525.00, 'Constant polishing makes the edge of the blade on its tail extremely sharp. It’s Zangoose’s archrival.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (337, 'Lunatone', 'Rock', 'Psychic', 90, 55, 65, 95, 85, 70, 10.00, 1680.00, 'It becomes active on nights with a full moon, so it is said to have some link to the lunar phases.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (338, 'Solrock', 'Rock', 'Psychic', 90, 95, 85, 55, 65, 70, 12.00, 1540.00, 'This new Pokémon species is rumored to be an avatar of the sun. The Pokémon gives off light while spinning.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (339, 'Barboach', 'Water', 'Ground', 50, 48, 43, 46, 41, 60, 4.00, 19.00, 'It probes muddy riverbeds with its two long whiskers. A slimy film protects its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (340, 'Whiscash', 'Water', 'Ground', 110, 78, 73, 76, 71, 60, 9.00, 236.00, 'Sighting Whiscash leaping from the water is believed to herald an earthquake.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (341, 'Corphish', 'Water', null, 43, 80, 65, 50, 35, 35, 6.00, 115.00, 'Its hardy vitality enables it to adapt to any environment. Its pincers will never release prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (342, 'Crawdaunt', 'Water', 'Dark', 63, 120, 85, 90, 55, 55, 11.00, 328.00, 'It is a ruffian that uses its pincers to pick up and toss out other Pokémon from its pond.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (343, 'Baltoy', 'Ground', 'Psychic', 40, 40, 55, 40, 70, 55, 5.00, 215.00, 'It moves by spinning on its foot. It is a rare Pokémon that was discovered in ancient ruins.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (344, 'Claydol', 'Ground', 'Psychic', 60, 70, 105, 70, 120, 75, 15.00, 1080.00, 'An ancient clay figurine was exposed to a mysterious ray of light, and it came to life as a Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (345, 'Lileep', 'Rock', 'Grass', 66, 41, 77, 61, 87, 23, 10.00, 238.00, 'It lived on the seafloor 100 million years ago and was reanimated scientifically.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (346, 'Cradily', 'Rock', 'Grass', 86, 81, 97, 81, 107, 43, 15.00, 604.00, 'It lives in the shallows of warm seas. When the tide goes out, it digs up prey from beaches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (347, 'Anorith', 'Rock', 'Bug', 45, 95, 50, 40, 50, 75, 7.00, 125.00, 'This Pokémon ancestor was reanimated from a fossil. It lived in the sea and hunted with its claws.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (348, 'Armaldo', 'Rock', 'Bug', 75, 125, 100, 70, 80, 45, 15.00, 682.00, 'It went ashore after evolving. Its entire body is clad in a sturdy armor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (349, 'Feebas', 'Water', null, 20, 15, 20, 10, 55, 80, 6.00, 74.00, 'It eats anything, so it can even live in polluted streams and lakes. No one pays any attention to it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (350, 'Milotic', 'Water', null, 95, 60, 79, 100, 125, 81, 62.00, 1620.00, 'It is the world’s most beautiful Pokémon. There are many works of art featuring Milotic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (351, 'Castform', 'Normal', null, 70, 70, 70, 70, 70, 70, 3.00, 8.00, 'Its appearance changes with the weather. Recently, its molecules were found to be just like water.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (352, 'Kecleon', 'Normal', null, 60, 90, 70, 60, 120, 40, 10.00, 220.00, 'It can freely change its body’s color. The zigzag pattern on its belly doesn’t change, however.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (353, 'Shuppet', 'Ghost', null, 44, 75, 35, 63, 33, 45, 6.00, 23.00, 'It feeds on the dark emotions of sadness and hatred, which make it grow steadily stronger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (354, 'Banette', 'Ghost', null, 64, 115, 65, 83, 63, 65, 11.00, 125.00, 'Strong feelings of hatred turned a puppet into a Pokémon. If it opens its mouth, its cursed energy escapes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (355, 'Duskull', 'Ghost', null, 20, 40, 90, 30, 90, 25, 8.00, 150.00, 'I’ve heard that the children of Hisui all begin to behave once they’ve been told the story of how this Pokémon roams about before the witching hour to spirit away misbehaving children.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (356, 'Dusclops', 'Ghost', null, 40, 70, 130, 60, 130, 25, 16.00, 306.00, 'There are rumors that peeking inside its bandage-wrapped body will cause one to get pulled in through the gaps between the bandages, never to return. I’ve been too scared to verify.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (357, 'Tropius', 'Grass', 'Flying', 99, 68, 83, 72, 87, 51, 20.00, 1000.00, 'Delicious fruits grew out from around its neck because it always ate the same kind of fruit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (358, 'Chimecho', 'Psychic', null, 75, 50, 80, 95, 90, 65, 6.00, 10.00, 'Can emit waves of air powerful enough to knock out prey taller than itself. I hypothesize that it amplifies the faint sound of wind within its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (359, 'Absol', 'Dark', null, 65, 130, 60, 75, 60, 75, 12.00, 470.00, 'It senses coming disasters and appears before people only to warn them of impending danger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (360, 'Wynaut', 'Psychic', null, 95, 23, 48, 23, 48, 23, 6.00, 140.00, 'They grow strong by pushing up against one another en masse. They love eating sweet fruit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (361, 'Snorunt', 'Ice', null, 50, 50, 50, 50, 50, 50, 7.00, 168.00, 'It is said that a home visited by a Snorunt will prosper. It can withstand cold of −150 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (362, 'Glalie', 'Ice', null, 80, 80, 80, 80, 80, 80, 15.00, 2565.00, 'It prevents prey from escaping by instantaneously freezing moisture in the air.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (363, 'Spheal', 'Ice', 'Water', 70, 40, 50, 55, 50, 25, 8.00, 395.00, 'During the season when drift ice approaches the shore, Spheal prefers living on the ice—where fewer predators lurk—rather than the land. Its fur retains heat superbly and resists harsh cold.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (364, 'Sealeo', 'Ice', 'Water', 90, 60, 70, 75, 70, 45, 11.00, 876.00, 'Its white whiskers are very sensitive. Sealeo will balance Spheal on the tip of its nose, checking its scent and its feel to be sure the Spheal is healthy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (365, 'Walrein', 'Ice', 'Water', 110, 80, 90, 95, 90, 65, 14.00, 1506.00, 'Its thick tusks are strong enough to shatter drift ice. They have been known to break, but they will grow back by the next year. The Hisui region is well known for these broken tusks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (366, 'Clamperl', 'Water', null, 35, 64, 85, 74, 55, 32, 4.00, 525.00, 'It makes a single pearl during its lifetime. The pearl is said to amplify psychic power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (367, 'Huntail', 'Water', null, 55, 104, 105, 94, 75, 52, 17.00, 270.00, 'It lives deep in the sea. With a tail shaped like a small fish, it attracts unsuspecting prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (368, 'Gorebyss', 'Water', null, 55, 84, 105, 114, 75, 52, 18.00, 226.00, 'It lives at the bottom of the sea. In the springtime, its pink body turns more vivid for some reason.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (369, 'Relicanth', 'Water', 'Rock', 100, 90, 130, 45, 65, 55, 10.00, 234.00, 'This rare Pokémon was discovered during a deep-sea exploration. It has not changed in over 100 million years.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (370, 'Luvdisc', 'Water', null, 43, 30, 55, 40, 65, 97, 6.00, 87.00, 'During the spawning season, countless Luvdisc congregate at coral reefs, turning the waters pink.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (371, 'Bagon', 'Dragon', null, 45, 75, 60, 40, 30, 50, 6.00, 421.00, 'Its belief that it will be able to fly one day is apparently the influence of information carried in its genes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (372, 'Shelgon', 'Dragon', null, 65, 95, 100, 60, 50, 50, 11.00, 1105.00, 'Its armored body makes all attacks bounce off. The armor is too tough, however, making it heavy and somewhat sluggish.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (373, 'Salamence', 'Dragon', 'Flying', 95, 135, 80, 110, 80, 100, 15.00, 1026.00, 'It becomes uncontrollable if it is enraged. It destroys everything with shredding claws and fire.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (374, 'Beldum', 'Steel', 'Psychic', 40, 55, 80, 35, 60, 30, 6.00, 952.00, 'They converse with one another by using magnetic pulses. In a swarm, they move in perfect unison.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (375, 'Metang', 'Steel', 'Psychic', 60, 75, 100, 55, 80, 50, 12.00, 2025.00, 'It is formed by two Beldum joining together. Its steel body won’t be scratched if it collides with a jet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (376, 'Metagross', 'Steel', 'Psychic', 80, 135, 130, 95, 90, 70, 16.00, 5500.00, 'Metang combined to form it. With four brains, it has the intelligence of a supercomputer.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (377, 'Regirock', 'Rock', null, 80, 100, 200, 50, 100, 50, 17.00, 2300.00, 'Its entire body is made of rock. If any part chips off in battle, Regirock attaches rocks to repair itself.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (378, 'Regice', 'Ice', null, 80, 50, 100, 100, 200, 50, 18.00, 1750.00, 'Its body is made of ice from the ice age. It controls frigid air of −328 degrees Fahrenheit.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (379, 'Registeel', 'Steel', null, 80, 75, 150, 75, 150, 50, 19.00, 2050.00, 'Tempered by pressure underground over tens of thousands of years, its body cannot be scratched.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (380, 'Latias', 'Dragon', 'Psychic', 80, 80, 90, 110, 130, 110, 14.00, 400.00, 'Its body is covered with a down that can refract light in such a way that it becomes invisible.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (381, 'Latios', 'Dragon', 'Psychic', 80, 90, 80, 130, 110, 110, 20.00, 600.00, 'It is a highly intelligent Pokémon. By folding back its forelegs in flight, it can overtake jet planes.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (382, 'Kyogre', 'Water', null, 100, 100, 90, 150, 140, 90, 45.00, 3520.00, 'It is said to have widened the seas by causing downpours. It had been asleep in a marine trench.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (383, 'Groudon', 'Ground', null, 100, 150, 140, 100, 90, 90, 35.00, 9500.00, 'It had been asleep in underground magma ever since it fiercely fought Kyogre long ago.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (384, 'Rayquaza', 'Dragon', 'Flying', 105, 150, 90, 150, 90, 95, 70.00, 2065.00, 'It lives in the ozone layer far above the clouds and cannot be seen from the ground.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (385, 'Jirachi', 'Steel', 'Psychic', 100, 100, 100, 100, 100, 100, 3.00, 11.00, 'It is said to wake up for just seven days every 1,000 years and use its power to grant any wish.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (386, 'Deoxys', 'Psychic', null, 50, 150, 50, 150, 50, 150, 17.00, 608.00, 'An alien virus that fell to earth on a meteorite underwent a DNA mutation to become this Pokémon.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (387, 'Turtwig', 'Grass', null, 55, 68, 64, 45, 55, 31, 4.00, 102.00, 'This Pokémon becomes more energetic the more sunlight there is. The part resembling a shell is similar to silt and is slightly damp and warm to the touch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (388, 'Grotle', 'Grass', null, 75, 89, 85, 55, 65, 36, 11.00, 970.00, 'Appears where there is clean spring water. The fruit that grows on the shrubs on its shell is sweet, nutritious, and truly delicious.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (389, 'Torterra', 'Grass', 'Ground', 95, 109, 105, 75, 85, 56, 22.00, 3100.00, 'This remarkable, large-bodied Pokémon would serve beautifully as borrowed scenery for a garden, and its strength is peerless. Torterra roams the wilderness in search of clean water.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (390, 'Chimchar', 'Fire', null, 44, 58, 44, 58, 44, 61, 5.00, 62.00, 'Full of vigor and always in high spirits. It was once known by the name “Lantern-Tail” and feared as some kind of apparition.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (391, 'Monferno', 'Fire', 'Fighting', 64, 78, 52, 78, 52, 81, 9.00, 220.00, 'The deeper the blue on its face, the more powerful it will grow to become. It leaps about every which way and lands powerful blows against its opponents with the flame on its tail.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (392, 'Infernape', 'Fire', 'Fighting', 76, 104, 71, 104, 71, 108, 12.00, 550.00, 'A tall, hardy Pokémon with a dazzling appearance. It shrouds itself in flame and battles as if engaged in dance—truly a sight to behold.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (393, 'Piplup', 'Water', null, 53, 51, 53, 61, 56, 40, 4.00, 52.00, 'Prefers cold climes and appears along coasts. It’s an adorable little thing—as cute as any child—but it’s also prideful, unwilling to accept handouts from people.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (394, 'Prinplup', 'Water', null, 64, 66, 68, 81, 76, 50, 8.00, 230.00, 'It swims gracefully through the frigid sea and sings with a voice like the roaring tide. It has powerful, sturdy wings and dignity to match.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (395, 'Empoleon', 'Water', 'Steel', 84, 86, 88, 111, 101, 60, 17.00, 845.00, 'Since ancient times, it has been revered by the people of Hisui, who call it the Master of the Waves. Its wings are a match for even master-crafted blades.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (396, 'Starly', 'Normal', 'Flying', 40, 55, 30, 30, 30, 60, 3.00, 20.00, 'Because they are weak individually, they form groups. However, they bicker if the group grows too big.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (397, 'Staravia', 'Normal', 'Flying', 55, 75, 50, 40, 40, 80, 6.00, 155.00, 'They maintain huge flocks, although fierce scuffles break out between various flocks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (398, 'Staraptor', 'Normal', 'Flying', 85, 120, 70, 50, 60, 100, 12.00, 249.00, 'It never stops attacking even if it is injured. It fusses over the shape of its comb.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (399, 'Bidoof', 'Normal', null, 59, 45, 40, 35, 40, 31, 5.00, 200.00, 'Bidoof has an unsophisticated face and is rarely flustered by anything. There have been incidents involving Bidoof sauntering into villages and gnawing on the houses without a single care.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (400, 'Bibarel', 'Normal', 'Water', 79, 85, 60, 55, 60, 71, 10.00, 315.00, 'Bibarel fur repels water and is also a fantastic material for heat retention. These Pokémon create dams on rivers to live in.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (401, 'Kricketot', 'Bug', null, 37, 25, 41, 25, 41, 25, 3.00, 22.00, 'When its antennae hit each other, it sounds like the music of a xylophone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (402, 'Kricketune', 'Bug', null, 77, 85, 51, 55, 51, 65, 10.00, 255.00, 'There is a village that hosts a contest based on the amazingly variable cries of this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (403, 'Shinx', 'Electric', null, 45, 65, 34, 40, 34, 45, 5.00, 95.00, 'The extension and contraction of its muscles generates electricity. Its fur glows when it’s in trouble.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (404, 'Luxio', 'Electric', null, 60, 85, 49, 60, 49, 60, 9.00, 305.00, 'By gathering their tails together, they collectively generate powerful electricity from their claws.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (405, 'Luxray', 'Electric', null, 80, 120, 79, 95, 79, 70, 14.00, 420.00, 'Luxray’s ability to see through objects comes in handy when it’s scouting for danger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (406, 'Budew', 'Grass', 'Poison', 40, 30, 35, 50, 70, 55, 2.00, 12.00, 'When the sun’s light strengthens, the bud atop this Pokémon’s head opens. This is a sign to the people that the harsh winter is over, and the season of budding has begun.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (407, 'Roserade', 'Grass', 'Poison', 60, 70, 65, 125, 105, 90, 9.00, 145.00, 'Hidden within the bouquet on each hand are thorned whips loaded with virulent poison. Roserade moves gracefully as it corners its prey and mercilessly lashes them with its whips.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (408, 'Cranidos', 'Rock', null, 67, 125, 40, 30, 30, 58, 9.00, 315.00, 'An incredibly rare sight. They duel each other by ramming their heads together, and the resulting sound echoes throughout the area like the pealing of a bell.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (409, 'Rampardos', 'Rock', null, 97, 165, 60, 65, 50, 58, 16.00, 1025.00, 'Very little is known about its biology. Can knock down massive trees by smashing its beautiful, pearl-like crown against them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (410, 'Shieldon', 'Rock', 'Steel', 30, 42, 118, 42, 88, 30, 5.00, 570.00, 'Much remains unknown about this Pokémon, as few have ever seen it. However, we know that it is calm and dislikes conflict, and it enjoys polishing its face against trees and rocks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (411, 'Bastiodon', 'Rock', 'Steel', 60, 52, 168, 47, 138, 30, 13.00, 1495.00, 'Its face is sturdy—as strong as diamond—and this hardness offers a very stable defense. Much about this species is still unknown, such as its natural habitat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (412, 'Burmy', 'Bug', null, 40, 29, 45, 29, 45, 36, 2.00, 34.00, 'If its cloak is even slightly damaged, Burmy will immediately repair it with whatever is close at hand. The Pokémon within the cloak is scrawny and vulnerable to the cold.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (413, 'Wormadam', 'Bug', 'Grass', 60, 59, 85, 79, 105, 36, 5.00, 65.00, 'The cloak—fashioned from plant matter—has merged with the Pokémon and is now part of the body, like fur or skin. I suspect this fusion is an effect of the energy involved in evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (414, 'Mothim', 'Bug', 'Flying', 70, 94, 50, 94, 50, 66, 9.00, 233.00, 'Scatters steel-colored scales as it flaps its wings. Despite being observed feeding primarily on the nectar of flowers, Mothim is not often seen around flower gardens.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (415, 'Combee', 'Bug', 'Flying', 30, 30, 42, 30, 42, 70, 3.00, 55.00, 'The trio is together from birth. It constantly gathers nectar from flowers to please Vespiquen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (416, 'Vespiquen', 'Bug', 'Flying', 70, 80, 102, 80, 102, 40, 12.00, 385.00, 'It raises grubs in the holes in its body. It secretes pheromones to control Combee.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (417, 'Pachirisu', 'Electric', null, 60, 45, 70, 45, 90, 95, 4.00, 39.00, 'A pair may be seen rubbing their cheek pouches together in an effort to share stored electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (418, 'Buizel', 'Water', null, 55, 65, 35, 60, 30, 85, 7.00, 295.00, 'It inflates its flotation sac, keeping its face above water in order to watch for prey movement.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (419, 'Floatzel', 'Water', null, 85, 105, 55, 85, 50, 115, 11.00, 335.00, 'It is a common sight around fishing ports. It is known to rescue people and help fishers carry what they caught.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (420, 'Cherubi', 'Grass', null, 45, 35, 45, 62, 53, 35, 4.00, 33.00, 'Once the fruit growing alongside the main body is large and plump, Cherubi will use the nutrients within to evolve. The fruit then detaches, becoming nourishment for other creatures.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (421, 'Cherrim', 'Grass', null, 70, 60, 70, 87, 78, 85, 5.00, 93.00, 'Motionless, save for the occasional quiver. A rich array of Pokémon can be found gathered around it, drawn by the scent exuded from Cherrim’s folded petals.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (422, 'Shellos', 'Water', null, 76, 48, 48, 57, 62, 34, 3.00, 63.00, 'It oozes a purple fluid to deter enemies. Apparently, there are more West Sea Shellos now than there were in the past.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (423, 'Gastrodon', 'Water', 'Ground', 111, 83, 68, 92, 82, 39, 9.00, 299.00, 'It appears on beaches where the waters are shallow. Once it catches prey, it will slowly melt them with its mucus before slurping them up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (424, 'Ambipom', 'Normal', null, 75, 100, 66, 60, 66, 115, 12.00, 203.00, 'To affirm their kinship, members of this species will form a ring by linking their newly doubled tails together. On rare occasions, humans have been accepted into such rings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (425, 'Drifloon', 'Ghost', 'Flying', 90, 50, 34, 60, 44, 70, 4.00, 12.00, 'Because of the way it floats aimlessly, an old folktale calls it a “signpost for wandering spirits.”', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (426, 'Drifblim', 'Ghost', 'Flying', 150, 80, 44, 90, 54, 80, 12.00, 150.00, 'They carry people and Pokémon, but the wind can catch them, so there can’t be a fixed destination.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (427, 'Buneary', 'Normal', null, 55, 66, 44, 44, 56, 85, 4.00, 55.00, 'My hypothesis as to why Buneary rolls up its ears is that its hearing is far too keen. I surmise that the Pokémon protects its hearing by limiting the sound that may enter its ears.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (428, 'Lopunny', 'Normal', null, 65, 76, 84, 54, 96, 105, 12.00, 333.00, 'Its fur is warm and yet remarkably light. This Pokémon kicks as though it were a master of karate, driving back its opponents with ease.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (429, 'Mismagius', 'Ghost', null, 60, 60, 60, 105, 105, 105, 9.00, 44.00, 'Its cries sound like incantations to torment the foe. It appears where you least expect it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (430, 'Honchkrow', 'Dark', 'Flying', 100, 125, 52, 105, 52, 71, 9.00, 273.00, 'A single cry from this nocturnal Pokémon, and more than 100 of its Murkrow cronies will assemble.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (431, 'Glameow', 'Normal', null, 49, 55, 42, 42, 37, 85, 5.00, 39.00, 'Bewitches humans with its helical tail and piercing gaze. Its hidden claws are quite sharp as well, making this Pokémon an exceedingly tricky opponent if antagonized.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (432, 'Purugly', 'Normal', null, 71, 82, 64, 64, 59, 112, 10.00, 438.00, 'Though impudent and difficult to tame, Purugly enjoys great popularity due to its fur, the beauty of which surpasses even velveteen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (433, 'Chingling', 'Psychic', null, 45, 30, 50, 65, 50, 45, 2.00, 6.00, 'This Pokémon gave me an excruciating headache when it seemingly cried out without making a sound. Perhaps there are some sounds that the human ear is simply incapable of hearing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (434, 'Stunky', 'Poison', 'Dark', 63, 63, 47, 41, 41, 74, 4.00, 192.00, 'The foul fluid from its rear is so revolting that it can make people feel queasy up to a mile and a quarter away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (435, 'Skuntank', 'Poison', 'Dark', 103, 93, 67, 71, 61, 84, 10.00, 380.00, 'It attacks by spraying a repugnant fluid from its tail, but the stench dulls after a few squirts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (436, 'Bronzor', 'Steel', 'Psychic', 57, 24, 86, 24, 86, 23, 5.00, 605.00, 'They are found in ancient tombs. The patterns on their backs are said to be imbued with mysterious power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (437, 'Bronzong', 'Steel', 'Psychic', 67, 89, 116, 79, 116, 33, 13.00, 1870.00, 'It brought rains by opening portals to another world. It was revered as a bringer of plentiful harvests.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (438, 'Bonsly', 'Rock', null, 50, 80, 95, 10, 45, 10, 5.00, 150.00, 'From its eyes, it can expel excess moisture from its body. This liquid is similar in composition to human sweat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (439, 'Mime Jr.', 'Psychic', 'Fairy', 20, 25, 45, 70, 90, 60, 6.00, 130.00, 'Known to turn up in bustling marketplaces now and again. It mimics people much as a child would, then watches how they react, eyes sparkling.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (440, 'Happiny', 'Normal', null, 100, 5, 5, 15, 65, 30, 6.00, 244.00, 'It carefully carries a round, white rock that it thinks is an egg. It’s bothered by how curly its hair looks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (441, 'Chatot', 'Normal', 'Flying', 76, 65, 45, 92, 42, 91, 5.00, 19.00, 'A versatile performer skilled in the imitation of human speech. It is said that older, more experienced Chatot can even understand the meaning of the words they mimic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (442, 'Spiritomb', 'Ghost', 'Dark', 50, 92, 108, 92, 108, 35, 10.00, 1080.00, 'It was formed by uniting 108 spirits. It has been bound to the Odd Keystone to keep it from doing any mischief.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (443, 'Gible', 'Dragon', 'Ground', 58, 70, 45, 40, 45, 42, 7.00, 205.00, 'It nests in horizontal holes warmed by geothermal heat. Foes who get too close can expect to be pounced on and bitten.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (444, 'Gabite', 'Dragon', 'Ground', 68, 90, 65, 50, 55, 82, 14.00, 560.00, 'It loves sparkly things. It seeks treasures in caves and hoards the loot in its nest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (445, 'Garchomp', 'Dragon', 'Ground', 108, 130, 95, 80, 85, 102, 19.00, 950.00, 'The protuberances on its head serve as sensors. It can even detect distant prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (446, 'Munchlax', 'Normal', null, 135, 85, 40, 40, 85, 5, 6.00, 1050.00, 'Its robust stomach allows it to nonchalantly devour even rotted matter. It pays frequent visits to villages, seeking out food scraps intended for compost.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (447, 'Riolu', 'Fighting', null, 40, 70, 40, 35, 40, 60, 7.00, 202.00, 'It has the peculiar power of being able to see emotions, such as joy and rage, in the form of waves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (448, 'Lucario', 'Fighting', 'Steel', 70, 110, 70, 115, 70, 90, 12.00, 540.00, 'A well-trained one can use its aura to identify and take in the feelings of creatures over half a mile away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (449, 'Hippopotas', 'Ground', null, 68, 72, 78, 38, 42, 32, 8.00, 495.00, 'It shrouds itself in sand to ward off germs. It travels easily through the sands of the desert.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (450, 'Hippowdon', 'Ground', null, 108, 112, 118, 68, 72, 47, 20.00, 3000.00, 'It brandishes its gaping mouth in a display of fearsome strength. It raises vast quantities of sand while attacking.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (451, 'Skorupi', 'Poison', 'Bug', 40, 50, 90, 30, 55, 65, 8.00, 120.00, 'Its claws are not only razor-sharp but poisonous, making Skorupi a highly dangerous Pokémon. It seems to be weakened by cold temperatures, however.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (452, 'Drapion', 'Poison', 'Dark', 70, 90, 110, 60, 75, 95, 13.00, 615.00, 'Has a brutish, ferocious temperament. With immense strength and a sturdy shell off which swords will bounce, it rampages about and wreaks havoc.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (453, 'Croagunk', 'Poison', 'Fighting', 48, 61, 40, 61, 40, 50, 7.00, 230.00, 'It rarely fights fairly, but that is strictly to ensure survival. It is popular as a mascot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (454, 'Toxicroak', 'Poison', 'Fighting', 83, 106, 65, 86, 65, 85, 13.00, 444.00, 'It has a poison sac at its throat. When it croaks, the stored poison is churned for greater potency.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (455, 'Carnivine', 'Grass', null, 74, 100, 72, 90, 72, 46, 14.00, 270.00, 'Though this is a plant Pokémon, it has a gluttonous and unruly temperament. Carnivine attacks its prey with its cavernous maw wide open.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (456, 'Finneon', 'Water', null, 49, 49, 56, 49, 61, 66, 4.00, 70.00, 'It absorbs sunlight with the pink areas of its skin, which then shine. This appears to be a form of camouflage.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (457, 'Lumineon', 'Water', null, 69, 69, 76, 69, 86, 91, 12.00, 240.00, 'Lumineon swimming in the darkness of the deep sea look like stars shining in the night sky.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (458, 'Mantyke', 'Water', 'Flying', 45, 20, 50, 60, 120, 50, 10.00, 650.00, 'Though ball-like in shape, this Pokémon is a proficient swimmer. I have discovered that if a Mantyke spends much time with schools of Remoraid, it will eventually achieve evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (459, 'Snover', 'Grass', 'Ice', 60, 62, 50, 62, 60, 40, 10.00, 505.00, 'Seemingly curious about people, they gather around footsteps they find on snowy mountains.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (460, 'Abomasnow', 'Grass', 'Ice', 90, 92, 75, 92, 85, 60, 22.00, 1355.00, 'They appear when the snow flowers bloom. When the petals fall, they retreat to places unknown again.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (461, 'Weavile', 'Dark', 'Ice', 70, 120, 65, 45, 85, 125, 11.00, 340.00, 'They travel in groups of four or five, leaving signs for one another on trees and rocks. They bring down their prey with coordinated attacks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (462, 'Magnezone', 'Electric', 'Steel', 70, 70, 115, 130, 90, 60, 12.00, 1800.00, 'Exposure to a special magnetic field changed Magneton’s molecular structure, turning it into Magnezone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (463, 'Lickilicky', 'Normal', null, 110, 85, 95, 80, 95, 50, 17.00, 1400.00, 'Its tongue can extend and contract freely, and it is capable of reaching lengths over 10 times Lickilicky’s height. Beware of the saliva, as it contains corrosive elements.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (464, 'Rhyperior', 'Ground', 'Rock', 115, 140, 130, 55, 55, 40, 24.00, 2828.00, 'This Pokémon evolved through use of a curious item. Its rocklike hide is composed of a mysterious substance and can withstand a blow from a masterwork sword with nary a scratch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (465, 'Tangrowth', 'Grass', null, 100, 100, 125, 110, 50, 50, 20.00, 1286.00, 'Draped with long vines, it resembles a shrub in appearance. It swings bundles of vines as though they were arms, wrapping them around prey to ensnare them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (466, 'Electivire', 'Electric', null, 75, 123, 67, 95, 85, 95, 18.00, 1386.00, 'Its evolution was induced by an unusual item, and its electrical output rises along with its heart rate. From its tails, it can unleash an electric current measuring 20,000 volts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (467, 'Magmortar', 'Fire', null, 75, 95, 67, 125, 95, 83, 16.00, 680.00, 'Use of a strange item caused this Pokémon to evolve. Fireballs launched from the ends of its tubelike arms are hot enough to melt an iron pot in an instant.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (468, 'Togekiss', 'Fairy', 'Flying', 85, 50, 95, 120, 115, 80, 15.00, 380.00, 'Scant few have ever sighted this Pokémon. After studying what literature remains, I am certain Togekiss will reveal itself when peace reigns in the land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (469, 'Yanmega', 'Bug', 'Flying', 86, 76, 86, 116, 56, 95, 19.00, 515.00, 'Extremely violent. When hunting, it wastes none of its energy, aiming only for prey’s most vulnerable spots. Any who manage to tame this Pokémon must be of incredible bravery.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (470, 'Leafeon', 'Grass', null, 65, 110, 130, 60, 65, 95, 10.00, 255.00, 'The younger they are, the more they smell like fresh grass. With age, their fragrance takes on the odor of fallen leaves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (471, 'Glaceon', 'Ice', null, 65, 60, 110, 130, 95, 65, 8.00, 259.00, 'It lowers its body heat to freeze its fur. The hairs then become like needles it can fire.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (472, 'Gliscor', 'Ground', 'Flying', 75, 95, 125, 45, 75, 95, 20.00, 425.00, 'It glides soundlessly on pitch-black wings and sinks sharp fangs into the throat of its prey. It takes on a look of satisfaction once it has entirely drained its prey of blood.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (473, 'Mamoswine', 'Ice', 'Ground', 110, 130, 80, 70, 60, 80, 25.00, 2910.00, 'This species reached its zenith during the period known as the ice age. I suspect that Hisui’s frigid climate is in harmony with Mamoswine’s constitution, thus awakening hidden potential.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (474, 'Porygon-Z', 'Normal', null, 85, 80, 70, 135, 75, 90, 9.00, 340.00, 'A curious item induced this evolution. The Pokémon’s offensive capabilities have greatly increased, but the strangeness of its behavior has magnified in equal measure. This worries me.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (475, 'Gallade', 'Psychic', 'Fighting', 68, 125, 65, 65, 115, 80, 16.00, 520.00, 'Because it can sense what its foe is thinking, its attacks burst out first, fast, and fierce.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (476, 'Probopass', 'Rock', 'Steel', 60, 55, 145, 75, 150, 40, 14.00, 3400.00, 'It is able to emit powerful magnetism, allowing it control over the iron sand that forms its luscious mustache. Using this iron sand, Probopass forms hard stones with which it smites its prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (477, 'Dusknoir', 'Ghost', null, 45, 100, 135, 65, 135, 45, 22.00, 1066.00, 'Comes to those whose lives have come to an end and escorts their souls to the afterlife. Known to mistakenly take the souls of those who yet have life left in them, albeit rarely.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (478, 'Froslass', 'Ice', 'Ghost', 70, 80, 70, 80, 70, 110, 13.00, 266.00, 'It freezes prey by blowing its −58 degree Fahrenheit breath. It is said to then secretly display its prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (479, 'Rotom', 'Electric', 'Ghost', 50, 50, 77, 95, 77, 91, 3.00, 3.00, 'Research continues on this Pokémon, which could be the power source of a unique motor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (480, 'Uxie', 'Psychic', null, 75, 75, 130, 75, 130, 95, 3.00, 3.00, 'A Pokémon feared but also respected for stealing away the memories of evildoers. I have found records that suggest Uxie holds dominion over knowledge.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (481, 'Mesprit', 'Psychic', null, 80, 105, 105, 105, 105, 80, 3.00, 3.00, 'Known as the Being of Emotion. In legend, this Pokémon was feared, as any who showed disrespect would have their emotions thrown into disarray.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (482, 'Azelf', 'Psychic', null, 75, 125, 70, 125, 70, 115, 3.00, 3.00, 'The dreaded Being of Willpower. Legends tell of this Pokémon manipulating the will of its adversaries and turning them into puppets of its own.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (483, 'Dialga', 'Steel', 'Dragon', 100, 120, 120, 150, 100, 90, 54.00, 6830.00, 'This Pokémon is revered as a deity in Hisuian legend. The birth of Dialga was what caused the vast river of time to begin flowing in our world.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (484, 'Palkia', 'Water', 'Dragon', 90, 120, 100, 150, 120, 100, 42.00, 3360.00, 'This Pokémon is feared as a deity in Hisuian legend. The birth of Palkia was what caused the walls of our world to disappear, creating a sky that spans for infinity.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (485, 'Heatran', 'Fire', 'Steel', 91, 90, 106, 130, 106, 77, 17.00, 4300.00, 'Stories tell of this Pokémon being birthed from the boiling magma within Mount Coronet. Its molten-steel body holds many mysteries.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (486, 'Regigigas', 'Normal', null, 110, 160, 110, 80, 110, 100, 37.00, 4200.00, 'According to legend, Regigigas pulled landmasses together and bound them with rope to create the continent of Hisui. Though I have my doubts, the story could well contain a shred of truth.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (487, 'Giratina', 'Ghost', 'Dragon', 150, 100, 120, 100, 120, 90, 45.00, 7500.00, 'There is one Hisuian verse that tells of a powerful light creating a deep shadow. I imagine that this deep shadow is Giratina.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (488, 'Cresselia', 'Psychic', null, 120, 70, 120, 75, 130, 85, 15.00, 856.00, 'Cresselia is reminiscent of the crescent moon. It leaves a brilliant line of light in its wake as it flies across the night sky. I daresay it resembles the heavenly maiden who created the Milky Way.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (489, 'Phione', 'Water', null, 80, 80, 80, 80, 80, 80, 4.00, 31.00, 'Can be seen floating offshore during seasons when the seas are warm. Its azure body blends in with the ocean waters—logic suggests this is a defense mechanism against natural predators.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (490, 'Manaphy', 'Water', null, 100, 100, 100, 100, 100, 100, 3.00, 14.00, 'Rumored to migrate across the oceans and visit Hisui’s coastal waters only rarely. Although Manaphy resembles Phione, it is also quite different. The relation between the two is unclear.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (491, 'Darkrai', 'Dark', null, 70, 90, 90, 135, 90, 125, 15.00, 505.00, 'On a moonless night, a strange incident occurred in which every one of a village’s inhabitants suffered nightmares. The villagers attested that Darkrai appeared before them in these nightmares.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (492, 'Shaymin', 'Grass', null, 100, 100, 100, 100, 100, 100, 2.00, 21.00, 'When the turning of seasons brings the cruel winter to its end and the joyous people give thanks to the heavens, Shaymin appears and covers the withered land with flowers.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (493, 'Arceus', 'Normal', null, 120, 120, 120, 120, 120, 120, 32.00, 3200.00, 'It is the heavenly fount from which pours the light that shines across Hisui. Its luminance guides and protects all Pokémon. Hisuian mythology states that Arceus is the creator of all things.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (494, 'Victini', 'Psychic', 'Fire', 100, 100, 100, 100, 100, 100, 4.00, 40.00, 'When it shares the infinite energy it creates, that being’s entire body will be overflowing with power.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (495, 'Snivy', 'Grass', null, 45, 45, 55, 45, 55, 63, 6.00, 81.00, 'They photosynthesize by bathing their tails in sunlight. When they are not feeling well, their tails droop.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (496, 'Servine', 'Grass', null, 60, 60, 75, 60, 75, 83, 8.00, 160.00, 'When it gets dirty, its leaves can’t be used in photosynthesis, so it always keeps itself clean.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (497, 'Serperior', 'Grass', null, 75, 75, 95, 75, 95, 113, 33.00, 630.00, 'It can stop its opponents’ movements with just a glare. It takes in solar energy and boosts it internally.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (498, 'Tepig', 'Fire', null, 65, 63, 45, 45, 45, 45, 5.00, 99.00, 'It loves to eat roasted berries, but sometimes it gets too excited and burns them to a crisp.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (499, 'Pignite', 'Fire', 'Fighting', 90, 93, 55, 70, 55, 55, 10.00, 555.00, 'When its internal fire flares up, its movements grow sharper and faster. When in trouble, it emits smoke.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (500, 'Emboar', 'Fire', 'Fighting', 110, 123, 65, 100, 65, 65, 16.00, 1500.00, 'It has mastered fast and powerful fighting moves. It grows a beard of fire.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (501, 'Oshawott', 'Water', null, 55, 55, 45, 63, 45, 45, 5.00, 59.00, 'This Pokémon from the Unova region uses the shell on its belly as a weapon to cut down its foes. Thus, I’ve conferred upon this shell the name “scalchop.”', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (502, 'Dewott', 'Water', null, 75, 75, 60, 83, 60, 60, 8.00, 245.00, 'Its exquisite double-scalchop technique is likely the result of daily training, and it can send even masters of the blade fleeing in defeat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (503, 'Samurott', 'Water', null, 95, 100, 85, 108, 70, 70, 15.00, 946.00, 'One swing of the sword incorporated in its armor can fell an opponent. A simple glare from one of them quiets everybody.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (504, 'Patrat', 'Normal', null, 45, 55, 39, 35, 39, 42, 5.00, 116.00, 'Extremely cautious, one of them will always be on the lookout, but it won’t notice a foe coming from behind.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (505, 'Watchog', 'Normal', null, 60, 85, 69, 60, 69, 77, 11.00, 270.00, 'When they see an enemy, their tails stand high, and they spit the seeds of berries stored in their cheek pouches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (506, 'Lillipup', 'Normal', null, 45, 60, 45, 25, 45, 55, 4.00, 41.00, 'This Pokémon is far brighter than the average child, and Lillipup won’t forget the love it receives or any abuse it suffers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (507, 'Herdier', 'Normal', null, 65, 80, 65, 35, 65, 60, 9.00, 147.00, 'The black fur that covers this Pokémon’s body is dense and springy. Even sharp fangs bounce right off.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (508, 'Stoutland', 'Normal', null, 85, 110, 90, 45, 90, 80, 12.00, 610.00, 'Stoutland is immensely proud of its impressive moustache. It’s said that moustache length is what determines social standing among this species.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (509, 'Purrloin', 'Dark', null, 41, 50, 37, 50, 37, 66, 4.00, 101.00, 'Opponents that get drawn in by its adorable behavior come away with stinging scratches from its claws and stinging pride from its laughter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (510, 'Liepard', 'Dark', null, 64, 88, 50, 88, 50, 106, 11.00, 375.00, 'This stealthy Pokémon sneaks up behind prey without making any sound at all. It competes with Thievul for territory.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (511, 'Pansage', 'Grass', null, 50, 53, 48, 53, 48, 64, 6.00, 105.00, 'It’s good at finding berries and gathers them from all over. It’s kind enough to share them with friends.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (512, 'Simisage', 'Grass', null, 75, 98, 63, 98, 63, 101, 11.00, 305.00, 'Ill tempered, it fights by swinging its barbed tail around wildly. The leaf growing on its head is very bitter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (513, 'Pansear', 'Fire', null, 50, 53, 48, 53, 48, 64, 6.00, 110.00, 'This Pokémon lives in caves in volcanoes. The fire within the tuft on its head can reach 600 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (514, 'Simisear', 'Fire', null, 75, 98, 63, 98, 63, 101, 10.00, 280.00, 'When it gets excited, embers rise from its head and tail and it gets hot. For some reason, it loves sweets.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (515, 'Panpour', 'Water', null, 50, 53, 48, 53, 48, 64, 6.00, 135.00, 'The water stored inside the tuft on its head is full of nutrients. Plants that receive its water grow large.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (516, 'Simipour', 'Water', null, 75, 98, 63, 98, 63, 101, 10.00, 290.00, 'It prefers places with clean water. When its tuft runs low, it replenishes it by siphoning up water with its tail.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (517, 'Munna', 'Psychic', null, 76, 25, 45, 67, 55, 24, 6.00, 233.00, 'It eats dreams and releases mist. The mist is pink when it’s eating a good dream, and black when it’s eating a nightmare.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (518, 'Musharna', 'Psychic', null, 116, 55, 85, 107, 95, 29, 11.00, 605.00, 'It drowses and dreams all the time. It’s best to leave it be if it’s just woken up, as it’s a terrible grump when freshly roused from sleep.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (519, 'Pidove', 'Normal', 'Flying', 50, 55, 50, 36, 30, 43, 3.00, 21.00, 'It’s forgetful and not very bright, but many Trainers love it anyway for its friendliness and sincerity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (520, 'Tranquill', 'Normal', 'Flying', 62, 77, 62, 50, 42, 65, 6.00, 150.00, 'These bright Pokémon have acute memories. Apparently delivery workers often choose them as their partners.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (521, 'Unfezant', 'Normal', 'Flying', 80, 115, 80, 65, 55, 93, 12.00, 290.00, 'Males have plumage on their heads. They will never let themselves feel close to anyone other than their Trainers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (522, 'Blitzle', 'Electric', null, 45, 60, 32, 50, 32, 76, 8.00, 298.00, 'Its mane shines when it discharges electricity. They use the frequency and rhythm of these flashes to communicate.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (523, 'Zebstrika', 'Electric', null, 75, 100, 63, 80, 63, 116, 16.00, 795.00, 'They have lightning-like movements. When Zebstrika run at full speed, the sound of thunder reverberates.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (524, 'Roggenrola', 'Rock', null, 55, 75, 85, 25, 25, 15, 4.00, 180.00, 'When it detects a noise, it starts to move. The energy core inside it makes this Pokémon slightly warm to the touch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (525, 'Boldore', 'Rock', null, 70, 105, 105, 50, 40, 20, 9.00, 1020.00, 'It relies on sound in order to monitor what’s in its vicinity. When angered, it will attack without ever changing the direction it’s facing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (526, 'Gigalith', 'Rock', null, 85, 135, 130, 60, 80, 25, 17.00, 2600.00, 'Although its energy blasts can blow away a dump truck, they have a limitation— they can only be fired when the sun is out.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (527, 'Woobat', 'Psychic', 'Flying', 65, 45, 43, 55, 43, 72, 4.00, 21.00, 'It emits ultrasonic waves as it flutters about, searching for its prey—bug Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (528, 'Swoobat', 'Psychic', 'Flying', 67, 57, 55, 77, 55, 114, 9.00, 105.00, 'The auspicious shape of this Pokémon’s nose apparently led some regions to consider Swoobat a symbol of good luck.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (529, 'Drilbur', 'Ground', null, 60, 85, 40, 30, 45, 68, 3.00, 85.00, 'It’s a digger, using its claws to burrow through the ground. It causes damage to vegetable crops, so many farmers have little love for it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (530, 'Excadrill', 'Ground', 'Steel', 110, 135, 60, 50, 65, 88, 7.00, 404.00, 'Known as the Drill King, this Pokémon can tunnel through the terrain at speeds of over 90 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (531, 'Audino', 'Normal', null, 103, 60, 86, 60, 86, 50, 11.00, 310.00, 'This Pokémon has a kind heart. By touching with its feelers, Audino can gauge other creatures’ feelings and physical conditions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (532, 'Timburr', 'Fighting', null, 75, 80, 55, 25, 35, 35, 6.00, 125.00, 'Timburr that have started carrying logs that are about three times their size are nearly ready to evolve.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (533, 'Gurdurr', 'Fighting', null, 85, 105, 85, 40, 50, 40, 12.00, 400.00, 'Gurdurr excels at demolition—construction is not its forte. In any case, there’s skill in the way this Pokémon wields its metal beam.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (534, 'Conkeldurr', 'Fighting', null, 105, 140, 95, 55, 65, 45, 14.00, 870.00, 'When going all out, this Pokémon throws aside its concrete pillars and leaps at opponents to pummel them with its fists.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (535, 'Tympole', 'Water', null, 50, 50, 40, 50, 40, 64, 5.00, 45.00, 'It uses sound waves to communicate with others of its kind. People and other Pokémon species can’t hear its cries of warning.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (536, 'Palpitoad', 'Water', 'Ground', 75, 65, 55, 65, 55, 69, 8.00, 170.00, 'On occasion, their cries are sublimely pleasing to the ear. Palpitoad with larger lumps on their bodies can sing with a wider range of sounds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (537, 'Seismitoad', 'Water', 'Ground', 105, 95, 75, 85, 75, 74, 15.00, 620.00, 'This Pokémon is popular among the elderly, who say the vibrations of its lumps are great for massages.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (538, 'Throh', 'Fighting', null, 120, 100, 85, 30, 85, 45, 13.00, 555.00, 'They train in groups of five. Any member that can’t keep up will discard its belt and leave the group.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (539, 'Sawk', 'Fighting', null, 75, 125, 75, 30, 75, 85, 14.00, 510.00, 'The karate chops of a Sawk that’s trained itself to the limit can cleave the ocean itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (540, 'Sewaddle', 'Bug', 'Grass', 45, 53, 70, 40, 60, 42, 3.00, 25.00, 'Since this Pokémon makes its own clothes out of leaves, it is a popular mascot for fashion designers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (541, 'Swadloon', 'Bug', 'Grass', 55, 63, 90, 50, 80, 42, 5.00, 73.00, 'It protects itself from the cold by wrapping up in leaves. It stays on the move, eating leaves in forests.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (542, 'Leavanny', 'Bug', 'Grass', 75, 103, 80, 70, 80, 92, 12.00, 205.00, 'It keeps its eggs warm with heat from fermenting leaves. It also uses leaves to make warm wrappings for Sewaddle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (543, 'Venipede', 'Bug', 'Poison', 30, 45, 59, 30, 39, 57, 4.00, 53.00, 'Its fangs are highly venomous. If this Pokémon finds prey it thinks it can eat, it leaps for them without any thought of how things might turn out.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (544, 'Whirlipede', 'Bug', 'Poison', 40, 55, 99, 40, 79, 47, 12.00, 585.00, 'Whirlipede protects itself with a sturdy shell and poisonous spikes while it stores up the energy it’ll need for evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (545, 'Scolipede', 'Bug', 'Poison', 60, 100, 89, 55, 69, 112, 25.00, 2005.00, 'Scolipede engage in fierce territorial battles with Centiskorch. At the end of one of these battles, the victor makes a meal of the loser.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (546, 'Cottonee', 'Grass', 'Fairy', 40, 27, 60, 37, 50, 66, 3.00, 6.00, 'Weaving together the cotton of both Cottonee and Eldegoss produces exquisite cloth that’s highly prized by many luxury brands.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (547, 'Whimsicott', 'Grass', 'Fairy', 60, 67, 85, 77, 75, 116, 7.00, 66.00, 'As long as this Pokémon bathes in sunlight, its cotton keeps growing. If too much cotton fluff builds up, Whimsicott tears it off and scatters it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (548, 'Petilil', 'Grass', null, 45, 35, 50, 70, 50, 30, 5.00, 66.00, 'If the leaves on its head are pruned with regularity, this Pokémon can be grown into a fine plump shape.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (549, 'Lilligant', 'Grass', null, 70, 60, 75, 110, 75, 90, 11.00, 163.00, 'No matter how much time and money is spent raising it, its flowers are the most beautiful when they bloom in the wild.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (550, 'Basculin', 'Water', null, 70, 92, 65, 80, 55, 98, 10.00, 180.00, 'Red and blue Basculin usually do not get along, but sometimes members of one school mingle with the other’s school.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (551, 'Sandile', 'Ground', 'Dark', 50, 72, 35, 35, 35, 65, 7.00, 152.00, 'They live hidden under hot desert sands in order to keep their body temperature from dropping.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (552, 'Krokorok', 'Ground', 'Dark', 60, 82, 45, 45, 45, 74, 10.00, 334.00, 'Thanks to the special membrane covering its eyes, it can see its surroundings clearly, even in the middle of the night.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (553, 'Krookodile', 'Ground', 'Dark', 95, 117, 80, 65, 70, 92, 15.00, 963.00, 'Its unique faculty of sight can detect small prey more than 30 miles away, even in the midst of a sandstorm.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (554, 'Darumaka', 'Fire', null, 70, 90, 45, 15, 45, 50, 6.00, 375.00, 'This popular symbol of good fortune will never fall over in its sleep, no matter how it’s pushed or pulled.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (555, 'Darmanitan', 'Fire', null, 105, 140, 55, 30, 55, 95, 13.00, 929.00, 'Its internal fire burns at 2,500 degrees Fahrenheit, making enough power that it can destroy a dump truck with one punch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (556, 'Maractus', 'Grass', null, 75, 86, 67, 106, 67, 60, 10.00, 280.00, 'Once each year, this Pokémon scatters its seeds. They’re jam-packed with nutrients, making them a precious food source out in the desert.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (557, 'Dwebble', 'Bug', 'Rock', 50, 65, 85, 35, 35, 55, 3.00, 145.00, 'It first tries to find a rock to live in, but if there are no suitable rocks to be found, Dwebble may move in to the ports of a Hippowdon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (558, 'Crustle', 'Bug', 'Rock', 70, 105, 125, 65, 75, 45, 14.00, 2000.00, 'Its thick claws are its greatest weapons. They’re mighty enough to crack Rhyperior’s carapace.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (559, 'Scraggy', 'Dark', 'Fighting', 50, 75, 70, 35, 70, 48, 6.00, 118.00, 'It protects itself with its durable skin. It’s thought that this Pokémon will evolve once its skin has completely stretched out.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (560, 'Scrafty', 'Dark', 'Fighting', 65, 90, 115, 45, 115, 58, 11.00, 300.00, 'While mostly known for having the temperament of an aggressive ruffian, this Pokémon takes very good care of its family, friends, and territory.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (561, 'Sigilyph', 'Psychic', 'Flying', 72, 58, 80, 103, 80, 97, 14.00, 140.00, 'A discovery was made in the desert where Sigilyph fly. The ruins of what may have been an ancient city were found beneath the sands.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (562, 'Yamask', 'Ghost', null, 38, 30, 85, 55, 65, 30, 5.00, 15.00, 'The spirit of a person from a bygone age became this Pokémon. It rambles through ruins, searching for someone who knows its face.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (563, 'Cofagrigus', 'Ghost', null, 58, 50, 145, 95, 105, 30, 17.00, 765.00, 'There are many depictions of Cofagrigus decorating ancient tombs. They’re symbols of the wealth that kings of bygone eras had.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (564, 'Tirtouga', 'Water', 'Rock', 54, 78, 103, 53, 45, 22, 7.00, 165.00, 'Tirtouga is considered to be the ancestor of many turtle Pokémon. It was restored to life from a fossil.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (565, 'Carracosta', 'Water', 'Rock', 74, 108, 133, 83, 65, 32, 12.00, 810.00, 'This Pokémon emerges from the water in search of prey despite the fact that it moves more slowly on land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (566, 'Archen', 'Rock', 'Flying', 55, 112, 45, 74, 45, 70, 5.00, 95.00, 'Archen is said to be the ancestor of bird Pokémon. It lived in treetops, eating berries and bug Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (567, 'Archeops', 'Rock', 'Flying', 75, 140, 65, 112, 65, 110, 14.00, 320.00, 'Though capable of flight, Archeops was apparently better at hunting on the ground.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (568, 'Trubbish', 'Poison', null, 50, 50, 62, 40, 62, 65, 6.00, 310.00, 'This Pokémon was born from a bag stuffed with trash. Galarian Weezing relish the fumes belched by Trubbish.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (569, 'Garbodor', 'Poison', null, 80, 95, 82, 60, 82, 75, 19.00, 1073.00, 'The toxic liquid it launches from its right arm is so virulent that it can kill a weakened creature instantly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (570, 'Zorua', 'Dark', null, 40, 65, 40, 80, 40, 65, 7.00, 125.00, 'To protect themselves from danger, they hide their true identities by transforming into people and Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (571, 'Zoroark', 'Dark', null, 60, 105, 60, 120, 60, 105, 16.00, 811.00, 'Each has the ability to fool a large group of people simultaneously. They protect their lair with illusory scenery.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (572, 'Minccino', 'Normal', null, 55, 50, 40, 40, 40, 75, 4.00, 58.00, 'They pet each other with their tails as a form of greeting. Of the two, the one whose tail is fluffier is a bit more boastful.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (573, 'Cinccino', 'Normal', null, 75, 95, 60, 65, 60, 115, 5.00, 75.00, 'A special oil that seeps through their fur helps them avoid attacks. The oil fetches a high price at market.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (574, 'Gothita', 'Psychic', null, 45, 30, 50, 55, 65, 45, 4.00, 58.00, 'Beware of touching the ribbon-shaped feelers that control its psychic power. Gothita will begin bawling if you do.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (575, 'Gothorita', 'Psychic', null, 60, 45, 70, 75, 85, 55, 7.00, 180.00, 'Using its psychic power, it arranges pebbles to form the shapes of constellations. Some people believe this Pokémon came from outer space.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (576, 'Gothitelle', 'Psychic', null, 70, 55, 95, 95, 110, 65, 15.00, 440.00, 'It gazes at the stars to predict the future. It acts somewhat detached because it has seen the end of all existence.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (577, 'Solosis', 'Psychic', null, 45, 30, 40, 105, 50, 20, 3.00, 10.00, 'Many say that the special liquid covering this Pokémon’s body would allow it to survive in the vacuum of space.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (578, 'Duosion', 'Psychic', null, 65, 40, 50, 125, 60, 30, 6.00, 80.00, 'Its brain has split into two, and the two halves rarely think alike. Its actions are utterly unpredictable.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (579, 'Reuniclus', 'Psychic', null, 110, 65, 75, 125, 85, 30, 10.00, 201.00, 'It’s said that drinking the liquid surrounding Reuniclus grants wisdom. Problem is, the liquid is highly toxic to anything besides Reuniclus itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (580, 'Ducklett', 'Water', 'Flying', 62, 44, 50, 44, 50, 55, 5.00, 55.00, 'They are better at swimming than flying, and they happily eat their favorite food, peat moss, as they dive underwater.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (581, 'Swanna', 'Water', 'Flying', 75, 87, 63, 87, 63, 98, 13.00, 242.00, 'Swanna start to dance at dusk. The one dancing in the middle is the leader of the flock.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (582, 'Vanillite', 'Ice', null, 36, 50, 50, 65, 60, 44, 4.00, 57.00, 'Supposedly, this Pokémon was born from an icicle. It spews out freezing air at −58 degrees Fahrenheit to make itself more comfortable.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (583, 'Vanillish', 'Ice', null, 51, 65, 65, 80, 75, 59, 11.00, 410.00, 'It blasts enemies with cold air reaching −148 degrees Fahrenheit, freezing them solid. But it spares their lives afterward—it’s a kind Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (584, 'Vanilluxe', 'Ice', null, 71, 95, 85, 110, 95, 79, 13.00, 575.00, 'People believe this Pokémon formed when two Vanillish stuck together. Its body temperature is roughly 21 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (585, 'Deerling', 'Normal', 'Grass', 60, 60, 50, 40, 50, 75, 6.00, 195.00, 'The turning of the seasons changes the color and scent of this Pokémon’s fur. People use it to mark the seasons.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (586, 'Sawsbuck', 'Normal', 'Grass', 80, 100, 70, 60, 70, 95, 19.00, 925.00, 'They migrate according to the seasons, so some people call Sawsbuck the harbingers of spring.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (587, 'Emolga', 'Electric', 'Flying', 55, 75, 60, 75, 60, 103, 4.00, 50.00, 'This Pokémon absolutely loves sweet berries. Sometimes it stuffs its cheeks full of so much food that it can’t fly properly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (588, 'Karrablast', 'Bug', null, 50, 75, 45, 40, 45, 60, 5.00, 59.00, 'It spits a liquid from its mouth to melt through Shelmet’s shell. Karrablast doesn’t eat the shell— it eats only the contents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (589, 'Escavalier', 'Bug', 'Steel', 70, 135, 105, 60, 105, 20, 10.00, 330.00, 'It charges its enemies, lances at the ready. An image of one of its duels is captured in a famous painting of Escavalier clashing with Sirfetch’d.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (590, 'Foongus', 'Grass', 'Poison', 69, 55, 45, 55, 55, 15, 2.00, 10.00, 'This Pokémon prefers damp places. It spurts out poison spores to repel approaching enemies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (591, 'Amoonguss', 'Grass', 'Poison', 114, 85, 70, 85, 80, 30, 6.00, 105.00, 'Amoonguss mimics Poké Balls. It is not yet clear whether this mimicry is effective against other Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (592, 'Frillish', 'Water', 'Ghost', 55, 40, 50, 65, 85, 40, 12.00, 330.00, 'Using the invisible poison spikes on its veillike arms and legs, it paralyzes its enemies and causes them to drown.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (593, 'Jellicent', 'Water', 'Ghost', 100, 60, 70, 85, 105, 60, 22.00, 1350.00, 'Fishermen are terrified of Jellicent. It’s rumored to drag them into the sea and steal their lives away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (594, 'Alomomola', 'Water', null, 165, 75, 80, 40, 45, 65, 12.00, 316.00, 'They float upon the open sea. Many water Pokémon gather in the area around Alomomola.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (595, 'Joltik', 'Bug', 'Electric', 50, 47, 50, 57, 50, 65, 1.00, 6.00, 'Joltik latch on to other Pokémon and suck out static electricity. They’re often found sticking to Yamper’s hindquarters.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (596, 'Galvantula', 'Bug', 'Electric', 70, 77, 60, 97, 60, 108, 8.00, 143.00, 'It lays traps of electrified threads near the nests of bird Pokémon, aiming to snare chicks that are not yet good at flying.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (597, 'Ferroseed', 'Grass', 'Steel', 44, 50, 91, 24, 86, 10, 6.00, 188.00, 'Mossy caves are their preferred dwellings. Enzymes contained in mosses help Ferroseed’s spikes grow big and strong.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (598, 'Ferrothorn', 'Grass', 'Steel', 74, 94, 131, 54, 116, 20, 10.00, 1100.00, 'Its spikes are harder than steel. This Pokémon crawls across rock walls by stabbing the spikes on its feelers into the stone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (599, 'Klink', 'Steel', null, 40, 55, 70, 45, 60, 30, 3.00, 210.00, 'It’s suspected that Klink were the inspiration behind ancient people’s invention of the first gears.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (600, 'Klang', 'Steel', null, 60, 80, 95, 70, 85, 50, 6.00, 510.00, 'Many companies in the Galar region choose Klang as their logo. This Pokémon is considered the symbol of industrial technology.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (601, 'Klinklang', 'Steel', null, 60, 100, 115, 70, 85, 90, 6.00, 810.00, 'The three gears that compose this Pokémon spin at high speed. Its new spiked gear isn’t a living creature.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (602, 'Tynamo', 'Electric', null, 35, 55, 40, 45, 40, 60, 2.00, 3.00, 'These Pokémon move in schools. They have an electricity-generating organ, so they discharge electricity if in danger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (603, 'Eelektrik', 'Electric', null, 65, 85, 70, 75, 70, 40, 12.00, 220.00, 'These Pokémon have a big appetite. When they spot their prey, they attack it and paralyze it with electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (604, 'Eelektross', 'Electric', null, 85, 115, 80, 105, 80, 50, 21.00, 805.00, 'It latches on to prey with its sucker mouth, sinking in its fangs and shocking the prey with powerful electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (605, 'Elgyem', 'Psychic', null, 55, 55, 55, 85, 55, 30, 5.00, 90.00, 'This Pokémon was discovered about 50 years ago. Its highly developed brain enables it to exert its psychic powers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (606, 'Beheeyem', 'Psychic', null, 75, 75, 75, 125, 95, 40, 10.00, 345.00, 'Sometimes found drifting above wheat fields, this Pokémon can control the memories of its opponents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (607, 'Litwick', 'Ghost', 'Fire', 50, 30, 55, 65, 55, 20, 3.00, 31.00, 'The younger the life this Pokémon absorbs, the brighter and eerier the flame on its head burns.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (608, 'Lampent', 'Ghost', 'Fire', 60, 40, 60, 95, 60, 55, 6.00, 130.00, 'It lurks in cities, pretending to be a lamp. Once it finds someone whose death is near, it will trail quietly after them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (609, 'Chandelure', 'Ghost', 'Fire', 60, 55, 90, 145, 90, 80, 10.00, 343.00, 'In homes illuminated by Chandelure instead of lights, funerals were a constant occurrence— or so it’s said.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (610, 'Axew', 'Dragon', null, 46, 87, 60, 30, 40, 57, 6.00, 180.00, 'If you see peculiar teeth marks on boulders or trees, it means an Axew is likely living nearby.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (611, 'Fraxure', 'Dragon', null, 66, 117, 70, 40, 50, 67, 10.00, 360.00, 'Fraxure uses its thick tusks to neatly cut prey into two portions—one to eat now and one to save for later.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (612, 'Haxorus', 'Dragon', null, 76, 147, 90, 60, 70, 97, 18.00, 1055.00, 'It overwhelms enemies with its prized tusks, which are sharp enough to cut through a metal transmission tower in one strike.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (613, 'Cubchoo', 'Ice', null, 55, 70, 40, 60, 40, 40, 5.00, 85.00, 'When Cubchoo starts sneezing, watch out! If it spatters you with its frosty snot, you’ll get frostbite.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (614, 'Beartic', 'Ice', null, 95, 130, 80, 70, 80, 50, 26.00, 2600.00, 'Feared as the Snow-White Demon in northern lands, Beartic uses its frosty claws and fangs to attack prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (615, 'Cryogonal', 'Ice', null, 80, 50, 50, 95, 135, 105, 11.00, 1480.00, 'Cryogonal uses its chains of ice to constrict its opponents and then flash-freezes them where they stand.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (616, 'Shelmet', 'Bug', null, 50, 40, 85, 40, 65, 25, 4.00, 77.00, 'It has a strange physiology that responds to electricity. When together with Karrablast, Shelmet evolves for some reason.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (617, 'Accelgor', 'Bug', null, 80, 70, 40, 100, 60, 145, 8.00, 253.00, 'Discarding its shell made it nimble. To keep itself from dehydrating, it wraps its body in bands of membrane.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (618, 'Stunfisk', 'Ground', 'Electric', 109, 66, 84, 81, 99, 32, 7.00, 110.00, 'For some reason, this Pokémon smiles slightly when it emits a strong electric current from the yellow markings on its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (619, 'Mienfoo', 'Fighting', null, 45, 85, 50, 55, 50, 65, 9.00, 200.00, 'Though small, Mienfoo’s temperament is fierce. Any creature that approaches Mienfoo carelessly will be greeted with a flurry of graceful attacks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (620, 'Mienshao', 'Fighting', null, 65, 125, 60, 95, 60, 105, 14.00, 355.00, 'Delivered at blinding speeds, kicks from this Pokémon can shatter massive boulders into tiny pieces.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (621, 'Druddigon', 'Dragon', null, 77, 120, 90, 60, 90, 48, 16.00, 1390.00, 'Druddigon are vicious and cunning. They take up residence in nests dug out by other Pokémon, treating the stolen nests as their own lairs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (622, 'Golett', 'Ground', 'Ghost', 59, 74, 50, 35, 50, 35, 10.00, 920.00, 'This Pokémon was created from clay. It received orders from its master many thousands of years ago, and it still follows those orders to this day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (623, 'Golurk', 'Ground', 'Ghost', 89, 124, 80, 55, 80, 55, 28.00, 3300.00, 'There’s a theory that inside Golurk is a perpetual motion machine that produces limitless energy, but this belief hasn’t been proven.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (624, 'Pawniard', 'Dark', 'Steel', 45, 85, 70, 40, 40, 60, 5.00, 102.00, 'Any chips in its blades would prove fatal for it. After each battle, it diligently maintains its blades using its favorite sharpening stone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (625, 'Bisharp', 'Dark', 'Steel', 65, 125, 100, 60, 70, 70, 16.00, 700.00, 'Bisharp mercilessly cuts its opponents to pieces with the sharp blades covering its body. It will do anything to win.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (626, 'Bouffalant', 'Normal', null, 95, 110, 95, 40, 95, 55, 16.00, 946.00, 'These Pokémon live in herds of about 20 individuals. Bouffalant that betray the herd will lose the hair on their heads for some reason.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (627, 'Rufflet', 'Normal', 'Flying', 70, 83, 50, 37, 50, 60, 5.00, 105.00, 'With its sharp claws, this Pokémon pierces its prey, and then it pecks at them. Although it also consumes berries, it’s a carnivore at heart.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (628, 'Braviary', 'Normal', 'Flying', 100, 123, 75, 57, 75, 80, 15.00, 410.00, 'For the sake of its friends, this brave warrior of the sky will not stop battling, even if injured.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (629, 'Vullaby', 'Dark', 'Flying', 70, 55, 75, 45, 65, 60, 5.00, 90.00, 'Vullaby grow quickly. Bones that have gotten too small for older Vullaby to wear often get passed down to younger ones in the nest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (630, 'Mandibuzz', 'Dark', 'Flying', 110, 65, 105, 55, 95, 80, 12.00, 395.00, 'They adorn themselves with bones. There seem to be fashion trends among them, as different bones come into and fall out of popularity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (631, 'Heatmor', 'Fire', null, 85, 97, 66, 105, 66, 65, 14.00, 580.00, 'A flame serves as its tongue, melting through the hard shell of Durant so that Heatmor can devour their insides.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (632, 'Durant', 'Bug', 'Steel', 58, 109, 112, 48, 48, 109, 3.00, 330.00, 'With their large mandibles, these Pokémon can crunch their way through rock. They work together to protect their eggs from Sandaconda.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (633, 'Deino', 'Dark', 'Dragon', 52, 65, 50, 45, 50, 38, 8.00, 173.00, 'It nests deep inside a cave. Food there is scarce, so Deino will sink its teeth into anything that moves and attempt to eat it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (634, 'Zweilous', 'Dark', 'Dragon', 72, 85, 70, 65, 70, 58, 14.00, 500.00, 'The two heads have different likes and dislikes. Because the heads fight with each other, Zweilous gets stronger without needing to rely on others.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (635, 'Hydreigon', 'Dark', 'Dragon', 92, 105, 90, 125, 90, 98, 18.00, 1600.00, 'It’s said that Hydreigon grew ferocious because people in times long past loathed it, considering it to be evil incarnate and attacking it relentlessly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (636, 'Larvesta', 'Bug', 'Fire', 55, 85, 55, 50, 55, 60, 11.00, 288.00, 'In ancient times, Larvesta was worshiped as the emissary of the sun. However, it was also viewed as a burden since it often caused forest fires.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (637, 'Volcarona', 'Bug', 'Fire', 85, 60, 65, 135, 105, 100, 16.00, 460.00, 'This Pokémon scatters burning scales. Most of the danger of these scales is not in their heat—it’s in the way they rob the surrounding air of oxygen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (638, 'Cobalion', 'Steel', 'Fighting', 91, 90, 129, 90, 72, 108, 21.00, 2500.00, 'From the moment it’s born, this Pokémon radiates the air of a leader. Its presence will calm even vicious foes.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (639, 'Terrakion', 'Rock', 'Fighting', 91, 129, 90, 72, 90, 108, 19.00, 2600.00, 'In Unovan legend, Terrakion battled against humans in an effort to protect other Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (640, 'Virizion', 'Grass', 'Fighting', 91, 90, 72, 90, 129, 108, 20.00, 2000.00, 'It darts around opponents with a flurry of quick movements, slicing them up with its horns.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (641, 'Tornadus', 'Flying', null, 79, 115, 70, 125, 80, 111, 15.00, 630.00, 'This storm-stirring Pokémon is said to cause the seasons to turn by whipping up the air. I suspect its humanlike form to be a false one.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (642, 'Thundurus', 'Electric', 'Flying', 79, 115, 70, 125, 80, 111, 15.00, 610.00, 'They say this wielder of electricity has waged war with its nemesis, Tornadus, since time immemorial. The lightning bolts it hurls pierce the very earth and enrich the soil.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (643, 'Reshiram', 'Dragon', 'Fire', 100, 120, 100, 150, 120, 90, 32.00, 3300.00, 'According to myth, if people ignore truth and let themselves become consumed by greed, Reshiram will arrive to burn their kingdoms down.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (644, 'Zekrom', 'Dragon', 'Electric', 100, 150, 120, 120, 100, 90, 29.00, 3450.00, 'Mythology tells us that if people lose the righteousness in their hearts, their kingdoms will be razed by Zekrom’s lightning.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (645, 'Landorus', 'Ground', 'Flying', 89, 125, 90, 115, 80, 101, 15.00, 680.00, 'When the incarnations of wind and of lightning clash, Landorus arrives to quell the conflict. After the tempests and thunderbolts abate, the land is sure to be blessed with bountiful harvests.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (646, 'Kyurem', 'Dragon', 'Ice', 125, 130, 90, 130, 90, 95, 30.00, 3250.00, 'It appears that this Pokémon uses its powers over ice to freeze its own body in order to stabilize its cellular structure.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (647, 'Keldeo', 'Water', 'Fighting', 91, 72, 90, 129, 90, 108, 14.00, 485.00, 'When it is resolute, its body fills with power and it becomes swifter. Its jumps are then too fast to follow.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (648, 'Meloetta', 'Normal', 'Psychic', 100, 77, 77, 128, 128, 90, 6.00, 65.00, 'Its melodies are sung with a special vocalization method that can control the feelings of those who hear it.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (649, 'Genesect', 'Bug', 'Steel', 71, 120, 95, 120, 95, 99, 15.00, 825.00, 'This Pokémon existed 300 million years ago. Team Plasma altered it and attached a cannon to its back.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (650, 'Chespin', 'Grass', null, 56, 61, 65, 48, 45, 38, 4.00, 90.00, 'Such a thick shell of wood covers its head and back that even a direct hit from a truck wouldn’t faze it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (651, 'Quilladin', 'Grass', null, 61, 78, 95, 56, 58, 57, 7.00, 290.00, 'They strengthen their lower bodies by running into one another. They are very kind and won’t start fights.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (652, 'Chesnaught', 'Grass', 'Fighting', 88, 107, 122, 74, 75, 64, 16.00, 900.00, 'When it takes a defensive posture with its fists guarding its face, it could withstand a bomb blast.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (653, 'Fennekin', 'Fire', null, 40, 45, 40, 62, 60, 60, 4.00, 94.00, 'As it walks, it munches on a twig in place of a snack. It intimidates opponents by puffing hot air out of its ears.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (654, 'Braixen', 'Fire', null, 59, 59, 58, 90, 70, 73, 10.00, 145.00, 'When the twig is plucked from its tail, friction sets the twig alight. The flame is used to send signals to its allies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (655, 'Delphox', 'Fire', 'Psychic', 75, 69, 72, 114, 100, 104, 15.00, 390.00, 'Using psychic power, it generates a fiery vortex of 5,400 degrees Fahrenheit, incinerating foes swept into this whirl of flame.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (656, 'Froakie', 'Water', null, 41, 56, 40, 62, 44, 71, 3.00, 70.00, 'It protects its skin by covering its body in delicate bubbles. Beneath its happy-go-lucky air, it keeps a watchful eye on its surroundings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (657, 'Frogadier', 'Water', null, 54, 63, 52, 83, 56, 97, 6.00, 109.00, 'Its swiftness is unparalleled. It can scale a tower of more than 2,000 feet in a minute’s time.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (658, 'Greninja', 'Water', 'Dark', 72, 95, 67, 103, 71, 122, 15.00, 400.00, 'It appears and vanishes with a ninja’s grace. It toys with its enemies using swift movements, while slicing them with throwing stars of sharpest water.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (659, 'Bunnelby', 'Normal', null, 38, 36, 38, 32, 36, 57, 4.00, 50.00, 'It’s very sensitive to danger. The sound of Corviknight’s flapping will have Bunnelby digging a hole to hide underground in moments.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (660, 'Diggersby', 'Normal', 'Ground', 85, 56, 77, 50, 77, 78, 10.00, 424.00, 'The fur on its belly retains heat exceptionally well. People used to make heavy winter clothing from fur shed by this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (661, 'Fletchling', 'Normal', 'Flying', 45, 50, 43, 40, 38, 62, 3.00, 17.00, 'Fletchling can be found in both rural and urban areas. They once had a huge territorial dispute with Squawkabilly. Fights broke out all over town.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (662, 'Fletchinder', 'Fire', 'Flying', 62, 73, 55, 56, 52, 84, 7.00, 160.00, 'Its territory has a radius of just over a mile. If any bird Pokémon should enter, it will show them no mercy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (663, 'Talonflame', 'Fire', 'Flying', 78, 81, 71, 74, 69, 126, 12.00, 245.00, 'When it gets excited, it vents sparks from the gaps between its feathers. These unburnable feathers are used as a fireproof material.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (664, 'Scatterbug', 'Bug', null, 38, 35, 40, 27, 25, 35, 3.00, 25.00, 'This Pokémon scatters poisonous powder to repel enemies. It will eat different plants depending on where it lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (665, 'Spewpa', 'Bug', null, 45, 22, 60, 27, 30, 29, 3.00, 84.00, 'Spewpa doesn’t live in a fixed location. It roams where it pleases across the fields and mountains, building up the energy it needs to evolve.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (666, 'Vivillon', 'Bug', 'Flying', 80, 52, 50, 90, 50, 89, 12.00, 170.00, 'This Pokémon was born in a land where flowers bloom. It scatters colorful, toxic scales from its wings during battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (667, 'Litleo', 'Fire', 'Normal', 62, 50, 58, 73, 54, 72, 6.00, 135.00, 'The more a Litleo trains its body and spirit by battling mighty enemies, the hotter its mane will grow.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (668, 'Pyroar', 'Fire', 'Normal', 86, 68, 72, 109, 66, 106, 15.00, 815.00, 'The mane of a male Pyroar heats up to over 3,600 degrees Fahrenheit during battle. Merely approaching it will cause severe burns.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (669, 'Flabébé', 'Fairy', null, 44, 38, 39, 61, 79, 42, 1.00, 1.00, 'Flabébé wears a crown made from pollen it’s collected from its flower. The crown has hidden healing properties.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (670, 'Floette', 'Fairy', null, 54, 45, 47, 75, 98, 52, 2.00, 9.00, 'It gives its own power to flowers, pouring its heart into caring for them. Floette never forgives anyone who messes up a flower bed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (671, 'Florges', 'Fairy', null, 78, 65, 68, 112, 154, 75, 11.00, 100.00, 'Its life can span several hundred years. It’s said to devote its entire life to protecting gardens.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (672, 'Skiddo', 'Grass', null, 66, 65, 48, 62, 57, 52, 9.00, 310.00, 'As long as it has sunlight and water, Skiddo can make energy with the leaves on its body, allowing it to live on rocky mountains barren of food.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (673, 'Gogoat', 'Grass', null, 123, 100, 62, 97, 81, 68, 17.00, 910.00, 'These Pokémon live in herds in mountainous places. The victor in their contests of clashing horns will become the leader of the herd.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (674, 'Pancham', 'Fighting', null, 67, 82, 62, 46, 48, 43, 6.00, 80.00, 'Wanting to make sure it’s taken seriously, Pancham’s always giving others a glare. But if it’s not focusing, it ends up smiling.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (675, 'Pangoro', 'Fighting', 'Dark', 95, 124, 78, 69, 71, 58, 21.00, 1360.00, 'Using its leaf, Pangoro can predict the moves of its opponents. It strikes with punches that can turn a dump truck into scrap with just one hit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (676, 'Furfrou', 'Normal', null, 75, 80, 60, 65, 90, 102, 12.00, 280.00, 'Left alone, its fur will grow longer and longer, but it will only allow someone it trusts to cut it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (677, 'Espurr', 'Psychic', null, 62, 48, 54, 63, 60, 68, 3.00, 35.00, 'There’s enough psychic power in Espurr to send a wrestler flying, but because this power can’t be controlled, Espurr finds it troublesome.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (678, 'Meowstic', 'Psychic', null, 74, 48, 76, 83, 81, 104, 6.00, 85.00, 'The eyeball patterns on the interior of its ears emit psychic energy. It keeps the patterns tightly covered because that power is too immense.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (679, 'Honedge', 'Steel', 'Ghost', 45, 80, 100, 35, 37, 28, 8.00, 20.00, 'The blue eye on the sword’s handguard is the true body of Honedge. With its old cloth, it drains people’s lives away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (680, 'Doublade', 'Steel', 'Ghost', 59, 110, 150, 45, 49, 35, 8.00, 45.00, 'The two swords employ a strategy of rapidly alternating between offense and defense to bring down their prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (681, 'Aegislash', 'Steel', 'Ghost', 60, 50, 150, 50, 150, 60, 17.00, 530.00, 'Apparently, it can detect the innate qualities of leadership. According to legend, whoever it recognizes is destined to become king.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (682, 'Spritzee', 'Fairy', null, 78, 52, 60, 63, 65, 23, 2.00, 5.00, 'The scent its body gives off enraptures those who smell it. Noble ladies had no shortage of love for Spritzee.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (683, 'Aromatisse', 'Fairy', null, 101, 72, 72, 99, 89, 29, 8.00, 155.00, 'The scents Aromatisse can produce range from sweet smells that bolster allies to foul smells that sap an opponent’s will to fight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (684, 'Swirlix', 'Fairy', null, 62, 48, 66, 59, 57, 49, 4.00, 35.00, 'The sweet smell of cotton candy perfumes Swirlix’s fluffy fur. This Pokémon spits out sticky string to tangle up its enemies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (685, 'Slurpuff', 'Fairy', null, 82, 80, 86, 85, 75, 72, 8.00, 50.00, 'Slurpuff’s fur contains a lot of air, making it soft to the touch and lighter than it looks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (686, 'Inkay', 'Dark', 'Psychic', 53, 54, 53, 37, 46, 45, 4.00, 35.00, 'By exposing foes to the blinking of its luminescent spots, Inkay demoralizes them, and then it seizes the chance to flee.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (687, 'Malamar', 'Dark', 'Psychic', 86, 92, 88, 68, 75, 73, 15.00, 470.00, 'It’s said that Malamar’s hypnotic powers played a role in certain history-changing events.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (688, 'Binacle', 'Rock', 'Water', 42, 52, 67, 39, 56, 50, 5.00, 310.00, 'If the two don’t work well together, both their offense and defense fall apart. Without good teamwork, they won’t survive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (689, 'Barbaracle', 'Rock', 'Water', 72, 105, 115, 54, 86, 68, 13.00, 960.00, 'Having an eye on each palm allows it to keep watch in all directions. In a pinch, its limbs start to act on their own to ensure the enemy’s defeat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (690, 'Skrelp', 'Poison', 'Water', 50, 60, 60, 60, 60, 30, 5.00, 73.00, 'This Pokémon is a poor swimmer. If it’s caught in a fierce storm, it will sometimes get washed far away and become unable to return to its home.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (691, 'Dragalge', 'Poison', 'Dragon', 65, 75, 90, 97, 123, 44, 18.00, 815.00, 'Since Finizen is the better swimmer, Dragalge will approach it under the cover of seaweed, then immobilize it with a poisonous attack.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (692, 'Clauncher', 'Water', null, 50, 53, 62, 58, 63, 44, 5.00, 83.00, 'Clauncher’s claws will regrow if they fall off. The meat inside the claws is edible, but it has a distinct flavor that doesn’t appeal to all tastes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (693, 'Clawitzer', 'Water', null, 71, 73, 88, 120, 89, 59, 13.00, 353.00, 'The cannonballs of seawater that Clawitzer launches from its claw are powerful enough to punch through tanker hulls.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (694, 'Helioptile', 'Electric', 'Normal', 44, 38, 33, 61, 43, 70, 5.00, 60.00, 'The sun powers this Pokémon’s electricity generation. Interruption of that process stresses Helioptile to the point of weakness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (695, 'Heliolisk', 'Electric', 'Normal', 62, 55, 52, 109, 94, 109, 10.00, 210.00, 'One Heliolisk basking in the sun with its frill outspread is all it would take to produce enough electricity to power a city.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (696, 'Tyrunt', 'Rock', 'Dragon', 58, 89, 77, 45, 45, 48, 8.00, 260.00, 'This Pokémon is selfish and likes to be pampered. It can also inflict grievous wounds on its Trainer just by playing around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (697, 'Tyrantrum', 'Rock', 'Dragon', 82, 121, 119, 69, 59, 71, 25.00, 2700.00, 'A single bite of Tyrantrum’s massive jaws will demolish a car. This Pokémon was the king of the ancient world.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (698, 'Amaura', 'Rock', 'Ice', 77, 59, 50, 67, 63, 46, 13.00, 252.00, 'Amaura is an ancient Pokémon that has gone extinct. Specimens of this species can sometimes be found frozen in ice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (699, 'Aurorus', 'Rock', 'Ice', 123, 77, 72, 99, 92, 58, 27.00, 2250.00, 'When gripped by rage, Aurorus will emanate freezing air, covering everything around it in ice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (700, 'Sylveon', 'Fairy', null, 95, 65, 65, 110, 130, 60, 10.00, 235.00, 'Sylveon cuts an elegant figure as it dances lightly around, feelers fluttering, but its piercing moves aim straight for its opponents’ weak spots.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (701, 'Hawlucha', 'Fighting', 'Flying', 78, 92, 75, 74, 63, 118, 8.00, 215.00, 'Hawlucha live quietly without flocking together. They fight constantly with their natural enemies: noisy groups of Primeape.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (702, 'Dedenne', 'Electric', 'Fairy', 67, 58, 57, 81, 67, 101, 2.00, 22.00, 'Dedenne emit electrical waves from the whiskers on their cheeks to communicate with each other. When low on electricity, they curl up and sleep.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (703, 'Carbink', 'Rock', 'Fairy', 50, 50, 150, 50, 150, 50, 3.00, 57.00, 'It’s said that somewhere in the world, there’s a mineral vein housing a large pack of slumbering Carbink. It’s also said that this pack has a queen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (704, 'Goomy', 'Dragon', null, 45, 50, 35, 55, 75, 40, 3.00, 28.00, 'Goomy’s horns are excellent sensory organs that cover all five of Goomy’s senses. Goomy picks up on danger from the movement of the air.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (705, 'Sliggoo', 'Dragon', null, 68, 75, 53, 83, 113, 60, 8.00, 175.00, 'When Sliggoo senses danger, the mucus coating its entire body becomes more concentrated—it’ll dissolve anything.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (706, 'Goodra', 'Dragon', null, 90, 100, 70, 110, 150, 80, 20.00, 1505.00, 'This Pokémon is uncontrollable when enraged. It rampages on and on, lashing its tail with enough power to send a dump truck flying.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (707, 'Klefki', 'Steel', 'Fairy', 57, 80, 91, 80, 87, 75, 2.00, 30.00, 'In the past, noble families entrusted their vault keys to a Klefki. They passed the Klefki down through the generations, taking good care of it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (708, 'Phantump', 'Ghost', 'Grass', 43, 70, 48, 50, 60, 38, 4.00, 70.00, 'With a voice like a human child’s, it cries out to lure adults deep into the forest, getting them lost among the trees.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (709, 'Trevenant', 'Ghost', 'Grass', 85, 110, 76, 65, 82, 56, 15.00, 710.00, 'Small roots that extend from the tips of this Pokémon’s feet can tie into the trees of the forest and give Trevenant control over them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (710, 'Pumpkaboo', 'Ghost', 'Grass', 49, 66, 70, 44, 55, 51, 4.00, 50.00, 'It is said to carry wandering spirits to the place where they belong so they can move on.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (711, 'Gourgeist', 'Ghost', 'Grass', 65, 90, 122, 58, 75, 84, 9.00, 125.00, 'It enwraps its prey in its hairlike arms. It sings joyfully as it observes the suffering of its prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (712, 'Bergmite', 'Ice', null, 55, 69, 85, 32, 35, 28, 10.00, 995.00, 'Bergmite protects itself by coating its body in ice formed by frigid air of −148 degrees Fahrenheit. It fights with Frigibax whenever they meet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (713, 'Avalugg', 'Ice', null, 95, 117, 184, 44, 46, 28, 20.00, 5050.00, 'This Pokémon uses its massive icy body to flatten anything that gets in its way. When it’s floating out on the ocean, it looks exactly like drift ice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (714, 'Noibat', 'Flying', 'Dragon', 40, 30, 35, 45, 40, 55, 5.00, 80.00, 'Noibat can change the frequency of its sound waves at will, and it generates ultrasonic waves of up to 200,000 hertz.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (715, 'Noivern', 'Flying', 'Dragon', 85, 70, 80, 97, 80, 123, 15.00, 850.00, 'In the dark, even Hydreigon are terrified of this Pokémon. But in the light, Noivern is the one that avoids battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (716, 'Xerneas', 'Fairy', null, 126, 131, 95, 131, 98, 99, 30.00, 2150.00, 'When the horns on its head shine in seven colors, it is said to be sharing everlasting life.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (717, 'Yveltal', 'Dark', 'Flying', 126, 131, 95, 131, 98, 99, 58.00, 2030.00, 'When its life comes to an end, it absorbs the life energy of every living thing and turns into a cocoon once more.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (718, 'Zygarde', 'Dragon', 'Ground', 108, 100, 121, 81, 95, 95, 50.00, 3050.00, 'Some say it can change to an even more powerful form when battling those who threaten the ecosystem.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (719, 'Diancie', 'Rock', 'Fairy', 50, 100, 150, 100, 150, 50, 7.00, 88.00, 'It can instantly create many diamonds by compressing the carbon in the air between its hands.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (720, 'Hoopa', 'Psychic', 'Ghost', 80, 110, 60, 150, 130, 70, 5.00, 90.00, 'It is said to be able to seize anything it desires with its six rings and six huge arms. With its power sealed, it is transformed into a much smaller form.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (721, 'Volcanion', 'Fire', 'Water', 80, 110, 120, 130, 90, 70, 17.00, 1950.00, 'It expels its internal steam from the arms on its back. It has enough power to blow away a mountain.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (722, 'Rowlet', 'Grass', 'Flying', 68, 55, 55, 50, 50, 42, 3.00, 15.00, 'Flies noiselessly on delicate wings. It has mastered the art of deftly launching dagger-sharp feathers from those same wings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (723, 'Dartrix', 'Grass', 'Flying', 78, 75, 75, 70, 70, 52, 7.00, 160.00, 'Regularly basks in sunlight to gather power—presumably due to the frigid climate. Nonetheless, the edges of the blade quills set into its wings are keen as ever.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (724, 'Decidueye', 'Grass', 'Ghost', 78, 107, 75, 100, 100, 70, 16.00, 366.00, 'In a tenth of a second, it can nock and fire an arrow quill, piercing an opponent’s weak point before they notice what’s happening.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (725, 'Litten', 'Fire', null, 45, 65, 40, 60, 40, 70, 4.00, 43.00, 'Trying to pet Litten before it trusts you will result in a nasty scratch from its sharp claws. Be careful.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (726, 'Torracat', 'Fire', null, 65, 85, 50, 80, 50, 90, 7.00, 250.00, 'When facing a powerful enemy, Torracat’s fighting spirit gets pumped up, and its fire bell blazes hotter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (727, 'Incineroar', 'Fire', 'Dark', 95, 115, 90, 80, 90, 60, 18.00, 830.00, 'Incineroar’s rough and aggressive behavior is its most notable trait, but the way it helps out small Pokémon shows that it has a kind side as well.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (728, 'Popplio', 'Water', null, 50, 54, 54, 66, 56, 40, 4.00, 75.00, 'If Popplio want to create big, powerful balloons, they must be persistent. It takes daily practice for these Pokémon to develop their skills.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (729, 'Brionne', 'Water', null, 60, 69, 69, 91, 81, 50, 6.00, 175.00, 'On nights when the sea is calm, Brionne dance with one another to the singing of the Primarina that’s leading them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (730, 'Primarina', 'Water', 'Fairy', 80, 74, 74, 126, 116, 60, 18.00, 440.00, 'For Primarina, every battle’s a stage. Its singing and the dancing of its balloons will mesmerize the audience.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (731, 'Pikipek', 'Normal', 'Flying', 35, 75, 30, 30, 30, 65, 3.00, 12.00, 'It may look spindly, but its neck muscles are heavy-duty. It can peck at a tree 16 times per second!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (732, 'Trumbeak', 'Normal', 'Flying', 55, 85, 50, 40, 50, 75, 6.00, 148.00, 'From its mouth, it fires the seeds of berries it has eaten. The scattered seeds give rise to new plants.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (733, 'Toucannon', 'Normal', 'Flying', 80, 120, 75, 75, 75, 60, 11.00, 260.00, 'Known for forming harmonious couples, this Pokémon is brought to wedding ceremonies as a good luck charm.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (734, 'Yungoos', 'Normal', null, 48, 70, 30, 30, 30, 45, 4.00, 60.00, 'It spends its waking hours searching endlessly for food. When Yungoos is hungry, its ferocity gains a certain edge.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (735, 'Gumshoos', 'Normal', null, 88, 110, 60, 55, 60, 45, 7.00, 142.00, 'Gumshoos specializes in relentlessly tracking down prey. The simple-minded Skwovet doesn’t seem to provide Gumshoos enough challenge.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (736, 'Grubbin', 'Bug', null, 47, 62, 45, 55, 45, 46, 4.00, 44.00, 'It uses its big jaws to dig nests into the forest floor, and it loves to feed on sweet tree sap.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (737, 'Charjabug', 'Bug', 'Electric', 57, 82, 95, 55, 75, 36, 5.00, 105.00, 'Its digestive processes convert the leaves it eats into electricity. An electric sac in its belly stores the electricity for later use.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (738, 'Vikavolt', 'Bug', 'Electric', 77, 70, 90, 145, 75, 43, 15.00, 450.00, 'If it carries a Charjabug to use as a spare battery, a flying Vikavolt can rapidly fire high-powered beams of electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (739, 'Crabrawler', 'Fighting', null, 47, 82, 57, 42, 47, 63, 6.00, 70.00, 'If it loses its pincers, they’ll quickly regrow. The pincers are popular ingredients in paella since their shells produce a tasty soup stock.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (740, 'Crabominable', 'Fighting', 'Ice', 97, 132, 77, 62, 67, 43, 17.00, 1800.00, 'Though its punches are powerful, this Pokémon’s movements are sluggish. It blows icy bubbles from its mouth to immobilize its opponents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (741, 'Oricorio', 'Fire', 'Flying', 75, 70, 70, 98, 70, 93, 6.00, 34.00, 'This form of Oricorio has sipped red nectar. It whips up blazing flames as it moves to the steps of its passionate dance.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (742, 'Cutiefly', 'Bug', 'Fairy', 40, 45, 40, 55, 40, 84, 1.00, 2.00, 'An opponent’s aura can tell Cutiefly what that opponent’s next move will be. Then Cutiefly can glide around the attack and strike back.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (743, 'Ribombee', 'Bug', 'Fairy', 60, 55, 60, 95, 70, 124, 2.00, 5.00, 'Ribombee absolutely hate getting wet or rained on. In the cloudy Galar region, they are very seldom seen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (744, 'Rockruff', 'Rock', null, 45, 65, 40, 30, 40, 60, 5.00, 92.00, 'This Pokémon travels in a pack with others until it grows up. When its mood turns sour, it starts striking the ground with the rocks on its neck.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (745, 'Lycanroc', 'Rock', null, 75, 115, 65, 55, 65, 112, 8.00, 250.00, 'It has a calm and collected demeanor. It swiftly closes in on its prey, then slices them with the rocks in its mane.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (746, 'Wishiwashi', 'Water', null, 45, 20, 20, 25, 25, 40, 2.00, 3.00, 'When it senses danger, its eyes tear up. The sparkle of its tears signals other Wishiwashi to gather.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (747, 'Mareanie', 'Poison', 'Water', 50, 53, 62, 43, 52, 45, 4.00, 80.00, 'It has excellent regenerative capabilities. Legs that a Mareanie has lost have a very bitter, astringent flavor—they’re not suitable as food.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (748, 'Toxapex', 'Poison', 'Water', 50, 63, 152, 53, 142, 35, 7.00, 145.00, 'Toxapex gets into fierce battles with Bruxish over areas where warm ocean currents flow, but the odds are always against it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (749, 'Mudbray', 'Ground', null, 70, 100, 70, 45, 55, 45, 10.00, 1100.00, 'Though a slow walker, Mudbray is plenty strong. Its pace doesn’t change even when it’s loaded with 50 times its own body weight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (750, 'Mudsdale', 'Ground', null, 100, 125, 100, 55, 85, 35, 25.00, 9200.00, 'Its legs are fortified with mud and harder than stone, and they can reduce a large truck to scrap with one kick.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (751, 'Dewpider', 'Water', 'Bug', 38, 40, 52, 40, 72, 27, 3.00, 40.00, 'Dewpider normally lives underwater. When it comes onto land in search of food, it takes water with it in the form of a bubble on its head.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (752, 'Araquanid', 'Water', 'Bug', 68, 70, 92, 50, 132, 42, 18.00, 820.00, 'It acts as a caretaker for Dewpider, putting them inside its bubble and letting them eat any leftover food.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (753, 'Fomantis', 'Grass', null, 40, 55, 35, 50, 35, 35, 3.00, 15.00, 'Many Trainers give their Fomantis their own flowerpots so they can sunbathe in peace and quiet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (754, 'Lurantis', 'Grass', null, 70, 105, 90, 80, 90, 45, 9.00, 185.00, 'A lot of time and effort is required to maintain the vivid colors of its petals. This Pokémon puts its Trainer’s attentiveness to the test.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (755, 'Morelull', 'Grass', 'Fairy', 40, 35, 55, 65, 75, 15, 2.00, 15.00, 'Morelull live in forests that stay dark even during the day. They scatter flickering spores that put enemies to sleep.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (756, 'Shiinotic', 'Grass', 'Fairy', 60, 45, 80, 90, 100, 30, 10.00, 115.00, 'If you see a light deep in a forest at night, don’t go near. Shiinotic will make you fall fast asleep.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (757, 'Salandit', 'Poison', 'Fire', 48, 44, 40, 71, 40, 77, 6.00, 48.00, 'Only female Salandit can produce gas laden with pheromones. Males entranced by this gas will do whatever the females tell them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (758, 'Salazzle', 'Poison', 'Fire', 68, 64, 60, 111, 60, 117, 12.00, 222.00, 'When two Salazzle meet, they will use their pheromone gas to fight over the males in each other’s group.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (759, 'Stufful', 'Normal', 'Fighting', 70, 75, 50, 45, 50, 50, 5.00, 68.00, 'The way it protects itself by flailing its arms may be an adorable sight, but stay well away. This is flailing that can snap thick tree trunks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (760, 'Bewear', 'Normal', 'Fighting', 120, 125, 80, 55, 60, 60, 21.00, 1350.00, 'The moves it uses to take down its prey would make a martial artist jealous. It tucks subdued prey under its arms to carry them to its nest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (761, 'Bounsweet', 'Grass', null, 42, 30, 38, 30, 38, 32, 3.00, 32.00, 'A Greedent drawn in by the sweet scent of these Pokémon will tuck the Bounsweet in among the berries in its tail and carry them all away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (762, 'Steenee', 'Grass', null, 52, 40, 48, 40, 48, 62, 7.00, 82.00, 'Steenee bounces energetically through forests. If the rind that peels off its body is pulverized, it can be used to treat stomach pains.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (763, 'Tsareena', 'Grass', null, 72, 120, 98, 50, 98, 72, 12.00, 214.00, 'This Pokémon launches fierce yet elegant kicks with its long, slender legs. It views Quaquaval as its rival.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (764, 'Comfey', 'Fairy', null, 51, 52, 90, 82, 110, 100, 1.00, 3.00, 'These Pokémon smell very nice. All Comfey wear different flowers, so each of these Pokémon has its own individual scent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (765, 'Oranguru', 'Normal', 'Psychic', 90, 60, 80, 90, 110, 60, 15.00, 760.00, 'This Pokémon lives quietly in the depths of the forest. The purple, cape-like fur gets longer and longer as Oranguru ages.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (766, 'Passimian', 'Fighting', null, 100, 120, 90, 40, 60, 80, 20.00, 828.00, 'The boss chooses 10 members of the group to go out hunting. The hunting party will evenly split the food they find with the rest of the group.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (767, 'Wimpod', 'Bug', 'Water', 25, 35, 40, 20, 30, 80, 5.00, 120.00, 'Wimpod gather in swarms, constantly on the lookout for danger. They scatter the moment they detect an enemy’s presence.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (768, 'Golisopod', 'Bug', 'Water', 75, 125, 140, 60, 90, 40, 20.00, 1080.00, 'They live in sunken ships or in holes in the seabed. When Golisopod and Grapploct battle, the loser becomes the winner’s meal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (769, 'Sandygast', 'Ghost', 'Ground', 55, 55, 80, 70, 45, 15, 5.00, 700.00, 'It flings sand into the eyes of its prey and tries to close in on them while they’re blinded, but since Sandygast is so slow, the prey tends to escape.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (770, 'Palossand', 'Ghost', 'Ground', 85, 75, 110, 100, 75, 35, 13.00, 2500.00, 'From the hollows in its arms, it fires the bones of its victims, which are all dried up after being drained of their vitality.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (771, 'Pyukumuku', 'Water', null, 55, 60, 130, 30, 130, 5, 3.00, 12.00, 'It’s covered in a slime that keeps its skin moist, allowing it to stay on land for days without drying up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (772, 'Type: Null', 'Normal', null, 95, 95, 95, 95, 95, 59, 19.00, 1205.00, 'It was modeled after a mighty Pokémon of myth. The mask placed upon it limits its power in order to keep it under control.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (773, 'Silvally', 'Normal', null, 95, 95, 95, 95, 95, 95, 23.00, 1005.00, 'The final factor needed to release this Pokémon’s true power was a strong bond with a Trainer it trusts.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (774, 'Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'Although its outer shell is uncommonly durable, the shock of falling to the ground smashes the shell to smithereens.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (775, 'Komala', 'Normal', null, 65, 115, 65, 75, 95, 65, 4.00, 199.00, 'A potent anesthetic can be made by diluting Komala’s drool. This anesthetic was used for surgeries in the past.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (776, 'Turtonator', 'Fire', 'Dragon', 60, 78, 135, 91, 85, 36, 20.00, 2120.00, 'Eating sulfur in its volcanic habitat is what causes explosive compounds to develop in its shell. Its droppings are also dangerously explosive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (777, 'Togedemaru', 'Electric', 'Steel', 65, 98, 63, 40, 73, 96, 3.00, 33.00, 'When it’s in trouble, it curls up into a ball, makes its fur spikes stand on end, and then discharges electricity indiscriminately.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (778, 'Mimikyu', 'Ghost', 'Fairy', 55, 90, 80, 50, 105, 96, 2.00, 7.00, 'Mimikyu was only recently identified as a Pokémon. Previously, people thought it was just a ghost wearing a cloth.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (779, 'Bruxish', 'Water', 'Psychic', 68, 105, 70, 70, 70, 92, 9.00, 190.00, 'When sunlight reflects on the ripples created by a Bruxish grinding its teeth, the water all around sparkles brilliantly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (780, 'Drampa', 'Normal', 'Dragon', 78, 60, 85, 135, 91, 36, 30.00, 1850.00, 'Drampa is a kind and friendly Pokémon—up until it’s angered. When that happens, it stirs up a gale and flattens everything around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (781, 'Dhelmise', 'Ghost', 'Grass', 70, 131, 100, 86, 90, 40, 39.00, 2100.00, 'After lowering its anchor, it waits for its prey. It catches large Wailord and drains their life-force.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (782, 'Jangmo-o', 'Dragon', null, 45, 55, 65, 45, 45, 45, 6.00, 297.00, 'Jangmo-o strikes its scales to communicate with others of its kind. Its scales are actually fur that’s become as hard as metal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (783, 'Hakamo-o', 'Dragon', 'Fighting', 55, 75, 90, 65, 70, 65, 12.00, 470.00, 'Before attacking its enemies, it clashes its scales together and roars. Its sharp claws shred the opposition.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (784, 'Kommo-o', 'Dragon', 'Fighting', 75, 110, 125, 100, 105, 85, 16.00, 782.00, 'Certain ruins have paintings of ancient warriors wearing armor made of Kommo-o scales.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (785, 'Tapu Koko', 'Electric', 'Fairy', 70, 115, 85, 95, 75, 130, 18.00, 205.00, 'The lightning-wielding guardian deity of Melemele, Tapu Koko is brimming with curiosity and appears before people from time to time.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (786, 'Tapu Lele', 'Psychic', 'Fairy', 70, 85, 75, 130, 115, 95, 12.00, 186.00, 'Although called a guardian deity, Tapu Lele is devoid of guilt about its cruel disposition and can be described as nature incarnate.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (787, 'Tapu Bulu', 'Grass', 'Fairy', 70, 130, 115, 85, 95, 75, 19.00, 455.00, 'It makes ringing sounds with its tail to let others know where it is, avoiding unneeded conflicts. This guardian deity of Ula’ula controls plants.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (788, 'Tapu Fini', 'Water', 'Fairy', 70, 75, 115, 95, 130, 85, 13.00, 212.00, 'Although it’s called a guardian deity, terrible calamities sometimes befall those who recklessly approach Tapu Fini.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (789, 'Cosmog', 'Psychic', null, 43, 29, 31, 29, 31, 37, 2.00, 1.00, 'Cosmog is very curious but not very cautious, often placing itself in danger. If things start to look dicey, it teleports away.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (790, 'Cosmoem', 'Psychic', null, 43, 29, 131, 29, 131, 37, 1.00, 9999.00, 'It sucks in dust from the air at an astounding rate, frantically building up energy within its core as preparation for evolution.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (791, 'Solgaleo', 'Psychic', 'Steel', 137, 137, 107, 113, 89, 97, 34.00, 2300.00, 'Solgaleo was once known as the Beast That Devours the Sun. Energy in the form of light radiates boundlessly from it.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (792, 'Lunala', 'Psychic', 'Ghost', 137, 113, 89, 137, 107, 97, 40.00, 1200.00, 'It steals the light from its surroundings and then becomes the full moon, showering its own light across the night sky.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (793, 'Nihilego', 'Rock', 'Poison', 109, 53, 47, 127, 131, 103, 12.00, 555.00, 'It appeared in this world from an Ultra Wormhole. Nihilego appears to be a parasite that lives by feeding on people and Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (794, 'Buzzwole', 'Bug', 'Fighting', 107, 139, 139, 53, 53, 79, 24.00, 3336.00, 'Buzzwole goes around showing off its abnormally swollen muscles. It is one kind of Ultra Beast.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (795, 'Pheromosa', 'Bug', 'Fighting', 71, 137, 37, 137, 37, 151, 18.00, 250.00, 'Although it’s alien to this world and a danger here, it’s apparently a common organism in the world where it normally lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (796, 'Xurkitree', 'Electric', null, 83, 89, 71, 173, 71, 83, 38.00, 1000.00, 'They’ve been dubbed Ultra Beasts. Some of them stand unmoving, like trees, with their arms and legs stuck into the ground.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (797, 'Celesteela', 'Steel', 'Flying', 97, 101, 103, 107, 101, 61, 92.00, 9999.00, 'Although it’s alien to this world and a danger here, it’s apparently a common organism in the world where it normally lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (798, 'Kartana', 'Grass', 'Steel', 59, 181, 131, 59, 31, 109, 3.00, 1.00, 'Although it’s alien to this world and a danger here, it’s apparently a common organism in the world where it normally lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (799, 'Guzzlord', 'Dark', 'Dragon', 223, 101, 53, 97, 53, 43, 55.00, 8880.00, 'An unknown life-form called a UB. It may be constantly hungry—it is certainly always devouring something.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (800, 'Necrozma', 'Psychic', null, 97, 107, 101, 127, 89, 79, 24.00, 2300.00, 'It needs light to survive, and it goes on a rampage seeking it out. Its laser beams will cut anything to pieces.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (801, 'Magearna', 'Steel', 'Fairy', 80, 95, 115, 130, 115, 65, 10.00, 805.00, 'Built roughly 500 years ago by a scientist, the part called the Soul-Heart is the actual life-form.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (802, 'Marshadow', 'Fighting', 'Ghost', 90, 125, 80, 90, 90, 125, 7.00, 222.00, 'This Pokémon can conceal itself in any shadow, so it went undiscovered for a long time.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (803, 'Poipole', 'Poison', null, 67, 73, 67, 73, 67, 73, 6.00, 18.00, 'An Ultra Beast that lives in a different world, it cackles wildly as it sprays its opponents with poison from the needles on its head.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (804, 'Naganadel', 'Poison', 'Dragon', 73, 73, 73, 127, 73, 121, 36.00, 1500.00, 'One kind of Ultra Beast, it fires a glowing, venomous liquid from its needles. This liquid is also immensely adhesive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (805, 'Stakataka', 'Rock', 'Steel', 61, 131, 211, 53, 101, 13, 55.00, 8200.00, 'When stone walls started moving and attacking, the brute’s true identity was this mysterious life-form, which brings to mind an Ultra Beast.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (806, 'Blacephalon', 'Fire', 'Ghost', 53, 127, 53, 151, 79, 107, 18.00, 130.00, 'A UB that appeared from an Ultra Wormhole, it causes explosions, then takes advantage of opponents’ surprise to rob them of their vitality.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (807, 'Zeraora', 'Electric', null, 88, 112, 75, 102, 80, 143, 15.00, 445.00, 'Electricity sparks from the pads on its limbs. Wherever Zeraora runs, lightning flashes and thunder echoes.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (808, 'Meltan', 'Steel', null, 46, 65, 65, 55, 35, 34, 2.00, 80.00, 'They live as a group, but when the time comes, one strong Meltan will absorb all the others and evolve.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (809, 'Melmetal', 'Steel', null, 135, 143, 143, 80, 65, 34, 25.00, 8000.00, 'Centrifugal force is behind the punches of Melmetal’s heavy hex-nut arms. Melmetal is said to deliver the strongest punches of all Pokémon.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (810, 'Grookey', 'Grass', null, 50, 65, 50, 40, 40, 65, 3.00, 50.00, 'It attacks with rapid beats of its stick. As it strikes with amazing speed, it gets more and more pumped.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (811, 'Thwackey', 'Grass', null, 70, 85, 70, 55, 60, 80, 7.00, 140.00, 'When it’s drumming out rapid beats in battle, it gets so caught up in the rhythm that it won’t even notice that it’s already knocked out its opponent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (812, 'Rillaboom', 'Grass', null, 100, 125, 90, 60, 70, 85, 21.00, 900.00, 'The one with the best drumming techniques becomes the boss of the troop. It has a gentle disposition and values harmony among its group.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (813, 'Scorbunny', 'Fire', null, 50, 71, 40, 40, 40, 69, 3.00, 45.00, 'It has special pads on the backs of its feet, and one on its nose. Once it’s raring to fight, these pads radiate tremendous heat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (814, 'Raboot', 'Fire', null, 65, 86, 60, 55, 60, 94, 6.00, 90.00, 'It kicks berries right off the branches of trees and then juggles them with its feet, practicing its footwork.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (815, 'Cinderace', 'Fire', null, 80, 116, 75, 65, 75, 119, 14.00, 330.00, 'It’s skilled at both offense and defense, and it gets pumped up when cheered on. But if it starts showboating, it could put itself in a tough spot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (816, 'Sobble', 'Water', null, 50, 40, 40, 70, 40, 70, 3.00, 40.00, 'When it gets wet, its skin changes color, and this Pokémon becomes invisible as if it were camouflaged.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (817, 'Drizzile', 'Water', null, 65, 60, 55, 95, 55, 90, 7.00, 115.00, 'Highly intelligent but also very lazy, it keeps enemies out of its territory by laying traps everywhere.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (818, 'Inteleon', 'Water', null, 70, 85, 65, 125, 65, 120, 19.00, 452.00, 'Its nictitating membranes let it pick out foes’ weak points so it can precisely blast them with water that shoots from its fingertips at Mach 3.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (819, 'Skwovet', 'Normal', null, 70, 55, 55, 35, 35, 25, 3.00, 25.00, 'No matter how much it stuffs its belly with food, it is always anxious about getting hungry again. So, it stashes berries in its cheeks and tail.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (820, 'Greedent', 'Normal', null, 120, 95, 95, 55, 75, 20, 6.00, 60.00, 'This Pokémon makes off with heaps of fallen berries by wrapping them in its tail, which is roughly twice the length of its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (821, 'Rookidee', 'Flying', null, 38, 47, 35, 33, 35, 57, 2.00, 18.00, 'The females are fussier than the males. If another creature dirties a female Rookidee’s wings, it’ll peck the offender relentlessly in a burning rage.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (822, 'Corvisquire', 'Flying', null, 68, 67, 55, 43, 55, 77, 8.00, 160.00, 'This intelligent Pokémon will quickly learn how to use any tool it can hold in its beak or its talons.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (823, 'Corviknight', 'Flying', 'Steel', 98, 87, 105, 53, 85, 67, 22.00, 750.00, 'Although its wings have partly turned to steel and become heavy as a result, this Pokémon flies through the skies with ease.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (824, 'Blipbug', 'Bug', null, 25, 20, 20, 25, 45, 45, 4.00, 80.00, 'Often found in gardens, this Pokémon has hairs on its body that it uses to assess its surroundings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (825, 'Dottler', 'Bug', 'Psychic', 50, 35, 80, 50, 90, 30, 4.00, 195.00, 'As it grows inside its shell, it uses its psychic abilities to monitor the outside world and prepare for evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (826, 'Orbeetle', 'Bug', 'Psychic', 60, 45, 110, 80, 120, 90, 4.00, 408.00, 'It emits psychic energy to observe and study what’s around it—and what’s around it can include things over six miles away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (827, 'Nickit', 'Dark', null, 40, 28, 28, 47, 52, 50, 6.00, 89.00, 'Cunning and cautious, this Pokémon survives by stealing food from others. It erases its tracks with swipes of its tail as it makes off with its plunder.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (828, 'Thievul', 'Dark', null, 70, 58, 58, 87, 92, 90, 12.00, 199.00, 'With a lithe body and sharp claws, it goes around stealing food and eggs. Boltund is its natural enemy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (829, 'Gossifleur', 'Grass', null, 40, 40, 60, 40, 60, 10, 4.00, 22.00, 'It whirls around in the wind while singing a joyous song. This delightful display has charmed many into raising this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (830, 'Eldegoss', 'Grass', null, 60, 50, 90, 80, 120, 60, 5.00, 25.00, 'The cotton on the head of this Pokémon can be spun into a glossy, gorgeous yarn—a Galar regional specialty.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (831, 'Wooloo', 'Normal', null, 42, 40, 55, 40, 45, 48, 6.00, 60.00, 'If its fleece grows too long, Wooloo won’t be able to move. Cloth made with the wool of this Pokémon is surprisingly strong.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (832, 'Dubwool', 'Normal', null, 72, 80, 100, 60, 90, 88, 13.00, 430.00, 'Its majestic horns are meant only to impress the opposite gender. They never see use in battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (833, 'Chewtle', 'Water', null, 50, 64, 50, 38, 38, 44, 3.00, 85.00, 'A popular game among children is to lift up sticks that Chewtle have bitten onto to see whose Chewtle can hang on the longest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (834, 'Drednaw', 'Water', 'Rock', 90, 115, 90, 48, 68, 74, 10.00, 1155.00, 'Drednaw lurks along the shoreline. When prey come to drink water, Drednaw stretches its neck out and chomps down on them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (835, 'Yamper', 'Electric', null, 59, 45, 50, 40, 50, 26, 3.00, 135.00, 'This gluttonous Pokémon only assists people with their work because it wants treats. As it runs, it crackles with electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (836, 'Boltund', 'Electric', null, 69, 90, 60, 90, 60, 121, 10.00, 340.00, 'It sends electricity through its legs to boost their strength. Running at top speed, it easily breaks 50 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (837, 'Rolycoly', 'Rock', null, 30, 40, 50, 40, 50, 30, 3.00, 120.00, 'Chunks of the surface of this Pokémon’s body that have grown old and flaked off have long been used for fuel as an alternative to coal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (838, 'Carkol', 'Rock', 'Fire', 80, 60, 90, 60, 70, 50, 11.00, 780.00, 'Due to the coal tar created inside it, the heap of coal on Carkol’s back never falls apart, even when the Pokémon rolls around at high speeds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (839, 'Coalossal', 'Rock', 'Fire', 110, 80, 120, 80, 90, 30, 28.00, 3105.00, 'It’s gentle usually but fearsome when angered. With a body that burns at over 2,700 degrees Fahrenheit, it crushes foes and turns them to ash.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (840, 'Applin', 'Grass', 'Dragon', 40, 40, 80, 40, 40, 20, 2.00, 5.00, 'Applin lives inside an apple. When an Applin is separated from its apple, its body loses moisture and the Pokémon grows weak.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (841, 'Flapple', 'Grass', 'Dragon', 70, 110, 80, 95, 60, 70, 3.00, 10.00, 'It uses its own body fluid to repair its apple. Strong Flapple that have won many battles have apples that are clay colored all over.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (842, 'Appletun', 'Grass', 'Dragon', 110, 85, 80, 100, 80, 30, 4.00, 130.00, 'When some Lechonk come along to lick the sweet nectar on Appletun’s back, Appletun will spew sticky nectar at them to drive them away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (843, 'Silicobra', 'Ground', null, 52, 57, 75, 35, 50, 46, 22.00, 76.00, 'Silicobra’s large nostrils are specialized for spraying sand, so this Pokémon is not very good at telling apart different smells.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (844, 'Sandaconda', 'Ground', null, 72, 107, 125, 65, 70, 71, 38.00, 655.00, 'The sand it spews contains sharp, pointy gravel, which is actually just sand that Sandaconda’s saliva has hardened into irregular shapes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (845, 'Cramorant', 'Flying', 'Water', 70, 85, 55, 85, 95, 85, 8.00, 180.00, 'This hungry Pokémon swallows Arrokuda whole. Occasionally, it makes a mistake and tries to swallow a Pokémon other than its preferred prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (846, 'Arrokuda', 'Water', null, 41, 63, 40, 40, 30, 66, 5.00, 10.00, 'It takes down prey by charging into them with its hard, pointed jaw. But Arrokuda’s eyesight is poor, so this tactic has a low success rate.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (847, 'Barraskewda', 'Water', null, 61, 123, 60, 60, 50, 136, 13.00, 300.00, 'It swims at speeds of over 100 knots and battles fiercely with pods of Finizen over prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (848, 'Toxel', 'Electric', 'Poison', 40, 38, 35, 54, 35, 40, 4.00, 110.00, 'This selfish, attention-seeking Pokémon stores poison and electricity in two different sacs inside its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (849, 'Amped Toxtricity', 'Electric', 'Poison', 75, 98, 70, 114, 70, 75, 16.00, 400.00, 'As it gulps down stagnant water and generates electricity in its body, a sound like a rhythm played by a bass guitar reverberates all around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (850, 'Sizzlipede', 'Fire', 'Bug', 50, 65, 45, 50, 50, 45, 7.00, 10.00, 'It wraps prey up with its heated body, cooking them in its coils. Once they’re well-done, it will voraciously nibble them down to the last morsel.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (851, 'Centiskorch', 'Fire', 'Bug', 100, 115, 65, 90, 90, 65, 30.00, 1200.00, 'While its burning body is already dangerous on its own, this excessively hostile Pokémon also has large and very sharp fangs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (852, 'Clobbopus', 'Fighting', null, 50, 68, 60, 50, 50, 32, 6.00, 40.00, 'Its tentacles tear off easily, but it isn’t alarmed when that happens—it knows they’ll grow back. It’s about as smart as a three-year-old.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (853, 'Grapploct', 'Fighting', null, 80, 118, 90, 70, 80, 42, 16.00, 390.00, 'Searching for an opponent to test its skills against, it emerges onto land. Once the battle is over, it returns to the sea.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (854, 'Sinistea', 'Ghost', null, 40, 45, 45, 74, 54, 50, 1.00, 2.00, 'Sinistea gets into your body when you drink it, and then it steals your vitality from within. It also tastes awful.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (855, 'Polteageist', 'Ghost', null, 60, 65, 65, 134, 114, 70, 2.00, 4.00, 'Though risky to drink, this Pokémon’s tea tastes delicious. Gourmets who have no fear of danger drink Polteageist tea day after day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (856, 'Hatenna', 'Psychic', null, 42, 30, 45, 56, 53, 39, 4.00, 34.00, 'It senses the feelings of other living creatures. Be careful not to expose it to strong emotions for too long, or it will end up exhausted.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (857, 'Hattrem', 'Psychic', null, 57, 40, 65, 86, 73, 49, 6.00, 48.00, 'The moment this Pokémon finds someone who’s emitting strong emotions, it will pummel them senseless with its braids to silence them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (858, 'Hatterene', 'Psychic', 'Fairy', 57, 90, 95, 136, 103, 29, 21.00, 51.00, 'Beware of forests that show no signs of living creatures within. You may have wandered into Hatterene’s territory.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (859, 'Impidimp', 'Dark', 'Fairy', 45, 45, 30, 55, 40, 50, 4.00, 55.00, 'They live in groups, pestering and playing pranks on each other to polish their troublemaking skills.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (860, 'Morgrem', 'Dark', 'Fairy', 65, 60, 45, 75, 55, 70, 8.00, 125.00, 'This Pokémon absorbs negative emotions and turns them into energy. It’s popular with people who tend to think gloomy thoughts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (861, 'Grimmsnarl', 'Dark', 'Fairy', 95, 120, 65, 95, 75, 60, 15.00, 610.00, 'It lives deep within the forest. Even after evolving into this splendid form, it hasn’t given up on its petty misdeeds and pranks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (862, 'Obstagoon', 'Dark', 'Normal', 93, 90, 101, 60, 81, 95, 16.00, 460.00, 'It evolved after experiencing numerous fights. While crossing its arms, it lets out a shout that would make any opponent flinch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (863, 'Perrserker', 'Steel', null, 70, 110, 100, 50, 60, 50, 8.00, 280.00, 'After many battles, it evolved dangerous claws that come together to form daggers when extended.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (864, 'Cursola', 'Ghost', null, 60, 95, 50, 145, 130, 30, 10.00, 4.00, 'Be cautious of the ectoplasmic body surrounding its soul. You’ll become stiff as stone if you touch it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (865, 'Sirfetch\'d', 'Fighting', null, 62, 135, 95, 68, 82, 65, 8.00, 1170.00, 'After deflecting attacks with its hard leaf shield, it strikes back with its sharp leek stalk. The leek stalk is both weapon and food.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (866, 'Mr. Rime', 'Ice', 'Psychic', 80, 85, 75, 110, 100, 70, 15.00, 582.00, 'Its amusing movements make it very popular. It releases its psychic power from the pattern on its belly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (867, 'Runerigus', 'Ground', 'Ghost', 58, 95, 145, 50, 105, 30, 16.00, 666.00, 'Never touch its shadowlike body, or you’ll be shown the horrific memories behind the picture carved into it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (868, 'Milcery', 'Fairy', null, 45, 40, 40, 50, 61, 34, 2.00, 3.00, 'They say that any patisserie visited by Milcery is guaranteed success and good fortune.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (869, 'Alcremie', 'Fairy', null, 65, 60, 75, 110, 121, 64, 3.00, 5.00, 'Alcremie that have been cherished produce exquisite cream, so Trainers always raise them lovingly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (870, 'Falinks', 'Fighting', null, 65, 100, 100, 70, 60, 75, 30.00, 620.00, 'The leader, known as the brass, uses its extendible horn to issue orders to the others when it’s time to change formation.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (871, 'Pincurchin', 'Electric', null, 48, 101, 95, 91, 85, 15, 3.00, 10.00, 'This Pokémon is so timid that even brushing against seaweed will make it discharge electricity in surprise. Its lips do not conduct electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (872, 'Snom', 'Ice', 'Bug', 30, 25, 35, 45, 30, 20, 3.00, 38.00, 'Within its internal organs, Snom amplifies the frigid air it gets from eating snow and then uses this amplified air to create icicle-like spikes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (873, 'Frosmoth', 'Ice', 'Bug', 70, 65, 60, 125, 90, 65, 13.00, 420.00, 'It causes blizzards as it flies around with its huge, chill-emanating wings. Clean meltwater is its favorite thing to drink.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (874, 'Stonjourner', 'Rock', null, 100, 125, 135, 20, 20, 70, 25.00, 5200.00, 'This Pokémon spends its life gazing at the setting sun. It strides leisurely across grassy plains on legs of rock that weigh over 400 pounds each.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (875, 'Eiscue', 'Ice', null, 75, 80, 110, 65, 90, 50, 14.00, 890.00, 'If you lick the ice covering its face, you’ll find it has a faintly salty taste. This species rode here on ocean currents from a cold, faraway land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (876, 'Indeedee', 'Psychic', 'Normal', 60, 65, 55, 105, 95, 95, 9.00, 280.00, 'This Pokémon never leaves its Trainer’s side. It predicts their actions with its psychic power and takes care of their day-to-day needs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (877, 'Morpeko', 'Electric', 'Dark', 58, 95, 58, 70, 58, 97, 3.00, 30.00, 'It carries electrically roasted seeds with it as if they’re precious treasures. No matter how much it eats, it always gets hungry again in short order.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (878, 'Cufant', 'Steel', null, 72, 80, 49, 40, 49, 40, 12.00, 1000.00, 'Cufant can lift loads weighing five tons. In the mornings, it heads into caves with its herd, in search of the ore on which these Pokémon feed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (879, 'Copperajah', 'Steel', null, 122, 130, 69, 80, 69, 30, 30.00, 6500.00, 'Copperajah are prideful, cantankerous Pokémon. Specimens with vibrant green skin command the respect of others of their kind.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (880, 'Dracozolt', 'Electric', 'Dragon', 90, 100, 90, 80, 70, 75, 18.00, 1900.00, 'The powerful muscles in its tail generate its electricity. Compared to its lower body, its upper half is entirely too small.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (881, 'Arctozolt', 'Electric', 'Ice', 90, 100, 90, 90, 80, 55, 23.00, 1500.00, 'This Pokémon lived on prehistoric seashores and was able to preserve food with the ice on its body. It went extinct because it moved so slowly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (882, 'Dracovish', 'Water', 'Dragon', 90, 90, 100, 70, 80, 75, 23.00, 2150.00, 'Its mighty legs are capable of running at speeds exceeding 40 mph, but this Pokémon can’t breathe unless it’s underwater.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (883, 'Arctovish', 'Water', 'Ice', 90, 90, 100, 80, 90, 55, 20.00, 1750.00, 'The skin on its face is impervious to attack, but breathing difficulties made this Pokémon go extinct anyway.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (884, 'Duraludon', 'Steel', 'Dragon', 70, 95, 115, 120, 50, 85, 18.00, 400.00, 'The special metal that composes its body is very light, so this Pokémon has considerable agility. It lives in caves because it dislikes the rain.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (885, 'Dreepy', 'Dragon', 'Ghost', 28, 60, 30, 40, 30, 82, 5.00, 20.00, 'It has a habit of biting at Clauncher even though it doesn’t feed on them. This is said to be vestigial behavior from when Dreepy was alive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (886, 'Drakloak', 'Dragon', 'Ghost', 68, 80, 50, 60, 50, 102, 14.00, 110.00, 'This Pokémon stores up energy in its lungs, then shoots it out. It takes care of Dreepy and battles alongside them until they’re all grown up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (887, 'Dragapult', 'Dragon', 'Ghost', 88, 120, 75, 100, 75, 142, 30.00, 500.00, 'The fastest Dragapult of the group is always surrounded by Dreepy that want to fly at sonic speed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (888, 'Zacian', 'Fairy', null, 92, 120, 115, 80, 115, 138, 28.00, 1100.00, 'This Pokémon has slumbered for many years. Some say it’s Zamazenta’s elder sister—others say the two Pokémon are rivals.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (889, 'Zamazenta', 'Fighting', null, 92, 120, 115, 80, 115, 138, 29.00, 2100.00, 'This Pokémon slept for aeons while in the form of a statue. It was asleep for so long, people forgot that it ever existed.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (890, 'Eternatus', 'Poison', 'Dragon', 140, 85, 95, 145, 95, 130, 200.00, 9500.00, 'It was inside a meteorite that fell 20,000 years ago. There seems to be a connection between this Pokémon and the Dynamax phenomenon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (891, 'Kubfu', 'Fighting', null, 60, 90, 60, 53, 50, 72, 6.00, 120.00, 'If Kubfu pulls the long white hair on its head, its fighting spirit heightens and power wells up from the depths of its belly.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (892, 'Urshifu', 'Fighting', 'Dark', 100, 130, 100, 63, 60, 97, 19.00, 1050.00, 'Inhabiting the mountains of a distant region, this Pokémon races across sheer cliffs, training its legs and refining its moves.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (893, 'Zarude', 'Dark', 'Grass', 105, 120, 105, 70, 95, 105, 18.00, 700.00, 'Once the vines on Zarude’s body tear off, they become nutrients in the soil. This helps the plants of the forest grow.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (894, 'Regieleki', 'Electric', null, 80, 100, 50, 100, 50, 200, 12.00, 1450.00, 'Its entire body is made up of a single organ that generates electrical energy. Regieleki is capable of creating all Galar’s electricity.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (895, 'Regidrago', 'Dragon', null, 200, 100, 50, 100, 50, 80, 21.00, 2000.00, 'Its body is composed of crystallized dragon energy. Regidrago is said to have the powers of every dragon Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (896, 'Glastrier', 'Ice', null, 100, 145, 130, 65, 110, 30, 22.00, 8000.00, 'Glastrier has tremendous physical strength, and the mask of ice covering its face is 100 times harder than diamond.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (897, 'Spectrier', 'Ghost', null, 100, 65, 60, 145, 80, 130, 20.00, 445.00, 'As it dashes through the night, Spectrier absorbs the life-force of sleeping creatures. It craves silence and solitude.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (898, 'Calyrex', 'Psychic', 'Grass', 100, 80, 80, 80, 80, 80, 11.00, 77.00, 'Calyrex is known in legend as a king that ruled over Galar in ancient times. It has the power to cause hearts to mend and plants to spring forth.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (899, 'Wyrdeer', 'Normal', 'Psychic', 103, 105, 72, 105, 75, 65, 18.00, 951.00, 'The black orbs shine with an uncanny light when the Pokémon is erecting invisible barriers. The fur shed from its beard retains heat well and is a highly useful material for winter clothing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (900, 'Kleavor', 'Bug', 'Rock', 70, 135, 95, 45, 70, 85, 18.00, 890.00, 'A violent creature that fells towering trees with its crude axes and shields itself with hard stone. If one should chance upon this Pokémon in the wilds, one’s only recourse is to flee.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (901, 'Ursaluna', 'Ground', 'Normal', 130, 140, 105, 45, 80, 50, 24.00, 2900.00, 'I believe it was Hisui’s swampy terrain that gave Ursaluna its burly physique and newfound capacity to manipulate peat at will.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (902, 'Basculegion', 'Water', 'Ghost', 120, 112, 65, 80, 75, 78, 30.00, 1100.00, 'Clads itself in the souls of comrades that perished before fulfilling their goals of journeying upstream. No other species throughout all Hisui’s rivers is Basculegion’s equal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (903, 'Sneasler', 'Fighting', 'Poison', 80, 130, 60, 40, 80, 120, 13.00, 430.00, 'Because of Sneasler’s virulent poison and daunting physical prowess, no other species could hope to best it on the frozen highlands. Preferring solitude, this species does not form packs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (904, 'Overqwil', 'Dark', 'Poison', 85, 115, 95, 65, 65, 85, 25.00, 605.00, 'Its lancelike spikes and savage temperament have earned it the nickname “sea fiend.” It slurps up poison to nourish itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (905, 'Enamorus', 'Fairy', 'Flying', 74, 115, 70, 135, 80, 106, 16.00, 480.00, 'When it flies to this land from across the sea, the bitter winter comes to an end. According to legend, this Pokémon’s love gives rise to the budding of fresh life across Hisui.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (906, 'Sprigatito', 'Grass', null, 40, 61, 54, 45, 45, 65, 4.00, 41.00, 'The sweet scent its body gives off mesmerizes those around it. The scent grows stronger when this Pokémon is in the sun.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (907, 'Floragato', 'Grass', null, 61, 80, 63, 60, 63, 83, 9.00, 122.00, 'The hardness of Floragato’s fur depends on the Pokémon’s mood. When Floragato is prepared to battle, its fur becomes pointed and needle sharp.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (908, 'Meowscarada', 'Grass', 'Dark', 76, 110, 70, 81, 70, 123, 15.00, 312.00, 'With skillful misdirection, it rigs foes with pollen-packed flower bombs. Meowscarada sets off the bombs before its foes realize what’s going on.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (909, 'Fuecoco', 'Fire', null, 67, 45, 59, 63, 40, 36, 4.00, 98.00, 'Its flame sac is small, so energy is always leaking out. This energy is released from the dent atop Fuecoco’s head and flickers to and fro.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (910, 'Crocalor', 'Fire', null, 81, 55, 78, 90, 58, 49, 10.00, 307.00, 'The valve in Crocalor’s flame sac is closely connected to its vocal cords. This Pokémon utters a guttural cry as it spews flames every which way.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (911, 'Skeledirge', 'Fire', 'Ghost', 104, 75, 100, 110, 75, 66, 16.00, 3265.00, 'Skeledirge’s gentle singing soothes the souls of all that hear it. It burns its enemies to a crisp with flames of over 5,400 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (912, 'Quaxly', 'Water', null, 55, 65, 45, 50, 45, 50, 5.00, 61.00, 'Its strong legs let it easily swim around in even fast-flowing rivers. It likes to keep things tidy and is prone to overthinking things.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (913, 'Quaxwell', 'Water', null, 70, 85, 65, 65, 60, 65, 12.00, 215.00, 'The hardworking Quaxwell observes people and Pokémon from various regions and incorporates their movements into its own dance routines.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (914, 'Quaquaval', 'Water', 'Fighting', 85, 120, 80, 85, 75, 85, 18.00, 619.00, 'Dancing in ways that evoke far-away places, this Pokémon mesmerizes all that see it. Flourishes of its decorative water feathers slice into its foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (915, 'Lechonk', 'Normal', null, 54, 45, 40, 35, 45, 35, 5.00, 102.00, 'This Pokémon spurns all but the finest of foods. Its body gives off an herblike scent that bug Pokémon detest.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (916, 'Oinkologne', 'Normal', null, 110, 100, 75, 59, 80, 65, 10.00, 1200.00, 'It entrances female Pokémon with the sweet, alluring scent that wafts from all over its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (917, 'Tarountula', 'Bug', null, 35, 41, 45, 29, 40, 20, 3.00, 40.00, 'The thread it secretes from its rear is as strong as wire. The secret behind the thread’s strength is the topic of ongoing research.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (918, 'Spidops', 'Bug', null, 60, 79, 92, 52, 86, 35, 10.00, 165.00, 'Spidops covers its territory in tough, sticky threads to set up traps for intruders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (919, 'Nymble', 'Bug', null, 33, 46, 40, 21, 25, 45, 2.00, 10.00, 'It’s highly skilled at a fighting style in which it uses its jumping capabilities to dodge incoming attacks while also dealing damage to opponents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (920, 'Lokix', 'Bug', 'Dark', 71, 102, 78, 52, 55, 92, 10.00, 175.00, 'It uses its normally folded third set of legs when in Showdown Mode. This places a huge burden on its body, so it can’t stay in this mode for long.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (921, 'Pawmi', 'Electric', null, 45, 50, 20, 40, 25, 60, 3.00, 25.00, 'The pads of its paws are electricity-discharging organs. Pawmi fires electricity from its forepaws while standing unsteadily on its hind legs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (922, 'Pawmo', 'Electric', 'Fighting', 60, 75, 40, 50, 40, 85, 4.00, 65.00, 'Pawmo uses a unique fighting technique in which it uses its forepaws to strike foes and zap them with electricity from its paw pads simultaneously.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (923, 'Pawmot', 'Electric', 'Fighting', 70, 115, 70, 70, 60, 105, 9.00, 410.00, 'Pawmot’s fluffy fur acts as a battery. It can store the same amount of electricity as an electric car.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (924, 'Tandemaus', 'Normal', null, 50, 50, 45, 40, 45, 75, 3.00, 18.00, 'The pair sticks together no matter what. They split any food they find exactly in half and then eat it together.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (925, 'Maushold', 'Normal', null, 74, 75, 70, 65, 75, 111, 3.00, 23.00, 'The larger pair protects the little ones during battles. When facing strong opponents, the whole group will join the fight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (926, 'Fidough', 'Fairy', null, 37, 55, 70, 30, 55, 65, 3.00, 109.00, 'The yeast in Fidough’s breath is useful for cooking, so this Pokémon has been protected by people since long ago.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (927, 'Dachsbun', 'Fairy', null, 57, 80, 115, 50, 80, 95, 5.00, 149.00, 'The surface of this Pokémon’s skin hardens when exposed to intense heat, and its body has an appetizing aroma.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (928, 'Smoliv', 'Grass', 'Normal', 41, 35, 45, 58, 51, 30, 3.00, 65.00, 'This Pokémon converts nutrients into oil, which it stores in the fruit on its head. It can easily go a whole week without eating or drinking.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (929, 'Dolliv', 'Grass', 'Normal', 52, 53, 60, 78, 78, 33, 6.00, 119.00, 'It basks in the sun to its heart’s content until the fruits on its head ripen. After that, Dolliv departs from human settlements and goes on a journey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (930, 'Arboliva', 'Grass', 'Normal', 78, 69, 90, 125, 109, 39, 14.00, 482.00, 'This Pokémon drives back enemies by launching its rich, aromatic oil at them with enough force to smash a boulder.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (931, 'Squawkabilly', 'Normal', 'Flying', 82, 96, 51, 45, 51, 92, 6.00, 24.00, 'Green-feathered flocks hold the most sway. When they’re out searching for food in the mornings and evenings, it gets very noisy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (932, 'Nacli', 'Rock', null, 55, 55, 75, 35, 35, 25, 4.00, 160.00, 'The ground scrapes its body as it travels, causing it to leave salt behind. Salt is constantly being created and replenished inside Nacli’s body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (933, 'Naclstack', 'Rock', null, 60, 60, 100, 35, 65, 35, 6.00, 1050.00, 'It compresses rock salt inside its body and shoots out hardened salt pellets with enough force to perforate an iron sheet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (934, 'Garganacl', 'Rock', null, 100, 100, 130, 45, 90, 35, 23.00, 2400.00, 'Many Pokémon gather around Garganacl, hoping to lick at its mineral-rich salt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (935, 'Charcadet', 'Fire', null, 40, 50, 40, 50, 40, 35, 6.00, 105.00, 'Its firepower increases when it fights, reaching over 1,800 degrees Fahrenheit. It likes berries that are rich in fat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (936, 'Armarouge', 'Fire', 'Psychic', 85, 60, 100, 125, 80, 75, 15.00, 850.00, 'This Pokémon clads itself in armor that has been fortified by psychic and fire energy, and it shoots blazing fireballs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (937, 'Ceruledge', 'Fire', 'Ghost', 75, 125, 80, 60, 100, 85, 16.00, 620.00, 'An old set of armor steeped in grudges caused this Pokémon’s evolution. Ceruledge cuts its enemies to pieces without mercy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (938, 'Tadbulb', 'Electric', null, 61, 31, 41, 59, 35, 45, 3.00, 4.00, 'It floats using the electricity stored in its body. When thunderclouds are around, Tadbulb will float higher off the ground.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (939, 'Bellibolt', 'Electric', null, 109, 64, 91, 103, 83, 45, 12.00, 1130.00, 'What appear to be eyeballs are actually organs for discharging the electricity generated by Bellibolt’s belly-button dynamo.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (940, 'Wattrel', 'Electric', 'Flying', 40, 40, 35, 55, 40, 70, 4.00, 36.00, 'These Pokémon make their nests on coastal cliffs. The nests have a strange, crackling texture, and they’re a popular delicacy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (941, 'Kilowattrel', 'Electric', 'Flying', 70, 70, 60, 105, 60, 125, 14.00, 386.00, 'It uses its throat sac to store electricity generated by its wings. There’s hardly any oil in its feathers, so it is a poor swimmer.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (942, 'Maschiff', 'Dark', null, 60, 78, 60, 40, 51, 51, 5.00, 160.00, 'Its well-developed jaw and fangs are strong enough to crunch through boulders, and its thick fat makes for an excellent defense.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (943, 'Mabosstiff', 'Dark', null, 80, 120, 90, 60, 70, 85, 11.00, 610.00, 'Mabosstiff loves playing with children. Though usually gentle, it takes on an intimidating look when protecting its family.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (944, 'Shroodle', 'Poison', 'Normal', 40, 65, 35, 40, 35, 75, 2.00, 7.00, 'To keep enemies away from its territory, it paints markings around its nest using a poisonous liquid that has an acrid odor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (945, 'Grafaiai', 'Poison', 'Normal', 63, 95, 65, 80, 72, 110, 7.00, 272.00, 'Each Grafaiai paints its own individual pattern, and it will paint that same pattern over and over again throughout its life.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (946, 'Bramblin', 'Grass', 'Ghost', 40, 65, 30, 45, 35, 60, 6.00, 6.00, 'Not even Bramblin knows where it is headed as it tumbles across the wilderness, blown by the wind. It loathes getting wet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (947, 'Brambleghast', 'Grass', 'Ghost', 55, 115, 70, 80, 70, 90, 12.00, 60.00, 'Brambleghast wanders around arid regions. On rare occasions, mass outbreaks of these Pokémon will bury an entire town.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (948, 'Toedscool', 'Ground', 'Grass', 40, 40, 35, 50, 100, 70, 9.00, 330.00, 'Though it looks like Tentacool, Toedscool is a completely different species. Its legs may be thin, but it can run at a speed of 30 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (949, 'Toedscruel', 'Ground', 'Grass', 80, 70, 65, 80, 120, 100, 19.00, 580.00, 'It coils its 10 tentacles around prey and sucks out their nutrients, causing the prey pain. The folds along the rim of its head are a popular delicacy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (950, 'Klawf', 'Rock', null, 70, 100, 115, 35, 55, 75, 13.00, 790.00, 'This Pokémon lives on sheer cliffs. It sidesteps opponents’ attacks, then lunges for their weak spots with its claws.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (951, 'Capsakid', 'Grass', null, 50, 62, 40, 62, 40, 50, 3.00, 30.00, 'Traditional Paldean dishes can be extremely spicy because they include the shed front teeth of Capsakid among their ingredients.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (952, 'Scovillain', 'Grass', 'Fire', 65, 108, 65, 108, 65, 75, 9.00, 150.00, 'The green head has turned vicious due to the spicy chemicals stimulating its brain. Once it goes on a rampage, there is no stopping it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (953, 'Rellor', 'Bug', null, 41, 50, 60, 31, 58, 30, 2.00, 10.00, 'It rolls its mud ball around while the energy it needs for evolution matures. Eventually the time comes for it to evolve.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (954, 'Rabsca', 'Bug', 'Psychic', 75, 50, 85, 115, 100, 45, 3.00, 35.00, 'An infant sleeps inside the ball. Rabsca rolls the ball soothingly with its legs to ensure the infant sleeps comfortably.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (955, 'Flittle', 'Psychic', null, 30, 35, 30, 55, 30, 75, 2.00, 15.00, 'It spends its time running around wastelands. If anyone steals its beloved berries, it will chase them down and exact its revenge.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (956, 'Espathra', 'Psychic', null, 95, 60, 60, 101, 60, 105, 19.00, 900.00, 'It emits psychic power from the gaps between its multicolored frills and sprints at speeds greater than 120 mph.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (957, 'Tinkatink', 'Fairy', 'Steel', 50, 45, 45, 35, 64, 58, 4.00, 89.00, 'This Pokémon pounds iron scraps together to make a hammer. It will remake the hammer again and again until it’s satisfied with the result.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (958, 'Tinkatuff', 'Fairy', 'Steel', 65, 55, 55, 45, 82, 78, 7.00, 591.00, 'These Pokémon make their homes in piles of scrap metal. They test the strength of each other’s hammers by smashing them together.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (959, 'Tinkaton', 'Fairy', 'Steel', 85, 75, 77, 70, 105, 94, 7.00, 1128.00, 'The hammer tops 220 pounds, yet it gets swung around easily by Tinkaton as it steals whatever it pleases and carries its plunder back home.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (960, 'Wiglett', 'Water', null, 10, 55, 25, 35, 25, 95, 12.00, 18.00, 'Though it looks like Diglett, Wiglett is an entirely different species. The resemblance seems to be a coincidental result of environmental adaptation.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (961, 'Wugtrio', 'Water', null, 35, 100, 50, 50, 70, 120, 12.00, 54.00, 'A variety of fish Pokémon, Wugtrio was once considered to be a regional form of Dugtrio.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (962, 'Bombirdier', 'Flying', 'Dark', 70, 103, 85, 60, 85, 82, 15.00, 429.00, 'Bombirdier uses the apron on its chest to bundle up food, which it carries back to its nest. It enjoys dropping things that make loud noises.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (963, 'Finizen', 'Water', null, 70, 45, 40, 45, 40, 75, 13.00, 602.00, 'Its water ring is made from seawater mixed with a sticky fluid that Finizen secretes from its blowhole.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (964, 'Palafin', 'Water', null, 100, 70, 72, 53, 62, 100, 13.00, 602.00, 'Its physical capabilities are no different than a Finizen’s, but when its allies are in danger, it transforms and powers itself up.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (965, 'Varoom', 'Steel', 'Poison', 45, 70, 63, 30, 45, 47, 10.00, 350.00, 'The steel section is Varoom’s actual body. This Pokémon clings to rocks and converts the minerals within into energy to fuel its activities.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (966, 'Revavroom', 'Steel', 'Poison', 80, 119, 90, 54, 67, 90, 18.00, 1200.00, 'Revavroom viciously threatens others with the sound of its exhaust. It sticks its tongue out from its cylindrical mouth and sprays toxic fluids.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (967, 'Cyclizar', 'Dragon', 'Normal', 70, 95, 65, 85, 65, 121, 16.00, 630.00, 'It can sprint at over 70 mph while carrying a human. The rider’s body heat warms Cyclizar’s back and lifts the Pokémon’s spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (968, 'Orthworm', 'Steel', null, 70, 85, 145, 60, 55, 65, 25.00, 3100.00, 'This Pokémon lives in arid deserts. It maintains its metal body by consuming iron from the soil.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (969, 'Glimmet', 'Rock', 'Poison', 48, 35, 42, 105, 60, 60, 7.00, 80.00, 'Glimmet’s toxic mineral crystals look just like flower petals. This Pokémon scatters poisonous powder like pollen to protect itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (970, 'Glimmora', 'Rock', 'Poison', 83, 55, 90, 130, 81, 86, 15.00, 450.00, 'Glimmora’s petals are made of crystallized poison energy. It has recently become evident that these petals resemble Tera Jewels.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (971, 'Greavard', 'Ghost', null, 50, 61, 60, 30, 55, 34, 6.00, 350.00, 'This friendly Pokémon doesn’t like being alone. Pay it even the slightest bit of attention, and it will follow you forever.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (972, 'Houndstone', 'Ghost', null, 72, 101, 100, 50, 97, 68, 20.00, 150.00, 'A lovingly mourned Pokémon was reborn as Houndstone. It doesn’t like anyone touching the protuberance atop its head.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (973, 'Flamigo', 'Flying', 'Fighting', 82, 115, 74, 75, 64, 90, 16.00, 370.00, 'Thanks to a behavior of theirs known as “synchronizing,” an entire flock of these Pokémon can attack simultaneously in perfect harmony.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (974, 'Cetoddle', 'Ice', null, 108, 68, 45, 30, 40, 43, 12.00, 450.00, 'It lives in frigid regions in pods of five or so individuals. It loves the minerals found in snow and ice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (975, 'Cetitan', 'Ice', null, 170, 113, 65, 45, 55, 73, 45.00, 7000.00, 'Ice energy builds up in the horn on its upper jaw, causing the horn to reach cryogenic temperatures that freeze its surroundings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (976, 'Veluza', 'Water', 'Psychic', 90, 102, 73, 78, 65, 70, 25.00, 900.00, 'Veluza has excellent regenerative capabilities. It sheds spare flesh from its body to boost its agility, then charges at its prey.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (977, 'Dondozo', 'Water', null, 150, 100, 115, 65, 65, 35, 120.00, 2200.00, 'It treats Tatsugiri like its boss and follows it loyally. Though powerful, Dondozo is apparently not very smart.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (978, 'Tatsugiri', 'Dragon', 'Water', 68, 50, 60, 120, 95, 82, 3.00, 80.00, 'Tatsugiri is an extremely cunning Pokémon. It feigns weakness to lure in prey, then orders its partner to attack.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (979, 'Annihilape', 'Fighting', 'Ghost', 110, 115, 80, 50, 90, 90, 12.00, 560.00, 'It imbues its fists with the power of the rage that it kept hidden in its heart. Opponents struck by these imbued fists will be shattered to their core.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (980, 'Clodsire', 'Poison', 'Ground', 130, 75, 60, 45, 100, 20, 18.00, 2230.00, 'It lives at the bottom of ponds and swamps. It will carry Wooper on its back and ferry them across water from one shore to the other.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (981, 'Farigiraf', 'Normal', 'Psychic', 120, 90, 70, 110, 70, 60, 32.00, 1600.00, 'The hardened head from the tail protects the head of the main body as Farigiraf whips its long neck around to headbutt enemies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (982, 'Dudunsparce', 'Normal', null, 125, 100, 80, 85, 75, 55, 36.00, 392.00, 'It drives enemies out of its nest by sucking in enough air to fill its long, narrow lungs, then releasing the air in an intense blast.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (983, 'Kingambit', 'Dark', 'Steel', 100, 135, 120, 60, 85, 50, 20.00, 1200.00, 'Though it commands a massive army in battle, it’s not skilled at devising complex strategies. It just uses brute strength to keep pushing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (984, 'Great Tusk', 'Ground', 'Fighting', 115, 131, 131, 53, 53, 87, 22.00, 3200.00, 'This creature resembles a mysterious Pokémon that, according to a paranormal magazine, has lived since ancient times.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (985, 'Scream Tail', 'Fairy', 'Psychic', 115, 65, 99, 65, 115, 111, 12.00, 80.00, 'It resembles a mysterious Pokémon described in a paranormal magazine as a Jigglypuff from one billion years ago.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (986, 'Brute Bonnet', 'Grass', 'Dark', 111, 127, 99, 79, 99, 55, 12.00, 210.00, 'It bears a slight resemblance to a Pokémon described in a dubious magazine as a cross between a dinosaur and a mushroom.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (987, 'Flutter Mane', 'Ghost', 'Fairy', 55, 55, 55, 135, 135, 135, 14.00, 40.00, 'It has similar features to a ghostly pterosaur that was covered in a paranormal magazine, but the two have little else in common.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (988, 'Slither Wing', 'Bug', 'Fighting', 85, 135, 79, 85, 105, 81, 32.00, 920.00, 'This Pokémon somewhat resembles an ancient form of Volcarona that was introduced in a dubious magazine.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (989, 'Sandy Shocks', 'Electric', 'Ground', 85, 81, 97, 121, 85, 101, 23.00, 600.00, 'It slightly resembles a Magneton that lived for 10,000 years and was featured in an article in a paranormal magazine.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (990, 'Iron Treads', 'Ground', 'Steel', 90, 112, 120, 72, 70, 106, 9.00, 2400.00, 'Sightings of this Pokémon have occurred in recent years. It resembles a mysterious object described in an old expedition journal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (991, 'Iron Bundle', 'Ice', 'Water', 56, 80, 114, 124, 60, 136, 6.00, 110.00, 'It resembles a mysterious object mentioned in an old book. There are only two reported sightings of this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (992, 'Iron Hands', 'Fighting', 'Electric', 154, 140, 108, 50, 68, 50, 18.00, 3807.00, 'This Pokémon shares many similarities with Iron Hands, an object mentioned in a certain expedition journal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (993, 'Iron Jugulis', 'Dark', 'Flying', 94, 80, 86, 122, 80, 108, 13.00, 1110.00, 'It’s possible that Iron Jugulis, an object described in an old book, may actually be this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (994, 'Iron Moth', 'Fire', 'Poison', 80, 70, 60, 140, 110, 110, 12.00, 360.00, 'No records exist of this species being caught. Data is lacking, but the Pokémon’s traits match up with an object described in an old book.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (995, 'Iron Thorns', 'Rock', 'Electric', 100, 134, 110, 70, 84, 72, 16.00, 3030.00, 'Some of its notable features match those of an object named within a certain expedition journal as Iron Thorns.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (996, 'Frigibax', 'Dragon', 'Ice', 65, 75, 45, 35, 45, 55, 5.00, 170.00, 'This Pokémon lives in forests and craggy areas. Using the power of its dorsal fin, it cools the inside of its nest like a refrigerator.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (997, 'Arctibax', 'Dragon', 'Ice', 90, 95, 66, 45, 65, 62, 8.00, 300.00, 'It attacks with the blade of its frozen dorsal fin by doing a front flip in the air. Arctibax’s strong back and legs allow it to pull off this technique.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (998, 'Baxcalibur', 'Dragon', 'Ice', 115, 145, 92, 75, 86, 87, 21.00, 2100.00, 'It launches itself into battle by flipping upside down and spewing frigid air from its mouth. It finishes opponents off with its dorsal blade.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (999, 'Gimmighoul', 'Ghost', null, 45, 30, 70, 75, 70, 10, 3.00, 50.00, 'It lives inside an old treasure chest. Sometimes it gets left in shop corners since no one realizes it’s actually a Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1000, 'Gholdengo', 'Steel', 'Ghost', 87, 60, 95, 133, 91, 84, 12.00, 300.00, 'It has a sturdy body made up of stacked coins. Gholdengo overwhelms its enemies by firing coin after coin at them in quick succession.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1001, 'Wo-Chien', 'Dark', 'Grass', 85, 85, 100, 95, 135, 70, 15.00, 742.00, 'It drains the life-force from vegetation, causing nearby forests to instantly wither and fields to turn barren.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1002, 'Chien-Pao', 'Dark', 'Ice', 80, 120, 80, 90, 65, 135, 19.00, 1522.00, 'The hatred of those who perished by the sword long ago has clad itself in snow and become a Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1003, 'Ting-Lu', 'Dark', 'Ground', 155, 110, 125, 55, 80, 45, 27.00, 6997.00, 'It slowly brings its exceedingly heavy head down upon the ground, splitting the earth open with huge fissures that run over 160 feet deep.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1004, 'Chi-Yu', 'Dark', 'Fire', 55, 80, 80, 135, 120, 100, 4.00, 49.00, 'The envy accumulated within curved beads that sparked multiple conflicts has clad itself in fire and become a Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1005, 'Roaring Moon', 'Dragon', 'Dark', 105, 139, 71, 55, 101, 119, 20.00, 3800.00, 'According to an article in a dubious magazine, this Pokémon has some connection to a phenomenon that occurs in a certain region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1006, 'Iron Valiant', 'Fairy', 'Fighting', 74, 130, 90, 120, 60, 116, 14.00, 350.00, 'It’s possible that this is the object listed as Iron Valiant in a certain expedition journal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1007, 'Koraidon', 'Fighting', 'Dragon', 100, 135, 115, 85, 100, 135, 25.00, 3030.00, 'This Pokémon resembles Cyclizar, but it is far burlier and more ferocious. Nothing is known about its ecology or other features.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1008, 'Miraidon', 'Electric', 'Dragon', 100, 85, 100, 135, 115, 135, 35.00, 2400.00, 'This seems to be the Iron Serpent mentioned in an old book. The Iron Serpent is said to have turned the land to ash with its lightning.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1009, 'Walking Wake', 'Water', 'Dragon', 99, 83, 91, 125, 83, 109, 35.00, 2800.00, 'It resembles an illustration published in a paranormal magazine, said to be a depiction of a super-ancient Suicune.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1010, 'Iron Leaves', 'Grass', 'Psychic', 90, 130, 88, 70, 108, 104, 15.00, 1250.00, 'According to the few eyewitness accounts that exist, it used its shining blades to julienne large trees and boulders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1011, 'Dipplin', 'Grass', 'Dragon', 80, 80, 110, 95, 80, 40, 4.00, 44.00, 'The head and tail appear to belong to two separate creatures; both help each other out from within their shared apple. Dipplin coat their apples with syrup produced within their bodies. The layers of fragrant syrup beguile opponents.​', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1012, 'Poltchageist', 'Grass', 'Ghost', 40, 45, 45, 73, 54, 50, 1.00, 11.00, 'Poltchageist has a swirl pattern not unlike Sinistea\'s - but unlike Sinistea, its swirl is not a weakness. After a target is sprinkled with some of Poltchageist\'s powdery body or eats food dusted with it, Poltchageist drains their life-force and absorbs it as energy.​', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1013, 'Sinistcha', 'Grass', 'Ghost', 71, 60, 106, 121, 80, 70, 2.00, 22.00, 'It prefers cool, dark places, such as the back of a shelf or the space beneath a home\'s floorboards. It wanders in search of prey after sunset.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1014, 'Okidogi', 'Poison', 'Fighting', 88, 128, 115, 58, 86, 80, 18.00, 920.00, 'Okidogi is a ruffian with a short temper. It can pulverize anything by swinging around the chain on its neck.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1015, 'Munkidori', 'Poison', 'Psychic', 88, 75, 66, 130, 90, 106, 10.00, 122.00, 'Munkidori keeps itself somewhere safe while it toys with its foes, using psychokinesis to induce intense dizziness.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1016, 'Fezandipiti', 'Poison', 'Fairy', 88, 91, 82, 70, 125, 99, 14.00, 301.00, 'Fezandipiti beats its glossy wings to scatter pheromones that captivate people and Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1017, 'Ogerpon', 'Grass', null, 80, 120, 84, 60, 96, 110, 12.00, 398.00, 'This mischief-loving Pokémon is full of curiosity. It battles by drawing out the type-based energy contained within its masks.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1018, 'Archaludon', 'Steel', 'Dragon', 90, 105, 130, 125, 65, 85, 20.00, 600.00, 'It digs holes on mountains, searching for food. It’s so durable that being caught in a cave-in won’t faze it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1019, 'Hydrapple', 'Grass', 'Dragon', 106, 80, 110, 120, 80, 44, 18.00, 930.00, 'These capricious syrpents have banded together. On the rare occasion that their moods align, their true power is unleashed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1020, 'Gouging Fire', 'Fire', 'Dragon', 105, 115, 121, 65, 93, 91, 35.00, 5900.00, 'It resembles an eerie Pokémon once shown in a paranormal magazine. That Pokémon was said to be an Entei regenerated from a fossil.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1021, 'Raging Bolt', 'Electric', 'Dragon', 125, 73, 91, 137, 89, 75, 52.00, 4800.00, 'It bears resemblance to a Pokémon that became a hot topic for a short while after a paranormal magazine touted it as Raikou\'s ancestor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1022, 'Iron Boulder', 'Rock', 'Psychic', 90, 120, 80, 68, 108, 124, 15.00, 1625.00, 'It was named after a mysterious object recorded in an old book. Its body seems to be metallic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1023, 'Iron Crown', 'Steel', 'Psychic', 90, 72, 100, 122, 108, 98, 16.00, 1560.00, 'There was supposedly an incident in which it launched shining blades to cut everything around it to pieces. Little else is known about it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1024, 'Terapagos', 'Normal', null, 90, 65, 85, 65, 85, 60, 2.00, 65.00, 'It’s thought that this Pokémon lived in ancient Paldea until it got caught in seismic shifts and went extinct.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (1025, 'Pecharunt', 'Poison', 'Ghost', 88, 88, 160, 88, 88, 88, 3.00, 3.00, 'Its peach-shaped shell serves as storage for a potent poison. It makes poisonous mochi and serves them to people and Pokémon.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10001, 'Attack Deoxys', 'Psychic', null, 50, 180, 20, 180, 20, 150, 17.00, 608.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10002, 'Defense Deoxys', 'Psychic', null, 50, 70, 160, 70, 160, 90, 17.00, 608.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10003, 'Speed Deoxys', 'Psychic', null, 50, 95, 90, 95, 90, 180, 17.00, 608.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10004, 'Sandy Wormadam', 'Bug', 'Ground', 60, 79, 105, 59, 85, 36, 5.00, 65.00, 'Its earthen skin is reasonably hard—it has no problem repelling a Starly’s pecking, at least.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10005, 'Trash Wormadam', 'Bug', 'Steel', 60, 69, 95, 69, 95, 36, 5.00, 65.00, 'Its body, composed of refuse, blends in to the scenery so much as to be inconspicuous. This seems to be the perfect way for the Pokémon to evade the detection of predators.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10006, 'Sky Shaymin', 'Grass', 'Flying', 100, 103, 75, 120, 75, 127, 4.00, 52.00, 'Upon taking in the scent of a particular rare flower, Shaymin is enveloped in light, and its tiny body transforms. I took a whiff of the flower myself, but alas, my body remained unchanged.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10007, 'Origin Giratina', 'Ghost', 'Dragon', 150, 120, 100, 120, 100, 90, 69.00, 6500.00, 'Giratina loses its legs upon changing into this form. I believe this Pokémon must hail from a world where the heavens and the earth are as one, though I have no way of proving it.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10008, 'Heat Rotom', 'Electric', 'Fire', 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'This Rotom has possessed a convection microwave oven. It will sear the surrounding area with its burning heat, then smile in delight.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10009, 'Wash Rotom', 'Electric', 'Water', 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'The model of washing machine that Rotom can inspirit has been discontinued, so these appliances are now traded at high prices.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10010, 'Frost Rotom', 'Electric', 'Ice', 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'The special motor within the refrigerator is the key to bringing about Rotom’s change in form.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10011, 'Fan Rotom', 'Electric', 'Flying', 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'There are several appliances that Rotom can inspirit, but the first one to be developed was the electric fan.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10012, 'Mow Rotom', 'Electric', 'Grass', 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'This Rotom has possessed a lawn mower. It will mow down grass and flowers, then swagger around with pride at its accomplishments.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10013, 'Sunny Castform', 'Fire', null, 70, 70, 70, 70, 70, 70, 3.00, 8.00, 'Castform changes to this form when it basks in bright sunlight. When you touch its glowing skin, it feels all dried out!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10014, 'Rainy Castform', 'Water', null, 70, 70, 70, 70, 70, 70, 3.00, 8.00, 'This is Castform’s form when pelted by rain. In an experiment where it was placed in a shower, this Pokémon didn’t change to this form.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10015, 'Snowy Castform', 'Ice', null, 70, 70, 70, 70, 70, 70, 3.00, 8.00, 'This is Castform’s form when caught in a hailstorm. Its whole body is chilled, and its skin is partially frozen!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10016, 'Blue-Striped Basculin', 'Water', null, 70, 92, 65, 80, 55, 98, 10.00, 180.00, 'The power of its jaws is immense—enough to leave teeth marks in iron sheets. Its personality is also extremely vicious.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10017, 'Zen Darmanitan', 'Fire', 'Psychic', 105, 30, 105, 140, 105, 55, 13.00, 929.00, 'When wounded, it stops moving. It goes as still as stone to meditate, sharpening its mind and spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10018, 'Pirouette Meloetta', 'Normal', 'Fighting', 100, 128, 90, 77, 77, 128, 6.00, 65.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10019, 'Therian Tornadus', 'Flying', null, 79, 100, 80, 110, 90, 121, 14.00, 630.00, 'An example of what is known as a “form change,” though I suspect this strange avian guise to be Tornadus’s true form. Tornadus has been sighted crossing the ocean while in this form.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10020, 'Therian Thundurus', 'Electric', 'Flying', 79, 105, 70, 145, 80, 101, 30.00, 610.00, 'Quick as a flash, it materializes out of nowhere. It pulverizes foes into nothingness with showers of devastatingly powerful lightning bolts launched from the string of orbs on its tail.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10021, 'Therian Landorus', 'Ground', 'Flying', 89, 145, 90, 105, 80, 91, 13.00, 680.00, 'Landorus soars through the sky in this form, bestowing plentiful harvests upon the land and earning the people’s reverence. It can traverse the whole of Hisui in a mere couple of hours.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10022, 'Black Kyurem', 'Dragon', 'Ice', 125, 170, 100, 120, 90, 95, 33.00, 3250.00, 'The sameness of Zekrom’s and Kyurem’s genes allowed Kyurem to absorb Zekrom. Kyurem can now use the power of both electricity and ice.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10023, 'White Kyurem', 'Dragon', 'Ice', 125, 120, 90, 170, 100, 95, 36.00, 3250.00, 'It has foreseen that a world of truth will arrive for people and Pokémon. It strives to protect that future.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10024, 'Resolute Keldeo', 'Water', 'Fighting', 91, 72, 90, 129, 90, 108, 14.00, 485.00, 'The power that lay hidden in its body now covers its horn, turning it into a sword that can slice through anything.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10025, 'Female Meowstic', 'Psychic', null, 74, 48, 76, 83, 81, 104, 6.00, 85.00, 'If it doesn’t hold back when it unleashes its psychic power, it can tear apart a tanker. Its unfriendliness is part of its charm.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10026, 'Blade Aegislash', 'Steel', 'Ghost', 60, 150, 50, 150, 50, 60, 17.00, 530.00, 'Once upon a time, a king with an Aegislash reigned over the land. His Pokémon eventually drained him of life, and his kingdom fell with him.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10027, 'Small Pumpkaboo', 'Ghost', 'Grass', 44, 66, 70, 44, 55, 56, 3.00, 35.00, 'Small Pumpkaboo are said to be the product of areas where few lost souls lingered.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10028, 'Large Pumpkaboo', 'Ghost', 'Grass', 54, 66, 70, 44, 55, 46, 5.00, 75.00, 'Large Pumpkaboo are said to be the product of areas where many lost souls lingered.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10029, 'Super Pumpkaboo', 'Ghost', 'Grass', 59, 66, 70, 44, 55, 41, 8.00, 150.00, 'Massive Pumpkaboo are said to be the product of areas where a great number of lost souls lingered.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10030, 'Small Gourgeist', 'Ghost', 'Grass', 55, 85, 122, 58, 75, 99, 7.00, 95.00, 'A small-sized Pumpkaboo evolves into a small-sized Gourgeist. Its bodily proportions also get passed on to its descendants.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10031, 'Large Gourgeist', 'Ghost', 'Grass', 75, 95, 122, 58, 75, 69, 11.00, 140.00, 'A large-sized Pumpkaboo evolves into a large-sized Gourgeist. Its bodily proportions also get passed on to its descendants.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10032, 'Super Gourgeist', 'Ghost', 'Grass', 85, 100, 122, 58, 75, 54, 17.00, 390.00, 'A supersized Pumpkaboo evolves into a supersized Gourgeist. Its bodily proportions also get passed on to its descendants.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10033, 'Mega Venusaur', 'Grass', 'Poison', 80, 100, 123, 122, 120, 80, 24.00, 1555.00, 'In order to support its flower, which has grown larger due to Mega Evolution, its back and legs have become stronger.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10034, 'Mega Charizard X', 'Fire', 'Dragon', 78, 130, 111, 130, 85, 100, 17.00, 1105.00, 'The overwhelming power that fills its entire body causes it to turn black and create intense blue flames.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10035, 'Mega Charizard Y', 'Fire', 'Flying', 78, 104, 78, 159, 115, 100, 17.00, 1005.00, 'Its bond with its Trainer is the source of its power. It boasts speed and maneuverability greater than that of a jet fighter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10036, 'Mega Blastoise', 'Water', null, 79, 103, 120, 135, 115, 78, 16.00, 1011.00, 'The cannon on its back is as powerful as a tank gun. Its tough legs and back enable it to withstand the recoil from firing the cannon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10037, 'Mega Alakazam', 'Psychic', null, 55, 50, 65, 175, 105, 150, 12.00, 480.00, 'It’s adept at precognition. When attacks completely miss Alakazam, that’s because it’s seeing the future.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10038, 'Mega Gengar', 'Ghost', 'Poison', 60, 65, 80, 170, 95, 130, 14.00, 405.00, 'It can pass through other dimensions and can appear anywhere. It caused a stir one time when it stuck just one leg out of a wall.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10039, 'Mega Kangaskhan', 'Normal', null, 105, 125, 100, 60, 100, 100, 22.00, 1000.00, 'Its child has grown rapidly, thanks to the energy of Mega Evolution. Mother and child show their harmonious teamwork in battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10040, 'Mega Pinsir', 'Bug', 'Flying', 65, 155, 120, 65, 90, 105, 17.00, 590.00, 'With its vaunted horns, it can lift an opponent 10 times heavier than itself and fly about with ease.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10041, 'Mega Gyarados', 'Water', 'Dark', 95, 155, 109, 70, 130, 81, 65.00, 3050.00, 'Although it obeys its instinctive drive to destroy everything within its reach, it will respond to orders from a Trainer it truly trusts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10042, 'Mega Aerodactyl', 'Rock', 'Flying', 80, 135, 85, 70, 95, 150, 21.00, 790.00, 'The power of Mega Evolution has completely restored its genes. The rocks on its body are harder than diamond.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10043, 'Mega Mewtwo X', 'Psychic', 'Fighting', 106, 190, 100, 154, 100, 130, 23.00, 1270.00, 'Psychic power has augmented its muscles. It has a grip strength of one ton and can sprint a hundred meters in two seconds flat!', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10044, 'Mega Mewtwo Y', 'Psychic', null, 106, 150, 70, 194, 120, 140, 15.00, 330.00, 'Despite its diminished size, its mental power has grown phenomenally. With a mere thought, it can smash a skyscraper to smithereens.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10045, 'Mega Ampharos', 'Electric', 'Dragon', 90, 95, 105, 165, 110, 45, 14.00, 615.00, 'Massive amounts of energy intensely stimulated Ampharos’s cells, apparently awakening its long-sleeping dragon’s blood.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10046, 'Mega Scizor', 'Bug', 'Steel', 70, 150, 140, 65, 100, 75, 20.00, 1250.00, 'It’s better at beating things than grasping them. When it battles for a long time, the weight of its pincers becomes too much to bear.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10047, 'Mega Heracross', 'Bug', 'Fighting', 80, 185, 115, 40, 105, 75, 17.00, 625.00, 'A tremendous influx of energy builds it up, but when Mega Evolution ends, Heracross is bothered by terrible soreness in its muscles.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10048, 'Mega Houndoom', 'Dark', 'Fire', 75, 90, 90, 140, 90, 115, 19.00, 495.00, 'Houndoom’s entire body generates heat when it Mega Evolves. Its fearsome fiery breath turns its opponents to ash.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10049, 'Mega Tyranitar', 'Rock', 'Dark', 100, 164, 150, 95, 120, 71, 25.00, 2550.00, 'The effects of Mega Evolution make it more ferocious than ever. It’s unclear whether it can even hear its Trainer’s orders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10050, 'Mega Blaziken', 'Fire', 'Fighting', 80, 160, 80, 130, 80, 100, 19.00, 520.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10051, 'Mega Gardevoir', 'Psychic', 'Fairy', 68, 85, 65, 165, 135, 100, 16.00, 484.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10052, 'Mega Mawile', 'Steel', 'Fairy', 50, 105, 125, 55, 95, 50, 10.00, 235.00, 'Its two sets of jaws thrash about violently as if they each had a will of their own. One gnash from them can turn a boulder to dust.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10053, 'Mega Aggron', 'Steel', null, 70, 140, 230, 60, 80, 50, 22.00, 3950.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10054, 'Mega Medicham', 'Fighting', 'Psychic', 60, 100, 85, 80, 85, 100, 13.00, 315.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10055, 'Mega Manectric', 'Electric', null, 70, 75, 80, 135, 80, 135, 18.00, 440.00, 'Too much electricity has built up in its body, irritating Manectric. Its explosive speed is equal to that of a lightning bolt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10056, 'Mega Banette', 'Ghost', null, 64, 165, 75, 93, 83, 75, 12.00, 130.00, 'Mega Evolution increases its vindictiveness, and the cursing power that was held back by its zipper comes spilling out.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10057, 'Mega Absol', 'Dark', null, 65, 150, 60, 115, 60, 115, 12.00, 490.00, 'It converts the energy from Mega Evolution into an intimidating aura. Fainthearted people expire from shock at the sight of it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10058, 'Mega Garchomp', 'Dragon', 'Ground', 108, 170, 115, 120, 95, 92, 19.00, 950.00, 'Its disposition is more vicious than before its Mega Evolution. Garchomp carves its opponents up with the scythes on both arms.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10059, 'Mega Lucario', 'Fighting', 'Steel', 70, 145, 88, 140, 70, 112, 13.00, 575.00, 'Bathed in explosive energy, its combative instincts have awakened. For its enemies, it has no mercy whatsoever.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10060, 'Mega Abomasnow', 'Grass', 'Ice', 90, 132, 105, 132, 105, 30, 27.00, 1850.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10061, 'Eternal Floette', 'Fairy', null, 74, 65, 67, 125, 128, 92, 2.00, 9.00, 'Terrifying energy is concealed within its ominous flower, but Floette still swings it about innocently.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10062, 'Mega Latias', 'Dragon', 'Psychic', 80, 100, 120, 140, 150, 110, 18.00, 520.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10063, 'Mega Latios', 'Dragon', 'Psychic', 80, 130, 100, 160, 120, 110, 23.00, 700.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10064, 'Mega Swampert', 'Water', 'Ground', 100, 150, 110, 95, 110, 70, 19.00, 1020.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10065, 'Mega Sceptile', 'Grass', 'Dragon', 70, 110, 75, 145, 85, 145, 19.00, 552.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10066, 'Mega Sableye', 'Dark', 'Ghost', 50, 85, 125, 85, 115, 20, 5.00, 1610.00, 'It blocks any and all attacks with its giant-sized gemstone. However, the stone’s a heavy burden, and it limits Mega Sableye’s movements.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10067, 'Mega Altaria', 'Dragon', 'Fairy', 75, 110, 110, 110, 105, 80, 15.00, 206.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10068, 'Mega Gallade', 'Psychic', 'Fighting', 68, 165, 95, 65, 115, 110, 16.00, 564.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10069, 'Mega Audino', 'Normal', 'Fairy', 103, 60, 126, 80, 126, 50, 15.00, 320.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10070, 'Mega Sharpedo', 'Water', 'Dark', 70, 140, 70, 110, 65, 105, 25.00, 1303.00, 'The moment it charges into its opponent, sharp spikes pop out of Sharpedo’s head, leaving its opponent with deep wounds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10071, 'Mega Slowbro', 'Water', 'Psychic', 95, 75, 180, 130, 80, 30, 20.00, 1200.00, 'Under the influence of Shellder’s digestive fluids, Slowpoke has awakened, gaining a great deal of power—and a little motivation to boot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10072, 'Mega Steelix', 'Steel', 'Ground', 75, 125, 230, 55, 95, 30, 105.00, 7400.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10073, 'Mega Pidgeot', 'Normal', 'Flying', 83, 80, 80, 135, 80, 121, 22.00, 505.00, 'With its muscular strength now greatly increased, it can fly continuously for two weeks without resting.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10074, 'Mega Glalie', 'Ice', null, 80, 120, 80, 120, 80, 100, 21.00, 3502.00, 'The power of Mega Evolution was so strong that it smashed Glalie’s jaw. Its inability to eat very well leaves Glalie irritated.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10075, 'Mega Diancie', 'Rock', 'Fairy', 50, 160, 110, 160, 110, 110, 11.00, 278.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10076, 'Mega Metagross', 'Steel', 'Psychic', 80, 145, 150, 105, 110, 110, 25.00, 9429.00, 'When it knows it can’t win, it digs the claws on its legs into its opponent and starts the countdown to a big explosion.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10077, 'Primal Kyogre', 'Water', null, 100, 150, 90, 180, 160, 90, 98.00, 4300.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10078, 'Primal Groudon', 'Ground', 'Fire', 100, 180, 160, 150, 90, 90, 50.00, 9997.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10079, 'Mega Rayquaza', 'Dragon', 'Flying', 105, 180, 100, 180, 100, 115, 108.00, 3920.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10080, 'Pikachu Rock Star', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10081, 'Pikachu Belle', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10082, 'Pikachu Pop Star', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10083, 'Pikachu Ph.D.', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10084, 'Pikachu Libre', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10085, 'Cosplay Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10086, 'Hoopa Unbound', 'Psychic', 'Dark', 80, 160, 60, 170, 130, 80, 65.00, 4900.00, '', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10087, 'Mega Camerupt', 'Fire', 'Ground', 70, 120, 100, 145, 105, 20, 25.00, 3205.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10088, 'Mega Lopunny', 'Normal', 'Fighting', 65, 136, 94, 54, 96, 135, 13.00, 283.00, 'Mega Evolution awakens its combative instincts. It has shed any fur that got in the way of its attacks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10089, 'Mega Salamence', 'Dragon', 'Flying', 95, 145, 130, 120, 90, 120, 18.00, 1126.00, 'It puts its forelegs inside its shell to streamline itself for flight. Salamence flies at high speeds over all kinds of topographical features.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10090, 'Mega Beedrill', 'Bug', 'Poison', 65, 150, 40, 15, 80, 145, 14.00, 405.00, 'Its legs have become poison stingers. It stabs its prey repeatedly with the stingers on its limbs, dealing the final blow with the stinger on its rear.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10091, 'Alolan Rattata', 'Dark', 'Normal', 30, 56, 35, 25, 35, 72, 3.00, 38.00, 'Its whiskers provide it with a keen sense of smell, enabling it to pick up the scent of hidden food and locate it instantly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10092, 'Alolan Raticate', 'Dark', 'Normal', 75, 71, 70, 40, 80, 77, 7.00, 255.00, 'It makes its Rattata underlings gather food for it, dining solely on the most nutritious and delicious fare.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10093, 'Totem Alolan Raticate', 'Dark', 'Normal', 75, 71, 70, 40, 80, 77, 14.00, 1050.00, 'It makes its Rattata underlings gather food for it, dining solely on the most nutritious and delicious fare.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10094, 'Original Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu is wearing its Trainer’s cap. Since the cap’s not the right size, the fit is a bit loose.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10095, 'Hoenn Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the Hoenn region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10096, 'Sinnoh Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the Sinnoh region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10097, 'Unova Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the Unova region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10098, 'Kalos Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the Kalos region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10099, 'Alola Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the Alola region.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10100, 'Alolan Raichu', 'Electric', 'Psychic', 60, 85, 50, 95, 85, 110, 7.00, 210.00, 'This Pokémon rides on its tail while it uses its psychic powers to levitate. It attacks with star-shaped thunderbolts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10101, 'Alolan Sandshrew', 'Ice', 'Steel', 50, 75, 90, 10, 35, 40, 7.00, 400.00, 'It lives in snowy mountains on southern islands. When a blizzard rolls in, this Pokémon hunkers down in the snow to avoid getting blown away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10102, 'Alolan Sandslash', 'Ice', 'Steel', 75, 100, 120, 25, 65, 65, 12.00, 550.00, 'Many people climb snowy mountains, hoping to see the icy spikes of these Pokémon glistening in the light of dawn.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10103, 'Alolan Vulpix', 'Ice', null, 38, 41, 40, 50, 65, 65, 6.00, 99.00, 'These Pokémon live in packs in the snowy mountains and defend themselves with icy breath. I suspect this species changed its form to adapt to the frigid climate.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10104, 'Alolan Ninetales', 'Ice', 'Fairy', 73, 67, 75, 81, 100, 109, 11.00, 199.00, 'Dwells on sacred peaks perpetually covered in snow. Said to appear to virtuous people who have lost their way on mountain paths—it then guides them back down to the mountain’s base.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10105, 'Alolan Diglett', 'Ground', 'Steel', 10, 55, 30, 35, 45, 90, 2.00, 10.00, 'Its three hairs change shape depending on Diglett’s mood. They’re a useful communication tool among these Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10106, 'Alolan Dugtrio', 'Ground', 'Steel', 35, 100, 60, 50, 70, 110, 7.00, 666.00, 'The three of them get along very well. Through their formidable teamwork, they defeat powerful opponents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10107, 'Alolan Meowth', 'Dark', null, 40, 35, 35, 50, 40, 90, 4.00, 42.00, 'Deeply proud and keenly smart, this Pokémon moves with cunning during battle and relentlessly attacks enemies’ weak points.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10108, 'Alolan Persian', 'Dark', null, 65, 60, 60, 75, 65, 115, 11.00, 330.00, 'This Pokémon is one tough opponent. Not only does it have formidable physical abilities, but it’s also not above fighting dirty.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10109, 'Alolan Geodude', 'Rock', 'Electric', 40, 80, 100, 30, 30, 20, 4.00, 203.00, 'Its stone head is imbued with electricity and magnetism. If you carelessly step on one, you’ll be in for a painful shock.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10110, 'Alolan Graveler', 'Rock', 'Electric', 55, 95, 115, 45, 45, 35, 10.00, 1100.00, 'When it comes rolling down a mountain path, anything in its way gets zapped by electricity and sent flying.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10111, 'Alolan Golem', 'Rock', 'Electric', 80, 120, 130, 55, 65, 45, 17.00, 3160.00, 'It uses magnetism to accelerate and fire off rocks tinged with electricity. Even if it doesn’t score a direct hit, the jolt of electricity will do the job.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10112, 'Alolan Grimer', 'Poison', 'Dark', 80, 80, 50, 40, 50, 25, 7.00, 420.00, 'It has a passion for trash above all else, speedily digesting it and creating brilliant crystals of sparkling poison.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10113, 'Alolan Muk', 'Poison', 'Dark', 105, 105, 75, 65, 100, 50, 10.00, 520.00, 'Muk’s coloration becomes increasingly vivid the more it feasts on its favorite dish—trash.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10114, 'Alolan Exeggutor', 'Grass', 'Dragon', 95, 105, 85, 125, 75, 45, 109.00, 4156.00, 'This Pokémon’s psychic powers aren’t as strong as they once were. The head on this Exeggutor’s tail scans surrounding areas with weak telepathy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10115, 'Alolan Marowak', 'Fire', 'Ghost', 60, 80, 110, 50, 80, 45, 10.00, 340.00, 'The cursed flames that light up the bone carried by this Pokémon are said to cause both mental and physical pain that will never fade.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10116, 'Battle Bond Greninja', 'Water', 'Dark', 72, 95, 67, 103, 71, 122, 15.00, 400.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10117, 'Ash\'s Greninja', 'Water', 'Dark', 72, 145, 67, 153, 71, 132, 15.00, 400.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10118, '10% Zygarde', 'Dragon', 'Ground', 54, 100, 71, 61, 85, 115, 12.00, 335.00, 'Born when around 10% of Zygarde’s cells have been gathered from all over, this form is skilled in close-range combat.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10119, '50% Zygarde', 'Dragon', 'Ground', 108, 100, 121, 81, 95, 95, 50.00, 3050.00, 'Some say it can change to an even more powerful form when battling those who threaten the ecosystem.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10120, 'Complete Zygarde', 'Dragon', 'Ground', 216, 100, 121, 91, 95, 85, 45.00, 6100.00, 'Born when all of Zygarde’s cells have been gathered together, it uses force to neutralize those who harm the ecosystem.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10121, 'Totem Gumshoos', 'Normal', null, 88, 110, 60, 55, 60, 45, 14.00, 600.00, 'Gumshoos specializes in relentlessly tracking down prey. The simple-minded Skwovet doesn’t seem to provide Gumshoos enough challenge.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10122, 'Totem Vikavolt', 'Bug', 'Electric', 77, 70, 90, 145, 75, 43, 26.00, 1475.00, 'If it carries a Charjabug to use as a spare battery, a flying Vikavolt can rapidly fire high-powered beams of electricity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10123, 'Pom-pom Oricorio', 'Electric', 'Flying', 75, 70, 70, 98, 70, 93, 6.00, 34.00, 'The energetic, cheerful dance of these Oricorio is popular with children, but the Oricorio themselves are hard to find in Paldea.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10124, 'Pa\'u Oricorio', 'Psychic', 'Flying', 75, 70, 70, 98, 70, 93, 6.00, 34.00, 'This Oricorio has sipped pink nectar. It gets so caught up in its dancing that it sometimes doesn’t hear its Trainer’s orders.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10125, 'Sensu Oricorio', 'Ghost', 'Flying', 75, 70, 70, 98, 70, 93, 6.00, 34.00, 'The elegant, attractive dance of these Oricorio is popular with adults, but the Oricorio themselves are hard to find in Paldea.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10126, 'Midnight Lycanroc', 'Rock', null, 85, 115, 75, 55, 75, 82, 11.00, 250.00, 'This Lycanroc has an extremely vicious temperament. It will happily sustain injuries for the sake of taking down its opponent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10127, 'School Wishiwashi', 'Water', null, 45, 140, 130, 140, 135, 30, 82.00, 786.00, 'When facing tough opponents, they get into formation. But if they get wounded in battle, they’ll scatter and become solitary again.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10128, 'Totem Lurantis', 'Grass', null, 70, 105, 90, 80, 90, 45, 15.00, 580.00, 'A lot of time and effort is required to maintain the vivid colors of its petals. This Pokémon puts its Trainer’s attentiveness to the test.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10129, 'Totem Salazzle', 'Poison', 'Fire', 68, 64, 60, 111, 60, 117, 21.00, 810.00, 'When two Salazzle meet, they will use their pheromone gas to fight over the males in each other’s group.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10130, 'Red Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10131, 'Orange Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10132, 'Yellow Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10133, 'Green Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10134, 'Blue Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10135, 'Indigo Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10136, 'Violet Meteor Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'It will react when touched or called to, but it’s unknown whether such responses indicate consciousness.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10137, 'Red Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10138, 'Orange Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10139, 'Yellow Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10140, 'Green Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10141, 'Blue Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10142, 'Indigo Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10143, 'Busted Mimikyu', 'Ghost', 'Fairy', 55, 90, 80, 50, 105, 96, 2.00, 7.00, 'It has taken damage and can no longer hold the head of its cloth disguise upright. For as long as it lives, Mimikyu will never forget its attacker.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10144, 'Totem Disguised Mimikyu', 'Ghost', 'Fairy', 55, 90, 80, 50, 105, 96, 4.00, 28.00, 'Mimikyu was only recently identified as a Pokémon. Previously, people thought it was just a ghost wearing a cloth.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10145, 'Totem Busted Mimikyu', 'Ghost', 'Fairy', 55, 90, 80, 50, 105, 96, 4.00, 28.00, 'It has taken damage and can no longer hold the head of its cloth disguise upright. For as long as it lives, Mimikyu will never forget its attacker.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10146, 'Totem Kommo\'o', 'Dragon', 'Fighting', 75, 110, 125, 100, 105, 85, 24.00, 2075.00, 'Certain ruins have paintings of ancient warriors wearing armor made of Kommo-o scales.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10147, 'Original Magearna', 'Steel', 'Fairy', 80, 95, 115, 130, 115, 65, 10.00, 805.00, 'It functions thanks to its artificial soul. The vivid decoration is proof that it was presented as a gift to royalty.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10148, 'Partner Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed as the two overcame many hardships together.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10149, '', 'Fire', 'Ghost', 60, 80, 110, 50, 80, 45, 17.00, 980.00, 'The bones it uses have been in its possession since it was born. It has a ferocious nature.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10150, 'Totem Ribombee', 'Bug', 'Fairy', 60, 55, 60, 95, 70, 124, 4.00, 20.00, 'Ribombee absolutely hate getting wet or rained on. In the cloudy Galar region, they are very seldom seen.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10151, 'Own Tempo Rockruff', 'Rock', null, 45, 65, 40, 30, 40, 60, 5.00, 92.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10152, 'Dusk Lycanroc', 'Rock', null, 75, 117, 65, 55, 65, 110, 8.00, 250.00, 'These Pokémon have both calm and ferocious qualities. It’s said that this form of Lycanroc is the most troublesome to raise.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10153, 'Totem Araquanid', 'Water', 'Bug', 68, 70, 92, 50, 132, 42, 31.00, 2175.00, 'It acts as a caretaker for Dewpider, putting them inside its bubble and letting them eat any leftover food.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10154, 'Totem Togedemaru', 'Electric', 'Steel', 65, 98, 63, 40, 73, 96, 6.00, 130.00, 'When it’s in trouble, it curls up into a ball, makes its fur spikes stand on end, and then discharges electricity indiscriminately.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10155, 'Dusk Mane Necrozma', 'Psychic', 'Steel', 97, 157, 127, 113, 109, 77, 38.00, 4600.00, 'Necrozma has attached itself to Solgaleo. It siphons away its host’s limitless energy, exploiting that energy to fuel a rampage.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10156, 'Dawn Wings Necrozma', 'Psychic', 'Ghost', 97, 113, 109, 157, 127, 77, 42.00, 3500.00, 'When Necrozma latches on to Lunala, it becomes vicious, seeing enemies everywhere it looks. It will burn the world with lasers.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10157, 'Ultra Necrozma', 'Psychic', 'Dragon', 97, 167, 97, 167, 97, 129, 75.00, 2300.00, 'The light pouring out from all over its body affects living things and nature, impacting them in various ways.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10158, 'Galarian Meowth', 'Steel', null, 50, 65, 55, 40, 40, 40, 4.00, 75.00, 'These daring Pokémon have coins on their foreheads. Darker coins are harder, and harder coins garner more respect among Meowth.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10159, 'Galarian Ponyta', 'Psychic', null, 50, 85, 55, 65, 65, 90, 8.00, 240.00, 'This Pokémon will look into your eyes and read the contents of your heart. If it finds evil there, it promptly hides away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10160, 'Galarian Rapidash', 'Psychic', 'Fairy', 65, 100, 70, 80, 80, 105, 17.00, 800.00, 'Brave and prideful, this Pokémon dashes airily through the forest, its steps aided by the psychic power stored in the fur on its fetlocks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10161, 'Galarian Slowpoke', 'Psychic', null, 90, 65, 65, 40, 40, 15, 12.00, 360.00, 'Because Galarian Slowpoke eat the seeds of a plant that grows only in Galar, their tails have developed a spicy flavor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10162, 'Galarian Slowbro', 'Poison', 'Psychic', 95, 100, 95, 100, 70, 30, 16.00, 705.00, 'If this Pokémon squeezes the tongue of the Shellder biting it, the Shellder will launch a toxic liquid from the tip of its shell.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10163, 'Galarian Farfetch\'d', 'Fighting', null, 52, 95, 55, 58, 62, 55, 8.00, 420.00, 'The stalks of leeks are thicker and longer in the Galar region. Farfetch’d that adapted to these stalks took on a unique form.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10164, 'Galarian Weezing', 'Poison', 'Fairy', 65, 90, 120, 85, 70, 60, 30.00, 160.00, 'Long ago, during a time when droves of factories fouled the air with pollution, Weezing changed into this form for some reason.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10165, 'Galarian Mr. Mime', 'Ice', 'Psychic', 50, 65, 65, 90, 90, 100, 14.00, 568.00, 'It can radiate chilliness from the bottoms of its feet. It’ll spend the whole day tap-dancing on a frozen floor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10166, 'Galarian Articuno', 'Psychic', 'Flying', 90, 85, 85, 125, 100, 95, 17.00, 509.00, 'Known as Articuno, this Pokémon fires beams that can immobilize opponents as if they had been frozen solid.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10167, 'Galarian Zapdos', 'Fighting', 'Flying', 90, 125, 90, 85, 90, 100, 16.00, 582.00, 'One kick from its powerful legs will pulverize a dump truck. Supposedly, this Pokémon runs through the mountains at over 180 mph.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10168, 'Galarian Moltres', 'Dark', 'Flying', 90, 85, 90, 100, 125, 90, 20.00, 660.00, 'The sinister aura that blazes like molten fire around this Pokémon is what inspired the name Moltres.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10169, 'Galarian Slowking', 'Poison', 'Psychic', 95, 65, 80, 110, 110, 30, 18.00, 795.00, 'While chanting strange spells, this Pokémon combines its internal toxins with what it’s eaten, creating strange potions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10170, 'Galarian Corsola', 'Ghost', null, 60, 55, 100, 65, 100, 30, 6.00, 5.00, 'Sudden climate change wiped out this ancient kind of Corsola. This Pokémon absorbs others’ life-force through its branches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10171, 'Galarian Zigzagoon', 'Dark', 'Normal', 38, 30, 41, 30, 41, 60, 4.00, 175.00, 'Thought to be the oldest form of Zigzagoon, it moves in zigzags and wreaks havoc upon its surroundings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10172, 'Galarian Linoone', 'Dark', 'Normal', 78, 70, 61, 50, 61, 100, 5.00, 325.00, 'This very aggressive Pokémon will recklessly challenge opponents stronger than itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10173, 'Galarian Darumaka', 'Ice', null, 70, 90, 45, 15, 45, 50, 7.00, 400.00, 'The colder they get, the more energetic they are. They freeze their breath to make snowballs, using them as ammo for playful snowball fights.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10174, 'Galarian Darmanitan', 'Ice', null, 105, 140, 55, 30, 55, 95, 17.00, 1200.00, 'Though it has a gentle disposition, it’s also very strong. It will quickly freeze the snowball on its head before going for a headbutt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10175, 'Galarian Zen Darmanitan', 'Ice', 'Fire', 105, 160, 55, 30, 55, 135, 17.00, 1200.00, 'Darmanitan takes this form when enraged. It won’t stop spewing flames until its rage has settled, even if its body starts to melt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10176, 'Galarian Yamask', 'Ground', 'Ghost', 38, 55, 85, 30, 65, 30, 5.00, 15.00, 'It’s said that this Pokémon was formed when an ancient clay tablet was drawn to a vengeful spirit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10177, 'Galarian Stunfisk', 'Ground', 'Steel', 109, 81, 99, 66, 84, 32, 7.00, 205.00, 'Its conspicuous lips lure prey in as it lies in wait in the mud. When prey gets close, Stunfisk clamps its jagged steel fins down on them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10178, 'Low Key Toxtricity', 'Electric', 'Poison', 75, 98, 70, 114, 70, 75, 16.00, 400.00, 'As it gulps down stagnant water and generates electricity in its body, a sound like a rhythm played by a bass guitar reverberates all around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10179, 'Noice Face Eiscue', 'Ice', null, 75, 80, 70, 65, 50, 130, 14.00, 890.00, 'If you lick the ice covering its face, you’ll find it has a faintly salty taste. This species rode here on ocean currents from a cold, faraway land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10180, 'Female Indeedee', 'Psychic', 'Normal', 70, 55, 65, 95, 105, 85, 9.00, 28.00, 'In search of happy feelings—such as joy and gratitude—Indeedee bustles around, taking diligent care of people and other Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10181, 'Crowned Zacian', 'Fairy', 'Steel', 92, 150, 115, 80, 115, 148, 28.00, 3550.00, 'Able to cut down anything with a single strike, it became known as the Fairy King’s Sword, and it inspired awe in friend and foe alike.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10182, 'Crowned Zamazenta', 'Fighting', 'Steel', 92, 120, 140, 80, 140, 128, 29.00, 7850.00, 'Now that it’s equipped with its shield, it can shrug off impressive blows, including the attacks of Dynamax Pokémon.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10183, 'Rapid Strike Urshifu', 'Fighting', 'Water', 100, 130, 100, 63, 60, 97, 19.00, 1050.00, 'This form of Urshifu is a strong believer in defeating foes by raining many blows down on them. Its strikes are nonstop, flowing like a river.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10184, 'Ice Rider Calyrex', 'Psychic', 'Ice', 100, 165, 150, 85, 130, 50, 24.00, 8091.00, 'It’s said that this Pokémon once moved a large forest—and all the Pokémon living there—to a new location overnight.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10185, 'Shadow Rider Calyrex', 'Psychic', 'Ghost', 100, 85, 80, 165, 100, 150, 24.00, 536.00, 'Legend says that by using its power to see all events from past to future, this Pokémon saved the creatures of a forest from a meteorite strike.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10186, 'Gigantamax Venusaur', 'Grass', 'Poison', 80, 112, 93, 130, 110, 100, 240.00, 10000.00, 'Huge amounts of pollen burst from it with the force of a volcanic eruption. Breathing in too much of the pollen can cause fainting.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10187, 'Gigantamax Charizard', 'Fire', 'Flying', 78, 139, 83, 139, 85, 100, 280.00, 10000.00, 'The flame inside its body burns hotter than 3,600 degrees Fahrenheit. When Charizard roars, that temperature climbs even higher.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10188, 'Gigantamax Blastoise', 'Water', null, 79, 106, 115, 125, 105, 100, 250.00, 10000.00, 'Water fired from this Pokémon\'s central main cannon has enough power to blast a hole into a mountain.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10189, 'Gigantamax Butterfree', 'Bug', 'Flying', 60, 75, 65, 100, 85, 110, 170.00, 10000.00, 'Once it has opponents trapped in a tornado that could blow away a 10-ton truck, it finishes them off with its poisonous scales.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10190, 'Gigantamax Pikachu', 'Electric', null, 35, 90, 70, 105, 80, 60, 210.00, 10000.00, 'When it smashes its opponents with its bolt- shaped tail, it delivers a surge of electricity equivalent to a lightning strike.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10191, 'Gigantamax Meowth', 'Normal', null, 40, 90, 45, 60, 45, 130, 330.00, 10000.00, 'Its body has grown incredibly long and the coin on its forehead has grown incredibly large—all thanks to Gigantamax power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10192, 'Gigantamax Machamp', 'Fighting', null, 90, 145, 95, 75, 105, 85, 250.00, 10000.00, 'One of these Pokémon once used its immeasurable strength to lift a large ship that was in trouble. It then carried the ship to port.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10193, 'Gigantamax Gengar', 'Ghost', 'Poison', 60, 109, 70, 150, 85, 126, 200.00, 10000.00, 'It lays traps, hoping to steal the lives of those it catches. If you stand in front of its mouth, you’ll hear your loved ones’ voices calling out to you.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10194, 'Gigantamax Kingler', 'Water', null, 55, 165, 115, 105, 65, 75, 190.00, 10000.00, 'The bubbles it spews out are strongly alkaline. Any opponents hit by them will have their bodies quickly melted away.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10195, 'Gigantamax Lapras', 'Water', 'Ice', 130, 100, 95, 145, 105, 60, 240.00, 10000.00, 'It surrounds itself with a huge ring of gathered ice particles. It uses the ring to smash any icebergs that might impede its graceful swimming.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10196, 'Gigantamax Eevee', 'Normal', null, 95, 105, 50, 45, 65, 85, 180.00, 10000.00, 'Having gotten even friendlier and more innocent, Eevee tries to play with anyone around, only to end up crushing them with its immense body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10197, 'Gigantamax Snorlax', 'Normal', null, 170, 130, 75, 95, 125, 45, 350.00, 10000.00, 'Terrifyingly strong, this Pokémon is the size of a mountain—and moves about as much as one as well.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10198, 'Gigantamax Garbodor', 'Poison', null, 80, 125, 92, 110, 92, 75, 210.00, 10000.00, 'It sprays toxic gas from its mouth and fingers. If the gas engulfs you, the toxins will seep in all the way down to your bones.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10199, 'Gigantamax Melmetal', 'Steel', null, 135, 143, 113, 113, 78, 118, 250.00, 10000.00, 'It can send electric beams streaking out from the hole in its belly. The beams’ tremendous energy can vaporize an opponent in one shot.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10200, 'Gigantamax Rillaboom', 'Grass', null, 100, 140, 100, 95, 95, 100, 280.00, 10000.00, 'Rillaboom has become one with its forest of drums and continues to lay down beats that shake all of Galar.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10201, 'Gigantamax Cinderace', 'Fire', null, 80, 145, 92, 85, 92, 131, 270.00, 10000.00, 'Gigantamax energy can sometimes cause the diameter of this Pokémon’s fireball to exceed 300 feet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10202, 'Gigantamax Inteleon', 'Water', null, 70, 120, 65, 155, 70, 150, 400.00, 10000.00, 'It has excellent sniping skills. Shooting a berry rolling along over nine miles away is a piece of cake for this Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10203, 'Gigantamax Corviknight', 'Flying', 'Steel', 98, 127, 120, 58, 105, 87, 140.00, 10000.00, 'The eight feathers on its back are called blade birds, and they can launch off its body to attack foes independently.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10204, 'Gigantamax Orbeetle', 'Bug', 'Psychic', 60, 85, 120, 115, 130, 95, 140.00, 10000.00, 'If it were to utilize every last bit of its power, it could control the minds of every living being in its vicinity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10205, 'Gigantamax Drednaw', 'Water', 'Rock', 90, 155, 110, 68, 83, 79, 240.00, 10000.00, 'In the Galar region, there’s a tale about this Pokémon chewing up a mountain and using the rubble to stop a flood.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10206, 'Gigantamax Coalossal', 'Rock', 'Fire', 110, 120, 120, 120, 100, 40, 420.00, 10000.00, 'When Galar was hit by a harsh cold wave, this Pokémon served as a giant heating stove and saved many lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10207, 'Gigantamax Flapple', 'Grass', 'Dragon', 70, 145, 90, 105, 80, 95, 240.00, 10000.00, 'If it stretches its neck, the strong aroma of its nectar pours out. The scent is so sickeningly sweet that one whiff makes other Pokémon faint.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10208, 'Gigantamax Appletun', 'Grass', 'Dragon', 110, 90, 105, 130, 105, 45, 240.00, 10000.00, 'Due to Gigantamax energy, this Pokémon’s nectar has thickened. The increased viscosity lets the nectar absorb more damage than before.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10209, 'Gigantamax Sandaconda', 'Ground', null, 72, 147, 135, 65, 80, 111, 220.00, 10000.00, 'Sand swirls around its body with such speed and power that it could pulverize a skyscraper.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10210, 'Gigantamax Amped Toxtricity', 'Electric', 'Poison', 75, 118, 80, 147, 80, 102, 240.00, 10000.00, 'Out of control after its own poison penetrated its brain, it tears across the land in a rampage, contaminating the earth with toxic sweat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10211, 'Gigantamax Centiskorch', 'Fire', 'Bug', 100, 125, 75, 120, 95, 110, 750.00, 10000.00, 'The heat that comes off a Gigantamax Centiskorch may destabilize air currents. Sometimes it can even cause storms.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10212, 'Gigantamax Hatterene', 'Psychic', 'Fairy', 57, 100, 115, 166, 123, 49, 260.00, 10000.00, 'Beams like lightning shoot down from its tentacles. It’s known to some as the Raging Goddess.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10213, 'Gigantamax Grimmsnarl', 'Dark', 'Fairy', 95, 150, 75, 125, 85, 80, 320.00, 10000.00, 'Gigantamax energy has caused more hair to sprout all over its body. With the added strength, it can jump over the world’s tallest building.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10214, 'Gigantamax Alcremie', 'Fairy', null, 85, 70, 75, 140, 141, 74, 300.00, 10000.00, 'It launches swarms of missiles, each made of cream and loaded with 100,000 kilocalories. Get hit by one of these, and your head will swim.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10215, 'Gigantamax Copperajah', 'Steel', null, 122, 140, 99, 80, 99, 60, 230.00, 10000.00, 'After this Pokémon has Gigantamaxed, its massive nose can utterly demolish large structures with a single smashing blow.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10216, 'Gigantamax Duraludon', 'Steel', 'Dragon', 70, 115, 135, 155, 75, 85, 430.00, 10000.00, 'The hardness of its cells is exceptional, even among Steel types. It also has a body structure that’s resistant to earthquakes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10217, 'Eternamax Eternatus', 'Poison', 'Dragon', 150, 120, 120, 165, 120, 105, 1000.00, 10000.00, 'Infinite amounts of energy pour from this Pokémon’s enlarged core, warping the surrounding space-time.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10218, 'Gigantamax Single Strike Urshifu', 'Fighting', 'Dark', 100, 145, 115, 93, 100, 97, 290.00, 10000.00, 'The energy released by this Pokémon’s fists forms shock waves that can blow away Dynamax Pokémon in just one hit.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10219, 'Gigantamax Rapid Strike Urshifu', 'Fighting', 'Water', 100, 145, 100, 93, 90, 122, 260.00, 10000.00, 'All it takes is a glare from this Pokémon to take the lives of those with evil in their hearts—or so they say.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10220, 'Gigantamax Low Key Toxtricity', 'Electric', 'Poison', 75, 118, 80, 147, 80, 102, 240.00, 10000.00, 'Out of control after its own poison penetrated its brain, it tears across the land in a rampage, contaminating the earth with toxic sweat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10221, 'Hisuian Growlithe', 'Fire', 'Rock', 60, 75, 45, 65, 50, 55, 8.00, 227.00, 'They patrol their territory in pairs. I believe the igneous rock components in the fur of this species are the result of volcanic activity in its habitat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10222, 'Hisuian Arcanine', 'Fire', 'Rock', 95, 115, 80, 95, 80, 90, 20.00, 1680.00, 'Snaps at its foes with fangs cloaked in blazing flame. Despite its bulk, it deftly feints every which way, leading opponents on a deceptively merry chase as it all but dances around them.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10223, 'Hisuian Voltorb', 'Electric', 'Grass', 40, 30, 50, 55, 55, 100, 5.00, 130.00, 'An enigmatic Pokémon that happens to bear a resemblance to a Poké Ball. When excited, it discharges the electric current it has stored in its belly, then lets out a great, uproarious laugh.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10224, 'Hisuian Electrode', 'Electric', 'Grass', 60, 50, 70, 80, 80, 150, 12.00, 710.00, 'The tissue on the surface of its body is curiously similar in composition to an Apricorn. When irritated, this Pokémon lets loose an electric current equal to 20 lightning bolts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10225, 'Hisuian Typhlosion', 'Fire', 'Ghost', 73, 84, 78, 119, 85, 95, 16.00, 698.00, 'Said to purify lost, forsaken souls with its flames and guide them to the afterlife. I believe its form has been influenced by the energy of the sacred mountain towering at Hisui’s center.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10226, 'Hisuian Qwilfish', 'Dark', 'Poison', 65, 95, 85, 55, 55, 85, 5.00, 39.00, 'Fishers detest this troublesome Pokémon because it sprays poison from its spines, getting it everywhere. A different form of Qwilfish lives in other regions.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10227, 'Hisuian Sneasel', 'Fighting', 'Poison', 55, 95, 55, 35, 75, 115, 9.00, 270.00, 'Its sturdy, curved claws are ideal for traversing precipitous cliffs. From the tips of these claws drips a venom that infiltrates the nerves of any prey caught in Sneasel’s grasp.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10228, 'Hisuian Samurott', 'Water', 'Dark', 90, 108, 80, 100, 65, 85, 15.00, 582.00, 'Hard of heart and deft of blade, this rare form of Samurott is a product of the Pokémon’s evolution in the region of Hisui. Its turbulent blows crash into foes like ceaseless pounding waves.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10229, 'Hisuian Lilligant', 'Grass', 'Fighting', 70, 105, 75, 50, 75, 105, 12.00, 192.00, 'I suspect that its well-developed legs are the result of a life spent on mountains covered in deep snow. The scent it exudes from its flower crown heartens those in proximity.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10230, 'Hisuian Zorua', 'Normal', 'Ghost', 35, 60, 40, 85, 40, 70, 7.00, 125.00, 'A once-departed soul, returned to life in Hisui. Derives power from resentment, which rises as energy atop its head and takes on the forms of foes. In this way, Zorua vents lingering malice.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10231, 'Hisuian Zoroark', 'Normal', 'Ghost', 55, 100, 60, 125, 60, 110, 16.00, 730.00, 'With its disheveled white fur, it looks like an embodiment of death. Heedless of its own safety, Zoroark attacks its nemeses with a bitter energy so intense, it lacerates Zoroark’s own body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10232, 'Hisuian Braviary', 'Psychic', 'Flying', 110, 83, 70, 112, 70, 65, 17.00, 434.00, 'Screaming a bloodcurdling battle cry, this huge and ferocious bird Pokémon goes out on the hunt. It blasts lakes with shock waves, then scoops up any prey that float to the water’s surface.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10233, 'Hisuian Sliggoo', 'Steel', 'Dragon', 58, 75, 83, 83, 113, 40, 7.00, 685.00, 'A creature given to melancholy. I suspect its metallic shell developed as a result of the mucus on its skin reacting with the iron in Hisui’s water.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10234, 'Hisuian Goodra', 'Steel', 'Dragon', 80, 100, 100, 110, 150, 60, 17.00, 3341.00, 'Able to freely control the hardness of its metallic shell. It loathes solitude and is extremely clingy—it will fume and run riot if those dearest to it ever leave its side.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10235, 'Hisuian Avalugg', 'Ice', 'Rock', 95, 127, 184, 34, 36, 38, 14.00, 2624.00, 'The armor of ice covering its lower jaw puts steel to shame and can shatter rocks with ease. This Pokémon barrels along steep mountain paths, cleaving through the deep snow.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10236, 'Hisuian Decidueye', 'Grass', 'Fighting', 88, 112, 80, 95, 95, 60, 16.00, 370.00, 'The air stored inside the rachises of Decidueye’s feathers insulates the Pokémon against Hisui’s extreme cold. This is firm proof that evolution can be influenced by environment.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10237, 'Origin Palkia', 'Water', 'Dragon', 90, 100, 100, 150, 120, 120, 63.00, 6590.00, 'It soars across the sky in a form that greatly resembles the creator of all things. Perhaps this imitation of appearance is Palkia’s strategy for gaining Arceus’s powers.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10238, 'Origin Dialga', 'Steel', 'Dragon', 100, 100, 120, 150, 120, 90, 70.00, 8487.00, 'Radiant light caused Dialga to take on a form bearing a striking resemblance to the creator Pokémon. Dialga now wields such colossal strength that one must conclude this is its true form.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10239, 'Partner Pikachu', 'Electric', null, 45, 80, 50, 75, 60, 120, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed as the two overcame many hardships together.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10240, 'Partner Eevee', 'Normal', null, 65, 75, 70, 65, 85, 75, 3.00, 65.00, 'It can evolve into a variety of forms. Eevee\'s genes are the key to solving the mysteries of Pokémon evolution.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10241, 'World Cap Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, 'This Pikachu wears its partner’s cap—proof of the strong bond Pikachu and its partner formed during adventures across the world.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10242, '10% Zygarde', 'Dragon', 'Ground', 54, 100, 71, 61, 85, 115, 12.00, 335.00, 'Born when around 10% of Zygarde’s cells have been gathered from all over, this form is skilled in close-range combat.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10243, 'Gulping Cramorant', 'Flying', 'Water', 70, 85, 55, 85, 95, 85, 8.00, 180.00, 'The slightest shock is sometimes enough to get this Pokémon to spit out the Arrokuda lodged in its throat.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10244, 'Gorging Cramorant', 'Flying', 'Water', 70, 85, 55, 85, 95, 85, 8.00, 180.00, 'The half-swallowed Pikachu is so startled that it isn’t struggling yet, but it’s still looking for a chance to strike back.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10245, 'Hangry Morpeko', 'Electric', 'Dark', 58, 95, 58, 70, 58, 97, 3.00, 30.00, 'Hunger hormones affect its temperament. Until its hunger is appeased, it gets up to all manner of evil deeds.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10246, 'Dada Zarude', 'Dark', 'Grass', 105, 120, 105, 70, 95, 105, 18.00, 700.00, 'This Zarude’s special strength stems from its love and care for an orphaned human child that the Pokémon has raised since the child’s infancy.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10247, 'White-Striped Basculin', 'Water', null, 70, 92, 65, 80, 55, 98, 10.00, 180.00, 'Though it differs from other Basculin in several respects, including demeanor—this one is gentle—I have categorized it as a regional form given the vast array of shared qualities.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10248, 'Basculegion', 'Water', 'Ghost', 120, 92, 65, 100, 75, 78, 30.00, 1100.00, 'Clads itself in the souls of comrades that perished before fulfilling their goals of journeying upstream. No other species throughout all Hisui’s rivers is Basculegion’s equal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10249, 'Therian Enamorus', 'Fairy', 'Flying', 74, 115, 110, 135, 100, 46, 16.00, 480.00, 'A different guise from its feminine humanoid form. From the clouds, it descends upon those who treat any form of life with disrespect and metes out wrathful, ruthless punishment.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10250, 'Combat Breed Tauros', 'Fighting', null, 75, 110, 105, 30, 70, 100, 14.00, 1150.00, 'This kind of Tauros, known as the Combat Breed, is distinguished by its thick, powerful muscles and its fierce disposition.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10251, 'Blaze Breed Tauros', 'Fighting', 'Fire', 75, 110, 105, 30, 70, 100, 14.00, 850.00, 'People call this kind of Tauros the Blaze Breed due to the hot air it snorts from its nostrils. Its three tails are intertwined.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10252, 'Aqua Breed Tauros', 'Fighting', 'Water', 75, 110, 105, 30, 70, 100, 14.00, 1100.00, 'It swims by jetting water from its horns. The most notable characteristic of the Aqua Breed is its high body fat, which allows it to float easily.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10253, 'Paldean Wooper', 'Poison', 'Ground', 55, 45, 45, 25, 25, 15, 4.00, 110.00, 'It’s dangerous for Wooper to travel alone. They line up in groups of three or four and help each other as they walk around the wetlands.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10254, 'Oinkologne', 'Normal', null, 115, 90, 70, 59, 90, 65, 10.00, 1200.00, 'This is a meticulous Pokémon that likes to keep things tidy. It shrouds itself in a floral aroma that soothes the Pokémon around it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10255, 'Three-Segment Dudunsparce', 'Normal', null, 125, 100, 80, 85, 75, 55, 45.00, 474.00, 'A recent study uncovered that the number of segments a Dudunsparce’s body has is determined by the Pokémon’s genes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10256, 'Hero Palafin', 'Water', null, 100, 160, 97, 106, 87, 100, 18.00, 974.00, 'This hero of the ocean swims at a speed of 50 knots and saves drowning people and Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10257, 'Family of Three Maushold', 'Normal', null, 74, 75, 70, 65, 75, 111, 3.00, 28.00, 'The little one just appeared one day. They all live together like a family, but the relationship between the three is still unclear.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10258, 'Droopy Tatsugiri', 'Dragon', 'Water', 68, 50, 60, 120, 95, 82, 3.00, 80.00, 'This Pokémon tricks its opponents by playing dead. It is small and weak, but it uses its smarts to survive.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10259, 'Stretchy Tatsugiri', 'Dragon', 'Water', 68, 50, 60, 120, 95, 82, 3.00, 80.00, 'It’s one of the most intelligent dragon Pokémon. It camouflages itself by inflating its throat sac.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10260, 'Blue Plumage Squawkabilly', 'Normal', 'Flying', 82, 96, 51, 45, 51, 92, 6.00, 24.00, 'Blue-feathered Squawkabilly view their green-feathered counterparts as rivals, since the latter make up the largest, most powerful groups.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10261, 'Yellow Plumage Squawkabilly', 'Normal', 'Flying', 82, 96, 51, 45, 51, 92, 6.00, 24.00, 'The yellow Squawkabilly are especially fierce. They’ve even been known to drive other bird Pokémon out of town.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10262, 'White Plumage Squawkabilly', 'Normal', 'Flying', 82, 96, 51, 45, 51, 92, 6.00, 24.00, 'Though these Squawkabilly are the fewest in number, they have no trouble living in towns since they blend in with the white buildings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10263, 'Roaming Gimmighoul', 'Ghost', null, 45, 30, 25, 75, 45, 80, 1.00, 10.00, 'It wanders around, carrying an old coin on its back. It survives by draining the life-force from humans who try to pick up its coin.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10264, 'Limited Build', 'Fighting', 'Dragon', 100, 135, 115, 85, 100, 135, 35.00, 3030.00, 'It has similar characteristics to a creature described in an old book as the Winged King.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10265, 'Sprinting Build Koraidon', 'Fighting', 'Dragon', 100, 135, 115, 85, 100, 135, 35.00, 3030.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10266, 'Swimming Build', 'Fighting', 'Dragon', 100, 135, 115, 85, 100, 135, 35.00, 3030.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10267, 'Gliding Build Koraidon', 'Fighting', 'Dragon', 100, 135, 115, 85, 100, 135, 35.00, 3030.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10268, 'Low-Power Mode', 'Electric', 'Dragon', 100, 85, 100, 135, 115, 135, 28.00, 2400.00, 'It was given the name Miraidon by the professor who discovered it. Its ecology and other details are unknown.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10269, 'Drive Mode Miraidon', 'Electric', 'Dragon', 100, 85, 100, 135, 115, 135, 28.00, 2400.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10270, 'Aquatic Mode', 'Electric', 'Dragon', 100, 85, 100, 135, 115, 135, 28.00, 2400.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10271, 'Glide Mode Miraidon', 'Electric', 'Dragon', 100, 85, 100, 135, 115, 135, 28.00, 2400.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10272, 'Bloodmoon Ursaluna', 'Ground', 'Normal', 113, 70, 120, 135, 65, 52, 27.00, 3333.00, 'This special Ursaluna can see in the dark with its left eye and protects itself with mud that is as hard as iron.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10273, 'Wellspring Mask Ogerpon', 'Grass', 'Water', 80, 120, 84, 60, 96, 110, 12.00, 398.00, 'In this form, it draws on the power of water. It attacks unrelentingly with kicks and ivy strikes.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10274, 'Hearthflame Mask Ogerpon', 'Grass', 'Fire', 80, 120, 84, 60, 96, 110, 12.00, 398.00, 'In this form, it draws on the power of fire. It spears its enemies with thorn-covered ivy.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10275, 'Cornerstone Mask Ogerpon', 'Grass', 'Rock', 80, 120, 84, 60, 96, 110, 12.00, 398.00, 'In this form, it draws on the power of stone. Its body is rock-solid, protecting it from all manner of attacks.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10276, 'Terastal Terapagos', 'Normal', null, 95, 95, 110, 105, 110, 85, 3.00, 160.00, 'The shell is made of crystallized Terastal energy. When struck by a move, this shell absorbs the move’s energy and transfers it to Terapagos.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10277, 'Stellar Terapagos', 'Normal', null, 160, 105, 110, 130, 110, 85, 17.00, 770.00, 'An old expedition journal describes the sight of this Pokémon buried in the depths of the earth as resembling a planet floating in space.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10278, 'Unown A', 'Psychic', null, 48, 72, 48, 72, 48, 48, 5.00, 50.00, 'It is hard to believe these strangely shaped Pokémon are truly living creatures. I’ve pointed out that the species’ many forms resemble writing from other lands; no one will take me seriously.', 0, 0);
