INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10305, 'Yellow Flower Flabébé', 'Fairy', null, 44, 38, 39, 61, 79, 42, 1.00, 1.00, 'Flabébé wears a crown made from pollen it’s collected from its flower. The crown has hidden healing properties.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10306, 'Orange Flower Flabébé', 'Fairy', null, 44, 38, 39, 61, 79, 42, 1.00, 1.00, 'Flabébé wears a crown made from pollen it’s collected from its flower. The crown has hidden healing properties.', 0, 0);
