INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10309, 'Yellow Flower Floette', 'Fairy', null, 54, 45, 47, 75, 98, 52, 2.00, 9.00, 'It gives its own power to flowers, pouring its heart into caring for them. Floette never forgives anyone who messes up a flower bed.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10310, 'Orange Flower Floette', 'Fairy', null, 54, 45, 47, 75, 98, 52, 2.00, 9.00, 'It gives its own power to flowers, pouring its heart into caring for them. Floette never forgives anyone who messes up a flower bed.', 0, 0);
