INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10313, 'Yellow Flower Florges', 'Fairy', null, 78, 65, 68, 112, 154, 75, 11.00, 100.00, 'Its life can span several hundred years. It’s said to devote its entire life to protecting gardens.', 0, 0);
