INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10318, 'Sunshine Cherrim', 'Grass', null, 70, 60, 70, 87, 78, 85, 5.00, 93.00, 'Cheerfully active on sunny days. Immediately closes its petals and becomes immobile once the sun becomes hidden, however.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10319, 'East Sea Shellos', 'Water', null, 76, 48, 48, 57, 62, 34, 3.00, 63.00, 'This Pokémon can often be seen along seashores. It\'s capable of spending a limited amount of time on land.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10320, 'East Sea Gastrodon', 'Water', 'Ground', 111, 83, 68, 92, 82, 39, 9.00, 299.00, 'Fishers say that they didn\'t see many of these Pokémon in the past, but this form of Gastrodon is now increasing in number.', 0, 0);
