INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10340, 'Summer Deerling', 'Normal', 'Grass', 60, 60, 50, 40, 50, 75, 6.00, 195.00, 'Deerling have different scents depending on the season. When a distinct grassy smell starts to waft from one, you know that summer has begun.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10341, 'Autumn Deerling', 'Normal', 'Grass', 60, 60, 50, 40, 50, 75, 6.00, 195.00, 'Deerling have different scents depending on the season. In this form, Deerling have a softly sweet scent that lingers in the nose.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10342, 'Winter Deerling', 'Normal', 'Grass', 60, 60, 50, 40, 50, 75, 6.00, 195.00, 'This Pokémon will playfully headbutt those it gets along well with. It has antlers hidden under its flower, so the headbutts are a little painful.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10343, 'Summer Sawsbuck', 'Normal', 'Grass', 80, 100, 70, 60, 70, 95, 19.00, 925.00, 'This Pokémon\'s leaves can be made into a black tea, the taste of which varies depending on the region of origin. Paldea\'s is especially aromatic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10344, 'Autumn Sawsbuck', 'Normal', 'Grass', 80, 100, 70, 60, 70, 95, 19.00, 925.00, 'Sawsbuck in their Autumn Form are known for having very short tempers. The males fight each other incessantly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10345, 'Winter Sawsbuck', 'Normal', 'Grass', 80, 100, 70, 60, 70, 95, 19.00, 925.00, 'Though there are many enthusiasts for Sawsbuck as a species, this seasonal form in particular is not very popular.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10346, 'Neutral Xerneas', 'Fairy', null, 126, 131, 95, 131, 98, 99, 30.00, 2150.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10347, 'Bug Arceus', 'Bug', null, 120, 120, 120, 120, 120, 120, 32.00, 3200.00, 'It is the heavenly fount from which pours the light that shines across Hisui. Its luminance guides and protects all Pokémon. Hisuian mythology states that Arceus is the creator of all things.', 1, 0);
