INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10452, 'Sandy Burmy', 'Bug', null, 40, 29, 45, 29, 45, 36, 2.00, 34.00, 'It creates a cloak by weaving together sand, mud, and silk it has spat out. This earthen cloak is ruined by wind and rain, so the Pokémon hides away in caves and other such places.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (10453, 'Trash Burmy', 'Bug', null, 40, 29, 45, 29, 45, 36, 2.00, 34.00, 'When confronted by a lack of other materials, Burmy will create its cloak using dust and refuse. The cloak seems to be more comfortable than one would think.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20000, 'Zygarde Cell', 'Dragon', 'Ground', 1, 1, 1, 1, 1, 1, 1.00, 61.00, 'The Zygarde Cells form the rest of Zygarde\'s body and are only able to act on the Core\'s orders. The Zygarde Cells allows the Zygarde Core to observe the ecosystem, allowing them to see through their eyes.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20001, 'Zygarde Core', 'Dragon', 'Ground', 11, 5, 6, 5, 5, 4, 9.00, 1220.00, 'The Zygarde Core remains in watch of the region, usually living in caves. The Cores have their own will and are sometimes able to act on their own. The Zygarde Core can order Zygarde Cells, commanding them to fly towards it to form Zygarde\'s body in order to protect the ecosystem.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20002, 'Zenith Marshadow', 'Fighting', 'Ghost', 90, 125, 80, 90, 90, 125, 7.00, 222.00, 'When angered or attacking, Marshadow\'s fighting spirit will begin to burn, causing it to become Zenith Marshadow. In this state, its headgear, wrist bumps, and collar flare up and resemble green and yellow flames. Marshadow\'s eyes also flare up when in this state, but do not change in color.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20003, 'Battle Cyclizar', 'Dragon', 'Normal', 70, 95, 65, 85, 65, 121, 16.00, 630.00, '', 0, 0);
