INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20006, 'Rotom Pokédex', 'Electric', null, 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'Its body is composed of plasma. It is known to infiltrate electronic devices and wreak havoc.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20007, 'Rotom Phone', 'Electric', null, 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'Its body is composed of plasma. It is known to infiltrate electronic devices and wreak havoc.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20008, 'Rotom Drone', 'Electric', null, 50, 65, 107, 105, 107, 86, 3.00, 3.00, 'Its body is composed of plasma. It is known to infiltrate electronic devices and wreak havoc.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (20009, 'Violet Core Minior', 'Rock', 'Flying', 60, 100, 60, 100, 60, 120, 3.00, 3.00, 'It feeds on dust in the atmosphere. The color of its core is said to be determined by the composition of the dust it eats.', 0, 0);
