INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50031, 'Ghost King Blacephalon', 'Ghost', 'Fire', 53, 127, 53, 151, 79, 107, 18.00, 130.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50032, 'United Pikachu', 'Electric', null, 35, 55, 40, 50, 50, 90, 4.00, 60.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50033, 'Rudolph Vulpix', 'Fire', null, 38, 41, 40, 50, 65, 65, 6.00, 99.00, 'In its belly burns a fire, which Vulpix spits out in the form of fireballs. When young, this Pokémon has but one white tail. As the Pokémon matures, this single tail splits into six.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50034, 'Angel Diglett', 'Ground', null, 10, 55, 25, 35, 45, 95, 2.00, 8.00, 'It flies through the sky at midnight. It searches for a Christmas tree without a tree topper so it can sit on top.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50035, 'Candy Cane Marowak', 'Ground', null, 60, 80, 110, 50, 80, 45, 10.00, 450.00, 'At Christmas eve, it replaces the bone with a candy cane to snack on a candy cane. This is the only time it lays down the bone.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50036, 'Mrs. Claus Jynx', 'Ice', 'Psychic', 65, 50, 35, 115, 95, 95, 14.00, 406.00, 'Appears to move to a rhythm of Christmas, as if it were dancing. It wiggles its hips as it walks to the jingle bells.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50037, 'Christmas Mareep', 'Electric', null, 55, 40, 40, 65, 45, 35, 6.00, 78.00, 'If you hang lights in its fleece, it will generate enough electricity to turn them on. Don’t pet it, you’ll get a painful shock.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50038, 'Santa Delibird', 'Ice', 'Flying', 45, 55, 45, 65, 45, 75, 9.00, 160.00, 'It has a generous habit of giving out presents to people and Pokémon, so it’s always shopping around for more presents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50039, 'Ornaments Spoink', 'Psychic', null, 60, 25, 35, 70, 80, 60, 7.00, 306.00, 'Spoink keeps an ornament on top of its head. The ornament functions to amplify this Pokémon\'s Christmas powers. It is therefore on a constant search for a bigger one.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50040, 'Poinsettia Lilligant', 'Grass', null, 70, 60, 75, 110, 75, 90, 11.00, 163.00, 'Essential oils made from Lilligant poinsettia flowers have a sublime scent. These are in a lot of homes during Christmas.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50041, 'Christmas Rowlet', 'Grass', 'Flying', 68, 55, 55, 50, 50, 42, 3.00, 15.00, 'During the day, it builds up energy via photosynthesis. At night, it flies silenty through the sky, scouting for the santa to bring his presents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50042, 'Wreath Comfey', 'Fairy', null, 51, 52, 90, 82, 110, 100, 1.00, 3.00, 'This Pokémon smells very nice. All comfey wear different kinds of wreaths, so each one has its own individual Christmas scent.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50043, 'Lights Pyukumuku', 'Water', null, 55, 60, 130, 30, 130, 5, 3.00, 12.00, 'They will get on land during Christmas eve to shine its lights on the back. They go back to the sea after New Year’s eve.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50044, 'Presents Komala', 'Normal', null, 65, 115, 65, 75, 95, 65, 4.00, 199.00, 'It remains asleep from birth to death as a result of the sedative music of Christmas that it hears all year long.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50045, 'Ornament Eldegoss', 'Grass', null, 60, 50, 90, 80, 120, 60, 5.00, 25.00, 'The ornament on the head of this Pokémon can be hung in the Christmas tree, shining bright.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50046, 'Cake Appletun', 'Grass', 'Dragon', 110, 85, 80, 100, 80, 30, 4.00, 130.00, 'Its body is covered with icing, and the skin on its back is especially yummy. Children used to have it as a snack at Christmas.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50047, 'Elf Impidimp', 'Dark', 'Fairy', 45, 45, 30, 55, 40, 50, 4.00, 55.00, 'It sneaks into people’s homes, puts presents underneath the Christmas tree and leaves via the chimney again.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50048, 'Snowflake Bronzor', 'Steel', 'Psychic', 57, 24, 86, 24, 86, 23, 5.00, 605.00, '', 0, 0);
