INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50088, 'Ice Yveltal', 'Ice', 'Flying', 126, 131, 95, 131, 98, 99, 58.00, 2030.00, '', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50089, 'Cupid Decidueye', 'Grass', 'Ghost', 78, 107, 75, 100, 100, 70, 16.00, 366.00, '', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50090, 'Bug Catcher Weedle', 'Bug', 'Poison', 40, 35, 30, 20, 20, 50, 3.00, 32.00, 'Beware of its net. It hides in grass and bushes where it hunts small bugs for its collection.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50091, 'Flower Paras', 'Bug', 'Grass', 35, 70, 55, 45, 55, 25, 3.00, 54.00, 'Burrows close to trees to cover itself. The flowers on its back gives it all the energy it needs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50092, 'Eggneton', 'Electric', 'Steel', 50, 60, 95, 120, 70, 70, 10.00, 600.00, 'This Pokémon is constantly putting out a powerful magnetic force. Most chocolate eggs are found when Eggneton approaches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50093, 'Egg Hunter Kangaskhan', 'Normal', null, 105, 95, 80, 40, 80, 90, 22.00, 800.00, 'There are records of Kangaskhan hiding chocolate eggs for their children to find on Easter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50094, 'Hatching Beautifly', 'Bug', 'Flying', 60, 70, 50, 100, 50, 65, 10.00, 284.00, 'Beautifly has a long mouth like a coiled needle, which is very convenient searching for hidden chocolate eggs in gardens. It rides the spring winds as it flits around gathering eggs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50095, 'Bird Nest Nuzleaf', 'Grass', 'Dark', 70, 70, 40, 60, 40, 60, 10.00, 280.00, 'They live in holes bored in large trees. The sound of Nuzleaf\'s grass flute lets birds whistle in joy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50096, 'Egg Basket Buneary', 'Normal', null, 55, 66, 44, 44, 56, 85, 4.00, 55.00, 'Buneary can crack eggs by rolling up their ears and then striking with the force created by unrolling them. This attack is useful for hard boiled eggs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50097, 'Spring Blooming Diancie', 'Rock', 'Fairy', 50, 100, 150, 100, 150, 50, 7.00, 88.00, 'It can instantly create many flowers by shaking its head to throw out seeds from the big flower on its head.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50098, 'Egg Searching Steenee', 'Grass', null, 52, 40, 48, 40, 48, 62, 7.00, 82.00, 'Any Corvisquire that pecks at this Pokémon will be greeted with a smack from the bag its wearing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50099, 'Flower Pheromosa', 'Bug', 'Fighting', 71, 137, 37, 137, 37, 151, 18.00, 250.00, 'Although it\'s alien to this world, It\'s enjoying the sunny fashion for this Spring.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50100, 'Anniversary Lapras', 'Water', 'Ice', 130, 85, 80, 85, 95, 60, 25.00, 2200.00, 'This gentle Pokémon loves to give people rides on its back. During the celebration, it covers itself with cake cream for everyone to enjoy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50101, 'Skater Wooper', 'Water', 'Ground', 55, 45, 45, 25, 25, 15, 4.00, 85.00, 'Wooper usually lives in water. However, it occasionally comes out onto land in search of food. There it discovered a skate shoe which made it more mobile on land!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50102, 'Cupcake Alcremie', 'Fairy', null, 65, 60, 75, 110, 121, 64, 3.00, 5.00, 'When Alcremie is content, it magically makes cupcakes for all to share.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50103, 'Pride Mew', 'Psychic', null, 100, 100, 100, 100, 100, 100, 4.00, 40.00, 'Its DNA is said to contain the genetic codes of all Pokémon and being neither male nor female at heart.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50104, 'Pride Bellossom', 'Grass', null, 75, 80, 95, 90, 100, 50, 4.00, 58.00, 'Bellossom gather at times and appear to dance. They go in groups and invite everyone to join in on the ritual.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50105, 'Pride Unown', 'Psychic', null, 48, 72, 48, 72, 48, 48, 5.00, 50.00, 'Its shape resembles the non-binary symbol that is known throughout the world.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50106, 'Pride Zigzagoon', 'Normal', null, 38, 30, 41, 30, 41, 60, 4.00, 175.00, 'Zigzagoon restlessly wanders everywhere at all times. This Pokémon does so because it is very curious, especially with parades and celebrations in town.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50107, 'Pride Gardevoir & Delphox', 'Psychic', 'Fairy', 68, 65, 65, 125, 115, 80, 16.00, 484.00, 'They have the ability to read the future. If they sense impending danger to a friend, these Pokémon are said to unleash their psychokinetic and flame energy at full power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50108, 'Pride Masquerain', 'Bug', 'Flying', 70, 60, 62, 100, 82, 80, 8.00, 36.00, 'Masquerain shows love with the colourful pattern on its antennas. This Pokémon flaps its four wings to freely fly in any direction - even sideways and backwards - as if it were a helicopter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50109, 'Pride Milotic', 'Water', null, 95, 60, 79, 100, 125, 81, 62.00, 1620.00, 'Its lovely scales are described as rainbow colored. For Pride, they wear the colours of blue, yellow and pink to represent Pan.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50110, 'Pride Piplup', 'Water', null, 53, 51, 53, 61, 56, 40, 4.00, 52.00, 'It\'s an adorable little thing - as cute as any child - but it\'s also prideful, unwilling to let others tell it what to do.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50111, 'Pride Roserade', 'Grass', 'Poison', 60, 70, 65, 125, 105, 90, 9.00, 145.00, 'With the movements of a dancer, it strikes with poses of all sorts to show its strength and pride.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50112, 'Pride Arceus', 'Normal', null, 120, 120, 120, 120, 120, 120, 32.00, 3200.00, 'It is said to have emerged from a rainbow in a place where there was nothing, then shaped the world.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50113, 'Pride Rufflet', 'Normal', 'Flying', 70, 83, 50, 37, 50, 60, 5.00, 105.00, 'They crush berries with their talons. They bravely stand up to any opponent, no matter how strong it is.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50114, 'Pride Sylveon', 'Fairy', null, 95, 65, 65, 110, 130, 60, 10.00, 235.00, 'It sends a soothing aura from its ribbon-like feelers to show love.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50115, 'Pride Toucannon', 'Normal', 'Flying', 80, 120, 75, 75, 75, 60, 11.00, 260.00, 'Known for forming harmonious couples no matter which gender, this Pokémon is brought to wedding ceremonies as a good luck charm.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50116, 'Pride Comfey', 'Fairy', null, 51, 52, 90, 82, 110, 100, 1.00, 3.00, 'It stretches sticky vines out from its head and picks flowers to adorn itself with. When the colours form a rainbow, it\'s the happiest it can ever be.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50117, 'Pride Tinkaton', 'Fairy', 'Steel', 85, 75, 77, 70, 105, 94, 7.00, 1128.00, 'This intelligent Pokémon has a very daring disposition. It loves to dare people to take its flag. Whoever loses, gets a firm hug.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50118, 'Pride Tandemaus', 'Normal', null, 50, 50, 45, 40, 45, 75, 3.00, 18.00, 'Tandemaus stick together no matter what. They help others and stay in contact throughout their whole lives.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50119, 'Camp Leader Quagsire', 'Water', 'Ground', 95, 85, 85, 65, 65, 35, 14.00, 750.00, 'A loving Pokémon. It cares about everyone in camp and is there for you when you need.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50120, 'Fishing Smeargle ft. Magikarp', 'Normal', null, 55, 20, 35, 20, 45, 75, 12.00, 580.00, 'It gets its food by using its tail like a fishing rod. It catches more than 50 fish every day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50121, 'Tent Snorunt', 'Ice', null, 50, 50, 50, 50, 50, 50, 7.00, 168.00, 'It is said that visiting a Tent Snorunt will give you luck. It can withstand heat of 110 degrees Fahrenheit.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50122, 'Timber Timburr', 'Fighting', null, 75, 80, 55, 25, 35, 35, 6.00, 125.00, 'It fights by swinging an axe around. It is close to evolving when it can chop down small trees without difficulty.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50123, 'Camper Charjabug', 'Bug', 'Electric', 57, 82, 95, 55, 75, 36, 30.00, 105.00, 'Its body is capable of storing electricity. On camping trips, people are grateful to have one around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50124, 'Kettle Polteageist', 'Ghost', null, 60, 65, 65, 134, 114, 70, 2.00, 4.00, 'Though risky to drink, this Pokémon’s campfire-boiled tea tastes delicious. Gourmets who have no fear of danger drink its tea day after day.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50125, 'Marshmallow Maushold', 'Normal', null, 74, 75, 70, 65, 75, 111, 3.00, 23.00, 'The larger marshmallows protect the little ones during battles. When facing other opponents, they use gooey melted marshmallow strings to trap them in battle.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50126, 'Pile of Leaves Swalot', 'Grass', 'Poison', 100, 73, 83, 73, 83, 55, 17.00, 800.00, 'It can swallow its enemies in one gulp. It secretes a dirty, damp-smelling fluid from within the leaves surrounding its body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50127, 'Toadsie', 'Grass', 'Water', 41, 56, 40, 62, 44, 71, 3.00, 70.00, 'It protects its skin by covering its body in mud and leaves. Beneath the innocence, it keeps a watchful eye on its surroundings, looking for any flies it can catch.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50128, 'Pumpkaboo Spice Latte', 'Ghost', null, 49, 66, 70, 44, 55, 51, 4.00, 50.00, 'Its body is full to the brim of sweet pumpkin spice latte. It always stays steaming hot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50129, 'Autumn Dachsbun', 'Grass', 'Fairy', 57, 80, 115, 50, 80, 95, 5.00, 149.00, 'The leaves on the surface of this Pokémon’s skin change colour as Autumn rolls around, and its body has the soothing aroma of maple.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50130, 'Mushroom Nacli', 'Rock', null, 55, 55, 75, 35, 35, 25, 4.00, 160.00, 'The ground scrapes its body as it travels, causing it to leave mushroom pieces and grass behind. Mushrooms are always being grown and replenished inside Nacli’s body.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50131, 'Evil Mightyena', 'Dark', 'Fire', 70, 90, 70, 60, 60, 70, 10.00, 370.00, 'It is always the leader of a pack of Mightyenas, it will never ally with another Evil Mightyena, nor will it ever listen to any other Pokémon or humans.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50132, 'Voodoo Spinda', 'Normal', 'Dark', 60, 60, 60, 60, 60, 60, 11.00, 50.00, 'No two Voodoo Spinda have the same pattern of stitches and colours. Their tottering steps hinder the aim of foes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50133, 'Pumpkin Gothorita', 'Psychic', 'Dark', 60, 45, 70, 75, 85, 55, 7.00, 180.00, 'Using its psychic power, it arranges pumpkins to form the shapes of evil spirits. Some people believe this Pokémon came from outer space.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50134, 'Overgrown Shiinotic', 'Grass', 'Poison', 60, 45, 80, 90, 100, 30, 10.00, 115.00, 'If you see a light deep in a forest at night, run as far as you can. Shiinotic will get you with its overgrown roots.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50135, 'Sage of Foliage', 'Grass', 'Fairy', 60, 130, 80, 60, 60, 70, 12.00, 392.00, 'The mushrooms on its tail give off a toxic cloud. It knocks out foes with quick, virtually invisible punches.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50136, 'Sage of Shadows', 'Dark', 'Ghost', 70, 120, 65, 45, 85, 125, 11.00, 340.00, 'It travels with other sages, leaving signs for one another on trees and rocks. It brings down its prey with shadow magic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50137, 'Sage of Snaring', 'Rock', 'Psychic', 55, 75, 85, 25, 25, 15, 4.00, 180.00, 'When it detects a noise, it starts to move. The energy core inside it can be used to make objects fly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50138, 'Sage of Flames', 'Fire', 'Fairy', 59, 59, 58, 90, 70, 73, 10.00, 145.00, 'When the staff is held high, the flame at the top will give a bright light. The sage can use it to lead the way in the darkest places.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50139, 'Ruined Golurk', 'Ground', 'Dark', 89, 124, 80, 55, 80, 55, 28.00, 3300.00, 'Its seal shattered, the infernal energy inside the Ruined Golurk seeps from within. The Ruined Golurk now roams the ruined forest, as it slowly loses grasp of the identity it once had.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50140, 'Hero Golurk', 'Ground', 'Fighting', 89, 124, 80, 55, 80, 55, 28.00, 3300.00, 'The Hero Golurk, restored through the valiant efforts of the Sinister Sages, actively protects other Pokémon from the Foul Beasts that roam the land. It seeks to make things right with those it has hurt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50141, 'Harvesting Ledian', 'Bug', 'Flying', 55, 35, 50, 55, 110, 85, 14.00, 356.00, 'It is said that in lands with clean air, where the stars fill the sky, there live Ledian in countless numbers. They gather during harvest season to help prepare for winter.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50142, 'Cooking Chespin', 'Grass', null, 56, 61, 65, 48, 45, 38, 4.00, 90.00, 'The quills on its head are usually sprouts. Nearing winter, the sprouts turn yellow, announcing the harvest season.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50143, 'Nibbling Bunnelby', 'Normal', null, 38, 36, 38, 32, 36, 57, 4.00, 50.00, 'It’s very sensitive to smell. It knows where the best carrots are found.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50144, 'Pear Flapple', 'Grass', 'Dragon', 70, 110, 80, 95, 60, 70, 3.00, 10.00, 'During the harvest season when an Applin evolves, it chooses the best fruit of the season. Humans watch evolving Applins carefully to determine what the fruit of the year will be.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50145, 'Santa H. Zorua', 'Normal', 'Ghost', 35, 60, 40, 85, 40, 70, 7.00, 125.00, 'It changes into the forms of others to disguise itself while bringing presents. Apparently, its true form is Santa Claus!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50146, 'Pyjama Minccino', 'Ice', null, 55, 50, 40, 40, 40, 75, 4.00, 58.00, 'These Pokémon like things neat and tidy during Christmas. They are always watching the house and helping decorate the Christmas tree.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50147, 'Reindeer Deerling', 'Normal', 'Grass', 60, 60, 50, 40, 50, 75, 6.00, 195.00, 'The color and scent of their fur change to match the Christmas celebration. People use it to mark the Christmas days.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50148, 'Conductor Dragonite', 'Dragon', 'Flying', 91, 134, 95, 100, 100, 80, 22.00, 2100.00, 'It can fly despite its big and bulky physique. It circles the North Pole in just half an hour.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50149, 'Pyjama Plusle & Minun', 'Electric', null, 60, 50, 40, 85, 75, 95, 4.00, 84.00, 'During the Winter, Plusle & Minun use their sparks to light candles and start a cozy fire to gather around.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50150, 'Fireworks Cosmog', 'Psychic', 'Fire', 43, 29, 31, 29, 31, 37, 2.00, 1.00, 'Its body is gaseous and frail. During the Holiday celebrations, it grows fast as it collects all the firework dust from the atmosphere.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50151, 'Train Varoom', 'Steel', 'Fairy', 45, 70, 63, 30, 45, 47, 10.00, 350.00, 'The steel section is Train Varoom’s actual body. This Pokémon pulls The Poké Express to the North Pole during Christmas!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50152, 'Christmas Tree Smoliv', 'Grass', null, 41, 35, 45, 58, 51, 30, 3.00, 65.00, 'This Pokémon converts snowflakes into baubles, which it stores in pine trees. It can easily go a whole week dancing around Christmas trees out of joy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50153, 'Christmas Tree Dolliv', 'Grass', null, 52, 53, 60, 78, 78, 33, 6.00, 119.00, 'It basks in the light of the stars to its heart’s content until the star on its head shines bright. After that, Christmas Tree Dolliv places the star on top of a decorated pine tree and goes on a journey for a new star.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50154, 'Christmas Tree Arboliva', 'Grass', 'Fairy', 78, 69, 90, 125, 109, 39, 14.00, 482.00, 'This Pokémon gathers friends by launching its rich, shiny lights at them and pulling them closer to itself.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50155, 'Snowmadam', 'Bug', 'Ice', 60, 59, 85, 79, 105, 36, 5.00, 65.00, 'Its cloak looks to be made of soft, fluffy snow, but don\'t be deceived. This packed, hardened snow offers it sturdy protection and gives frostbite to any who touch it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50156, 'Lovebird Unfezant', 'Fairy', 'Flying', 80, 115, 80, 65, 55, 93, 12.00, 290.00, 'Males swing their head plumage to attract females. The females\' flying abilities are shown to impress the male.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50157, 'Snoozing Meowstic', 'Psychic', null, 74, 48, 76, 83, 81, 104, 6.00, 85.00, 'The defensive instinct of the males is strong. It\'s when they\'re protecting their partners that they unleash their full power.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50158, 'Polar Stufful', 'Ice', 'Fighting', 70, 75, 50, 45, 50, 50, 5.00, 68.00, 'The way it protects itself by flailing its arms may be an adorable sight, but stay well away. This is flailing that can snap thick tree trunks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50159, 'Snow Leopard Sneasler', 'Fighting', 'Ice', 80, 130, 60, 40, 80, 120, 13.00, 430.00, 'This catlike subspecies of Sneasler has further adapted to its frozen climate, becoming an even more elusive, deadly predator.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50160, 'Overgrown Mawile', 'Steel', 'Grass', 50, 85, 85, 55, 55, 50, 6.00, 115.00, 'Attached to its head is a huge set of several jaws formed by horns. These can chew through iron beams.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50161, 'Blossom Cherrim', 'Grass', null, 70, 60, 70, 87, 78, 85, 5.00, 93.00, 'It blooms during times of strong sunlight. It tries to make up for everything it endured as a bud. The more blossom it has, the darker their past.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50162, 'Overgrown Carnivine', 'Grass', null, 74, 100, 72, 90, 72, 46, 14.00, 270.00, 'It binds itself to trees in marshes. It attracts prey with its sweet-smelling flowers and gulps them down.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50163, 'Egg Painter Meowth', 'Normal', null, 40, 45, 35, 40, 40, 90, 4.00, 42.00, 'Adores circular objects. Wanders the forests to look for dropped eggs to paint.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50164, 'Easter Egg Azurill', 'Normal', 'Fairy', 50, 20, 40, 20, 40, 20, 2.00, 20.00, 'It distracts by flinging around its tail in the bushes, showing as if it’s an Easter egg. When close enough, it jumps out of the bushes to surprise you.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50165, 'Flower Family Swanna', 'Water', 'Flying', 75, 87, 63, 87, 63, 98, 13.00, 242.00, 'Swanna start to gather flowers at dawn. It makes flower crowns for the new duckletts.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50166, 'Easter Togedemaru', 'Electric', 'Steel', 65, 98, 63, 40, 73, 96, 3.00, 33.00, 'When it\'s surprised or excited, the 14 fur spikes on its back will stand up and light up in different colours.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50167, 'Egg Forager Lechonk', 'Normal', null, 54, 45, 40, 35, 45, 35, 5.00, 102.00, 'It searches for food all day. It possesses a keen sense of smell but doesn’t use it for anything other than foraging chocolate eggs.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50168, 'Birthday Cake Alopix', 'Ice', null, 38, 41, 40, 50, 65, 65, 6.00, 99.00, 'It looks like a birthday cake come to life. If you approach it because it\'s cute, it could give you a slice of cake as a reward.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50169, 'Pasta Bolognese Tangela', 'Fire', null, 65, 55, 115, 100, 40, 60, 10.00, 350.00, 'It is cloaked entirely in al dente pasta and meatballs, preventing any glimpse of its true identity. The pasta, meatballs and various spices make for a hearty meal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50170, 'Temaki Gulpin', 'Water', null, 70, 43, 53, 43, 53, 40, 4.00, 103.00, 'It has a small heart and brain. Its stomach comprises most of its body along with beansprouts and other fillings, all wrapped in nori.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50171, 'Ice Cream Spheals', 'Ice', 'Water', 70, 40, 50, 55, 50, 25, 8.00, 395.00, 'During the summer when the weather warms, Ice Cream Spheals prefer living in groups on the cone to keep each other cool.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50172, 'Clamacaron', 'Water', null, 35, 64, 85, 74, 55, 32, 4.00, 525.00, 'It makes a single peach flavored pearl during its lifetime. The pearl along with the crumbly shell is said to amplify the fruity flavor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50173, 'Fancy Cutlery Doublade', 'Steel', 'Ghost', 59, 110, 150, 45, 49, 35, 8.00, 45.00, 'The two cutlery employ a strategy of rapidly alternating between fork and knife to spear and slice food elegantly.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50174, 'Goomy Brûlée', 'Dragon', null, 45, 50, 35, 55, 75, 40, 3.00, 28.00, 'It\'s covered in a caramel membrane that makes any person desire a bite.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50175, 'Strawberry Shortcake Applin', 'Grass', 'Dragon', 40, 40, 80, 40, 40, 20, 2.00, 5.00, 'It lives inside a slice of strawberry shortcake. When a Strawberry Shortcake Applin is separated from its slice, its body loses sugar and the Pokémon grows weak.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50176, 'Dango Falinks', 'Fighting', null, 65, 100, 100, 70, 60, 75, 30.00, 620.00, 'The leader dango, distinguished by the number of strawberries, uses the skewer to signal the others when it\'s time to rearrange.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50177, 'Onigiri Bellibolt', 'Grass', null, 109, 64, 91, 103, 83, 45, 12.00, 1130.00, 'When this Pokémon expands and contracts its rice-y body, the seaweed on its stomach keeps the rice from popping out.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50178, 'Pride Ampharos', 'Electric', null, 90, 75, 85, 115, 90, 55, 14.00, 615.00, 'When it gets dark, the rainbow light from its bright, shiny horns form a rainbow in the sky.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50179, 'Rainbow Minior', 'Rock', 'Flying', 60, 60, 100, 60, 100, 60, 3.00, 400.00, 'Although its outer shell is uncommonly durable, the shock of falling to the ground smashes the shell to smithereens, revealing its mesmerizing colourful patterns underneath.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50180, 'Painted Acorn Skwovet', 'Normal', null, 70, 55, 55, 35, 35, 25, 3.00, 25.00, 'It eats all kinds of coloured berries nonstop—a habit that has made it more resilient than it looks. It\'ll show up on farms, searching for the brightest coloured berries.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50181, 'Gradient Chi-Yu', 'Dark', 'Fire', 55, 80, 80, 135, 120, 100, 4.00, 49.00, 'It controls the colours of flames burning at over 3,000 degrees Celsius. It casually swims through the sea of lava it creates by melting rock and sand.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50182, 'Olympic Flame Moltres', 'Fire', 'Flying', 90, 100, 90, 125, 85, 90, 20.00, 600.00, 'Known as the legendary bird of fire. Moltres is the perfect Pokémon to carry the Olympic Flame into the stadium.', 0, 1);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50183, 'Archery Sentret', 'Normal', null, 35, 46, 34, 35, 45, 20, 8.00, 60.00, 'They take turns helping with archery when the team is finished. They sometimes run in too fast and jump behind a target for protection.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50184, 'Waterpolo Ducklett', 'Water', 'Flying', 62, 44, 50, 44, 50, 55, 5.00, 55.00, 'These bird Pokémon are excellent at waterpolo. They swim around in the water throwing balls and plants at each other to train.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50185, 'Relay Race Raboot', 'Fire', null, 65, 86, 60, 55, 60, 94, 6.00, 90.00, 'While it prides itself on its varied kicking moves, it can also run really fast once its flames have heated up its feet.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50186, 'Fencinteleon', 'Water', 'Fighting', 70, 85, 65, 125, 65, 120, 19.00, 452.00, 'It uses special lenses in its eyes to sense things about its opponents—like their body heat—then poke once it identifies a weak spot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50187, 'Boxel', 'Electric', 'Fighting', 40, 38, 35, 54, 35, 40, 4.00, 110.00, 'It stores poison in an internal poison sac and secretes that poison through its skin. You better not touch its skin during the fight!', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50188, 'Cheerleader Oricorio', 'Electric', 'Flying', 75, 70, 70, 98, 70, 93, 6.00, 34.00, 'It lifts the team spirit with its cheerful dance moves. They are so good at dancing, that even the opponents gets a spirit boost.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50189, 'Moon Fairy Mudkip', 'Water', 'Fairy', 50, 70, 50, 50, 50, 40, 4.00, 76.00, 'The fin on Mudkip\'s head acts as highly sensitive radar. Using this fin to sense magic in the air, this Pokémon can determine what is taking place around it without using its eyes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50190, 'Flower Fairy Flabébé', 'Grass', 'Fairy', 44, 38, 39, 61, 79, 42, 1.00, 1.00, 'When it finds a flower it likes, it dwells on that flower its whole life long and even sleeps on the flower to draw energy to heal.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50191, 'Fire Fairy Salandit', 'Fire', 'Fairy', 48, 44, 40, 71, 40, 77, 6.00, 48.00, 'Its venom sacs produce a fluid that this Pokémon then heats up with the flame in its tail. This process creates Salandit\'s fire wings.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50192, 'Papel Picado Pidgey', 'Normal', 'Flying', 40, 45, 40, 35, 35, 56, 3.00, 18.00, 'A common sight in cities and villages. It flies between homes to hang Papel Picado.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50193, 'Sombrero Lotad', 'Water', 'Grass', 40, 30, 30, 40, 50, 30, 5.00, 26.00, 'Its sombrero is its pride, which it shows off during Día de Muertos.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50194, 'Sugar Duskull', 'Ghost', null, 20, 40, 90, 30, 90, 25, 8.00, 150.00, 'Duskull can pass through any wall no matter how thick it may be. Once this Pokémon chooses a target, it will dance around them until the break of dawn.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50195, 'Honoring Yamask', 'Ghost', null, 38, 30, 85, 55, 65, 30, 5.00, 15.00, 'These Pokémon arose from the spirits of people interred in graves. They search for their families on Día de Muertos, connecting with loved ones and sharing memories of its former life.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50196, 'Monarch Gothitelle', 'Psychic', null, 70, 55, 95, 95, 110, 65, 15.00, 440.00, 'Instead of gazing at the stars for the future, Monarch Gothitelle gazes into the past, through the souls of the departed, in order to share favored memories with their loved ones on Día de Muertos.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50197, 'Alebrije Pyroar', 'Fire', 'Ghost', 86, 68, 72, 109, 66, 106, 15.00, 815.00, 'Its vibrant, colorful fur shines brightly as it flies through the sky, guiding spirits to their loved ones on Día de Muertos.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50198, 'La Catrina Hisuian Lilligant', 'Grass', 'Fighting', 70, 105, 75, 50, 75, 105, 12.00, 192.00, 'The fragrance of its flower differs slightly on Día de Muertos, its scent becomes sweeter. Sniffing the aroma calms your heart and mind.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50199, 'Sweater Teddiursa', 'Normal', null, 60, 80, 50, 50, 50, 40, 6.00, 88.00, 'Before it gets cold in wintertime, its habit is to hoard warm sweaters and blankets to make its home cosy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50200, 'Leafy Baltoy', 'Grass', 'Psychic', 40, 40, 55, 40, 70, 55, 5.00, 215.00, 'It moves by spinning on its foot. It makes little leafy whirlwinds with its movement.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50201, 'Cosy Perrserker', 'Steel', null, 70, 110, 100, 50, 60, 50, 8.00, 280.00, 'This Pokémon lives for the thrill of colder times. It drinks hot choco while watching the leaves fall.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50202, 'Santa Snorlax', 'Normal', null, 160, 110, 65, 65, 110, 30, 21.00, 4600.00, 'This glutton appears in houses without warning and devours the entirety of their milk and cookies—such occurrences have long been counted among the merriest of surprises.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50203, 'Music Box Bellossom', 'Grass', null, 75, 80, 95, 90, 100, 50, 4.00, 58.00, 'When the jolly snowfall season starts, cranking the spring draws it out to dance in the open.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50204, 'Doll Lopunny', 'Normal', null, 65, 76, 84, 54, 96, 105, 12.00, 333.00, 'Once the hot seasons end, its coat will be replaced with soft wooly fur that holds a lot of insulating air in preparation for the colder weather.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50205, 'Snowglobe Glaceon', 'Ice', null, 65, 60, 110, 130, 95, 65, 8.00, 259.00, 'It lowers its body heat to freeze its fur. The hairs then become like needles it can fire.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50206, 'Elf Audino', 'Normal', null, 103, 60, 86, 60, 86, 50, 11.00, 310.00, 'This Pokémon has a kind heart. By touching with its feelers, Elf Audino can find out other creatures’ wishes and desires.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50207, 'Grinchsnarl', 'Dark', 'Fairy', 95, 120, 65, 95, 75, 60, 15.00, 610.00, 'It lives deep within the forest. Even after evolving into this splendid form, it hasn’t given up on its mischievous antics and holiday pranks.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50208, 'Candy Cane Wiglett', 'Water', null, 10, 55, 25, 35, 25, 95, 12.00, 18.00, 'Though they look like candy canes, Candy Cane Wiglett is a living pokémon. The resemblance seems to be a coincidental result of festive adaptation.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50209, 'Gingerbread Gimmighoul', 'Ghost', null, 45, 30, 70, 75, 70, 10, 3.00, 50.00, 'It lives inside a gingerbread house. Sometimes it gets left in gift shop corners during the holidays since no one realizes it’s actually a Pokémon.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50210, 'Wooden Serperior', 'Grass', null, 75, 75, 95, 75, 95, 113, 33.00, 630.00, 'With its tail, Serperior holds a lantern to celebrate Lunar New Year. Its wooden body radiates charm and grace.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50211, 'Paper Lantern Lampent', 'Ghost', 'Fire', 60, 40, 60, 95, 60, 55, 6.00, 130.00, 'This Pokémon appears on Lunar New Year, just before the celebration starts, so kids wait for its arrival.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50212, 'Lion Dancer Litleo', 'Fire', 'Normal', 62, 50, 58, 73, 54, 72, 6.00, 135.00, 'This hot-blooded Pokémon is filled with energy. When it gets excited or starts dancing, its body gets hot.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50213, 'Baby Ducklett', 'Water', 'Flying', 62, 44, 50, 44, 50, 55, 5.00, 55.00, 'These bird Pokémon are excellent divers. They can swim from day one and start diving after the first week.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50214, 'Pacifier Pancham', 'Fighting', null, 67, 82, 62, 46, 48, 43, 6.00, 80.00, 'When Pancham are born, they don’t start glaring immediately—they only begin to glare once they swap their pacifier for a leaf to chew on.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50215, 'Baby Toy Klefki', 'Steel', 'Fairy', 57, 80, 91, 80, 87, 75, 2.00, 30.00, 'These key collectors love to play around with toy keys when they live in a household with babies.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50216, 'Hearts Fidough', 'Fairy', null, 37, 55, 70, 30, 55, 65, 3.00, 109.00, 'This Pokémon is sweet, and smooth to the touch. Fragrance in Fidough’s breath attracts customers into the bakery.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50217, 'Love Bombirdier', 'Flying', 'Fairy', 70, 103, 85, 60, 85, 82, 15.00, 429.00, 'Bombirdier uses the apron on its chest to bundle up baby Pokémon, which it carries to their parents.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50218, 'Shamrock Meganium', 'Grass', null, 80, 82, 100, 83, 100, 80, 18.00, 1005.00, 'The aroma that rises from the flowers contains a substance that makes anyone happy.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50219, 'Treasure Turtwig', 'Grass', null, 55, 68, 64, 45, 55, 31, 4.00, 102.00, 'The shell on its back carries a cauldron. On a very happy Turtwig, the cauldron is full of gold.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50220, 'Good Luck Sinistea', 'Ghost', 'Grass', 40, 45, 45, 74, 54, 50, 1.00, 2.00, 'During St Patrick\'s Day, Sinistea will "drown the shamrock" in its tea before throwing it over the shoulder for good luck.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50221, 'Porygon-X', 'Normal', 'Electric', 85, 80, 70, 135, 75, 90, 9.00, 340.00, 'An attempt to fix its faulty programming failed, corrupting it further and resulting in this glitched form.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50222, 'Error Darkrai', 'Dark', 'Electric', 70, 90, 90, 135, 90, 125, 15.00, 505.00, 'In a world dominated by AI, a powerful Darkrai is trapped in a decaying virtual Pokémon battle system. Twisted by data corruption, it moves between reality and broken digital realms, dragging victims into a fractured dreamscape.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50223, 'Glitched Beta Arceus', 'Electric', null, 120, 120, 120, 120, 120, 120, 32.00, 3200.00, 'In an alternate universe, Glitched Beta Arceus emerged from equations which it bends to shape the world in bits and bytes.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50224, 'Sylvirus', 'Fairy', null, 95, 65, 65, 110, 130, 60, 10.00, 235.00, 'Eevee’s unstable genes have led to a genetic malfunction during evolution, resulting in Sylvirus’ misshapen and jagged appearance.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50225, 'Corrupted Blacephalon', 'Fire', 'Ghost', 53, 127, 53, 151, 79, 107, 18.00, 130.00, 'An error caused by corrupted ultra wormholes makes its explosions stronger than any before it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50226, 'Egg Nest Lapras', 'Water', 'Ice', 130, 85, 80, 85, 95, 60, 25.00, 2200.00, 'A gentle soul that can read the minds of others. It can ferry eggs across the sea on its back.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50227, 'Cracked Ditto', 'Normal', null, 48, 48, 48, 48, 48, 48, 3.00, 40.00, 'It can transform into anything. It likes to fool people during Easter by transforming into an Easter egg.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50228, 'Easter Bidoof', 'Normal', null, 59, 45, 40, 35, 40, 31, 5.00, 200.00, 'It lives in groups by the water. During Easter, it plays the role of Easter Bunny for nearby villages to entertain the children.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50229, 'Cube Slime Grimer', 'Poison', null, 80, 80, 50, 40, 50, 25, 9.00, 300.00, 'Appears in filthy dungeons. Thrives by sucking up metals like swords and armor from adventurers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50230, 'Guardian Dragonite', 'Dragon', 'Flying', 91, 134, 95, 100, 100, 80, 22.00, 2100.00, 'It is said that this Pokémon lives somewhere deep in the mountains and that it flies. However, it is only a rumor.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50231, 'Banshee Banette', 'Ghost', 'Fairy', 64, 115, 65, 83, 63, 65, 11.00, 125.00, 'Strong feelings of grief turned a soul into a Pokémon. If it opens its mouth, its cursed energy escapes.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50232, 'Wizard Kricketune', 'Bug', null, 77, 85, 51, 55, 51, 65, 10.00, 255.00, 'By allowing its cry to resonate in the hollow of its belly, it produces magic.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50233, 'Ranger Floatzel', 'Water', null, 85, 105, 55, 85, 50, 115, 11.00, 335.00, 'It is a common sight around cave entrances. It is known to rescue people and keep evil at bay.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50234, 'Rogue Toxicroak', 'Poison', 'Fighting', 83, 106, 65, 86, 65, 85, 13.00, 444.00, 'Its knuckle claws secrete a toxin that is used for battles in dungeons.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50235, 'Bard Purrloin', 'Dark', null, 41, 50, 37, 50, 37, 66, 4.00, 101.00, 'Its cute music act is a ruse. When victims let down their guard, they find their items taken. It disappears in the night after every performance.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50236, 'Minotaur Bouffalant', 'Normal', null, 95, 110, 95, 40, 95, 55, 16.00, 946.00, 'These Pokémon live in solitude. Their fluffy fur absorbs damage, even if they strike foes with a fierce headbutt.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50237, 'Cursed Blade Honedge', 'Steel', 'Ghost', 45, 80, 100, 35, 37, 28, 8.00, 20.00, 'Apparently, this Pokémon is born when an evil spirit inhabits a sword. It attaches itself to people and drinks their life force.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50238, 'Druid Zarude', 'Dark', 'Grass', 105, 120, 105, 70, 95, 105, 18.00, 700.00, 'Within dense forests, this Pokémon lives in a grove with others of its kind. It’s focused on the health of the forest and sees it as its purpose to keep the forest alive.', 1, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50239, 'Barbarian Bloodmoon Ursaluna', 'Ground', 'Fighting', 113, 70, 120, 135, 65, 52, 27.00, 3333.00, 'It survived many hunts that led it to take on a unique appearance and gain special powers.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50240, 'Pride Queen Bruxish', 'Water', 'Psychic', 68, 105, 70, 70, 70, 92, 9.00, 190.00, 'When it unleashes its psychic power from the protuberance on its head, the sound of music and dance echoes through the area.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50241, 'Proud Crocalor', 'Fire', 'Psychic', 81, 55, 78, 90, 58, 49, 10.00, 307.00, 'This Crocalor loves camping, and is an expert at starting fires. It wears a hat to protect other camp members from getting burned when they stand close.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50242, 'Celebrating Alolan Exeggutor ft. Komala', 'Grass', 'Dragon', 95, 105, 85, 125, 75, 45, 109.00, 4156.00, 'Its three heads think independently. However, they respect each other and never appear to squabble.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50243, 'Umbrella Farfetch\'d', 'Normal', 'Flying', 52, 90, 55, 58, 62, 60, 8.00, 150.00, 'It doesn’t like to be in the rain. That’s why it always brings its umbrella.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50244, 'Cloubat', 'Psychic', 'Water', 67, 57, 55, 77, 55, 114, 9.00, 105.00, 'It shakes its tail vigorously when it emits thunder sounds strong enough to reduce concrete to rubble.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50245, 'Foombrella', 'Grass', 'Poison', 69, 55, 45, 55, 55, 15, 2.00, 10.00, 'It lures humans with the hat that looks just like an umbrella, then releases poison spores.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50246, 'Muddy Goomy', 'Dragon', 'Water', 45, 50, 35, 55, 75, 40, 3.00, 28.00, 'Its source of protection is its muddy, germ-laden brown puddle. Anyone who touches it needs some thorough hand-washing.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50247, 'Raincoat Grafaiai', 'Poison', 'Normal', 63, 95, 65, 80, 72, 110, 7.00, 272.00, 'Every Grafaiai dresses for each occasion to paint its individual patterns all over the city.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50248, 'Chicombusken', 'Steel', 'Fighting', 60, 85, 60, 85, 60, 55, 9.00, 195.00, 'Chicombusken toughens up its legs and thighs by running after trainers in their homes. This Pokémon’s legs possess both speed and power, enabling it to dole out ten kicks in one second.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50249, 'Soluna', 'Rock', 'Psychic', 90, 95, 85, 55, 65, 70, 12.00, 1540.00, 'A fused Pokémon, never seen before. It floats in the air, staring silently.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50250, 'Drifboy', 'Ghost', 'Flying', 150, 80, 44, 90, 54, 80, 12.00, 150.00, 'It carries people and Pokémon when it flies. But nobody knows where you end up…', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50251, 'Leavanette', 'Ghost', 'Grass', 75, 103, 80, 70, 80, 92, 12.00, 205.00, 'This Pokémon has strong attacking instincts. The leaf-like arms are sharp enough to slice a thick steel beam in half with one stroke.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50252, 'Foroark', 'Steel', 'Dark', 60, 105, 60, 120, 60, 105, 16.00, 811.00, 'If it thinks humans are going to discover its den, Foroark will scare them almost to death.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50253, 'Bonnersby', 'Steel', 'Ground', 85, 56, 77, 50, 77, 78, 10.00, 424.00, 'As powerful as an excavator, it can heft boulders of a ton or more with ease. Watch out, or you might become a pancake.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50254, 'Fazwear', 'Steel', 'Fighting', 120, 125, 80, 55, 60, 60, 21.00, 1350.00, 'This Pokémon has the habit of chasing its companions. Many trainers have left this world after last being seen with it.', 0, 0);
INSERT INTO pokedex.pokemon (number, name, type_1, type_2, hp, attack, defense, sp_atk, sp_def, speed, height, weight, description, mythical, legendary) VALUES (50255, 'Charmander', '224', '42', 2, 232, 23, null, null, 23, 23.00, 22.00, 'aac', null, null);
