create table evolution
(
    number                  int  null,
    evolved_species_id      int  null,
    evolution_trigger_id    int  null,
    trigger_item_id         text null,
    minimum_level           int  null,
    gender_id               text null,
    location_id             text null,
    held_item_id            text null,
    time_of_day             text null,
    known_move_id           text null,
    known_move_type_id      text null,
    minimum_happiness       text null,
    minimum_beauty          text null,
    minimum_affection       text null,
    relative_physical_stats text null,
    party_species_id        text null,
    party_type_id           text null,
    trade_species_id        text null,
    needs_overworld_rain    int  null,
    turn_upside_down        int  null,
    natures                 text null,
    base_species_id         int  null
);

create table pokemon
(
    number      int            not null
        primary key,
    name        varchar(100)   null,
    type_1      varchar(20)    null,
    type_2      varchar(20)    null,
    hp          int            null,
    attack      int            null,
    defense     int            null,
    sp_atk      int            null,
    sp_def      int            null,
    speed       int            null,
    height      decimal(10, 2) null,
    weight      decimal(10, 2) null,
    description text           null,
    mythical    int            null,
    legendary   int            null
);

create table pokemon_moves
(
    pokemon_id             int null,
    version_group_id       int null,
    move_id                int null,
    pokemon_move_method_id int null,
    level                  int null,
    `order`                int null
);

create table teams
(
    team_id   int auto_increment
        primary key,
    team_name varchar(50) not null,
    user_id   int         null,
    constraint team_name
        unique (team_name)
);

create table team_members
(
    team_id    int null,
    pokemon_id int null,
    constraint team_members_ibfk_1
        foreign key (team_id) references teams (team_id)
            on delete cascade,
    constraint team_members_ibfk_2
        foreign key (pokemon_id) references pokemon (number)
);

create index pokemon_id
    on team_members (pokemon_id);

create index team_id
    on team_members (team_id);

create table users
(
    user_id       int auto_increment
        primary key,
    username      varchar(50)  not null,
    password_hash varchar(255) not null,
    constraint username
        unique (username)
);

